    @login_manager.user_loader
    def load_user(user_stamp):
        row = get_user_by_stamp(db.session, user_stamp)
        if not row:
            return None
        if row.get('IS_ACTIVE') is False or bool(row.get('INATIVO') or 0):
            return None

        user = US()
        for k, v in row.items():
            setattr(user, k, v)
        return user

    # Rotas de autenticação
    @app.route('/login', methods=['GET', 'POST'])
    def login():
        def _safe_next_url(value: str | None) -> str:
            target = str(value or '').strip()
            if not target:
                return ''
            if not target.startswith('/') or target.startswith('//'):
                return ''
            if any(ch in target for ch in ('\r', '\n', '\x00')):
                return ''
            return target

        def _render_login(error: str = '', selected_target: str = '', verify_db: bool = False):
            host = _normalized_request_host() if has_request_context() else ''
            host_target = _normalize_db_target((app.config.get('DB_HOST_TARGETS') or {}).get(host))
            show_db_target_select = _is_localhost_host(host) and not host_target
            resolved_target = (
                _normalize_db_target(selected_target)
                or _resolve_db_target()
            )
            next_url = _safe_next_url(request.values.get('next'))
            return render_template(
                'login.html',
                error=error,
                show_db_target_select=show_db_target_select,
                db_target_options=_db_target_options(),
                selected_db_target=resolved_target,
                verify_db=bool(verify_db),
                db_target_prod=db_target_prod,
                next_url=next_url,
            )

        if request.method == 'POST':
            login_ = request.form['login']
            pwd = request.form['password']
            verify_db_requested = str(request.form.get('verify_db') or '').strip() in {'1', 'true', 'on', 'yes'}
            request_host = _normalized_request_host()
            host_target = _normalize_db_target((app.config.get('DB_HOST_TARGETS') or {}).get(request_host))
            if _is_localhost_host(request_host) and not host_target:
                selected_target = _normalize_db_target(request.form.get('db_target'))
                if not selected_target:
                    return _render_login(
                        error=translate('login.db_target_invalid'),
                        selected_target=request.form.get('db_target'),
                        verify_db=verify_db_requested,
                    )
                session[db_target_session_key] = selected_target
            try:
                result = authenticate_user(db.session, login_, pwd)
                if result.success and result.row:
                    try:
                        user_entities = get_user_entities(db.session, result.row.get('USSTAMP'))
                        default_entity = get_default_entity_for_user(db.session, result.row.get('USSTAMP'))
                    except MissingUserEntitiesError as entity_error:
                        session.pop('current_feid', None)
                        session.pop('current_entity_name', None)
                        auth_logger.warning(
                            'Login recusado: utilizador sem entidades ativas',
                            extra={'login': result.row.get('LOGIN'), 'usstamp': result.row.get('USSTAMP')},
                        )
                        return _render_login(
                            error=str(entity_error),
                            selected_target=request.form.get('db_target'),
                            verify_db=verify_db_requested,
                        )

                    user = US()
                    for k, v in result.row.items():
                        setattr(user, k, v)
                    login_user(user)
                    store_current_entity_in_session(default_entity)
                    auth_logger.info(
                        'Contexto multiempresa carregado no login',
                        extra={
                            'login': result.row.get('LOGIN'),
                            'usstamp': result.row.get('USSTAMP'),
                            'entity_count': len(user_entities),
                            'current_feid': default_entity.get('FEID'),
                        },
                    )
                    try:
                        para_map = _load_para_map()
                        session['APP_PARAMS'] = para_map
                        app.config['PARA_VALUES'] = para_map
                        _sync_i18n_runtime(para_map)
                    except Exception:
                        session['APP_PARAMS'] = {}
                    target_after_login = _resolve_db_target()
                    must_open_consistency = (
                        _is_localhost_host(_normalized_request_host())
                        and target_after_login != db_target_prod
                        and verify_db_requested
                    )
                    if target_after_login == db_target_prod or must_open_consistency:
                        session.pop(db_consistency_unlocked_target_session_key, None)
                    else:
                        session[db_consistency_unlocked_target_session_key] = target_after_login
                    session.pop(db_consistency_apply_result_session_key, None)
                    if must_open_consistency:
                        return redirect(url_for('database_consistency_page'))
                    return redirect(
                        _safe_next_url(request.form.get('next') or request.args.get('next'))
                        or url_for('home_page')
                    )

                return _render_login(
                    error=result.user_message,
                    selected_target=request.form.get('db_target'),
                    verify_db=verify_db_requested,
                )
            except Exception:
                db.session.rollback()
                auth_logger.exception('Erro inesperado durante autenticação', extra={'login': login_})
                return _render_login(
                    error=translate('login.internal_error'),
                    selected_target=request.form.get('db_target'),
                    verify_db=verify_db_requested,
                )
        return _render_login()

    def _database_consistency_allow_request() -> bool:
        if not current_user.is_authenticated:
            return True
        target = _resolve_db_target()
        if target == db_target_prod:
            return True
        unlocked_target = _normalize_db_target(session.get(db_consistency_unlocked_target_session_key))
        if unlocked_target == target:
            return True
        endpoint = str(request.endpoint or '').strip()
        if endpoint in {
            'database_consistency_page',
            'database_consistency_apply',
            'database_consistency_continue',
            'login',
            'logout',
            'service_worker',
            'static',
        }:
            return True
        if endpoint.startswith('api_database_consistency'):
            return True
        return False

    @app.before_request
    def _enforce_database_consistency():
        if _database_consistency_allow_request():
            return None
        if not current_user.is_authenticated:
            return None
        return redirect(url_for('database_consistency_page'))

    @app.route('/database_consistency', methods=['GET'])
    @login_required
    def database_consistency_page():
        report = _load_database_consistency_report()
        target = _resolve_db_target()
        if target == db_target_prod:
            session[db_consistency_unlocked_target_session_key] = target
            return redirect(url_for('home_page'))
        can_continue = bool(report.get('is_ok'))
        if can_continue:
            session[db_consistency_unlocked_target_session_key] = target
        else:
            session.pop(db_consistency_unlocked_target_session_key, None)
        apply_result = session.pop(db_consistency_apply_result_session_key, None)
        return render_template(
            'database_consistency.html',
            report=report,
            can_continue=can_continue,
            can_apply=bool(getattr(current_user, 'ADMIN', False) or getattr(current_user, 'DEV', False)),
            apply_result=apply_result,
        )

    @app.route('/database_consistency/apply', methods=['POST'])
    @login_required
    def database_consistency_apply():
        if not (getattr(current_user, 'ADMIN', False) or getattr(current_user, 'DEV', False)):
            abort(403)
        try:
            result = _database_consistency_apply_reference_structure(
                requested_by=str(getattr(current_user, 'LOGIN', '') or '').strip()
            )
        except Exception as exc:
            result = {
                'status': 'error',
                'applied': [],
                'failed': [{'type': 'apply', 'name': 'estrutura', 'error': str(exc)}],
                'skipped': [],
            }
        session[db_consistency_apply_result_session_key] = _database_consistency_compact_result(result)
        return redirect(url_for('database_consistency_page'))

    @app.route('/database_consistency/continue', methods=['POST'])
    @login_required
    def database_consistency_continue():
        report = _load_database_consistency_report()
        if not report.get('is_ok'):
            return redirect(url_for('database_consistency_page'))
        session[db_consistency_unlocked_target_session_key] = _resolve_db_target()
        return redirect(url_for('home_page'))

    _rsguests_siba_columns_checked = False

    def _ensure_rsguests_siba_columns():
        nonlocal _rsguests_siba_columns_checked
        if _rsguests_siba_columns_checked:
            return
        try:
            db.session.execute(text("""
                IF COL_LENGTH('dbo.RSGUESTS', 'NACIONALIDADE_ICAO') IS NULL
                    ALTER TABLE dbo.RSGUESTS ADD NACIONALIDADE_ICAO varchar(3) NULL;
                IF COL_LENGTH('dbo.RSGUESTS', 'PAIS_RESIDENCIA_ICAO') IS NULL
                    ALTER TABLE dbo.RSGUESTS ADD PAIS_RESIDENCIA_ICAO varchar(3) NULL;
                IF COL_LENGTH('dbo.RSGUESTS', 'PAIS_EMISSOR_DOC_ICAO') IS NULL
                    ALTER TABLE dbo.RSGUESTS ADD PAIS_EMISSOR_DOC_ICAO varchar(3) NULL;
                IF COL_LENGTH('dbo.RSGUESTS', 'TIPO_DOC_SIBA') IS NULL
                    ALTER TABLE dbo.RSGUESTS ADD TIPO_DOC_SIBA varchar(1) NULL;
            """))
            rows = db.session.execute(text("""
                SELECT RSGUESTSTAMP, NACIONALIDADE, PAIS_RESIDENCIA, PAIS_EMISSOR_DOC, TIPO_DOC,
                       ISNULL(NACIONALIDADE_ICAO, '') AS NACIONALIDADE_ICAO,
                       ISNULL(PAIS_RESIDENCIA_ICAO, '') AS PAIS_RESIDENCIA_ICAO,
                       ISNULL(PAIS_EMISSOR_DOC_ICAO, '') AS PAIS_EMISSOR_DOC_ICAO,
                       ISNULL(TIPO_DOC_SIBA, '') AS TIPO_DOC_SIBA
                FROM dbo.RSGUESTS
                WHERE LTRIM(RTRIM(ISNULL(NACIONALIDADE_ICAO, ''))) = ''
                   OR LTRIM(RTRIM(ISNULL(PAIS_RESIDENCIA_ICAO, ''))) = ''
                   OR LTRIM(RTRIM(ISNULL(PAIS_EMISSOR_DOC_ICAO, ''))) = ''
                   OR LTRIM(RTRIM(ISNULL(TIPO_DOC_SIBA, ''))) = ''
                   OR (
                        UPPER(LTRIM(RTRIM(ISNULL(TIPO_DOC, '')))) COLLATE SQL_Latin1_General_CP1_CI_AI
                            IN ('ID_NACIONAL', 'ID', 'CC', 'BI', 'CARTAO DE CIDADAO', 'CARTAO CIDADAO',
                                'DOCUMENTO DE IDENTIFICACAO NACIONAL', 'DOC. IDENTIFICACAO NACIONAL',
                                'DOC IDENTIFICACAO NACIONAL', 'DOC IDENTIFICACAO', 'NATIONAL IDENTITY DOCUMENT',
                                'NATIONAL ID')
                        AND LTRIM(RTRIM(ISNULL(TIPO_DOC_SIBA, ''))) <> 'B'
                   )
                   OR (
                        UPPER(LTRIM(RTRIM(ISNULL(TIPO_DOC, '')))) COLLATE SQL_Latin1_General_CP1_CI_AI
                            IN ('PASSAPORTE', 'PASSPORT')
                        AND LTRIM(RTRIM(ISNULL(TIPO_DOC_SIBA, ''))) <> 'P'
                   )
                   OR (
                        UPPER(LTRIM(RTRIM(ISNULL(TIPO_DOC, '')))) COLLATE SQL_Latin1_General_CP1_CI_AI
                            IN ('OUTRO', 'OTHER', 'AUTRE')
                        AND LTRIM(RTRIM(ISNULL(TIPO_DOC_SIBA, ''))) <> 'O'
                   )
            """)).mappings().all()
            for row in rows:
                values = {
                    's': row.get('RSGUESTSTAMP'),
                    'nacionalidade_icao': (row.get('NACIONALIDADE_ICAO') or '').strip() or country_to_icao(row.get('NACIONALIDADE')),
                    'pais_residencia_icao': (row.get('PAIS_RESIDENCIA_ICAO') or '').strip() or country_to_icao(row.get('PAIS_RESIDENCIA')),
                    'pais_emissor_doc_icao': (row.get('PAIS_EMISSOR_DOC_ICAO') or '').strip() or country_to_icao(row.get('PAIS_EMISSOR_DOC')),
                    'tipo_doc_siba': doc_type_to_siba(row.get('TIPO_DOC')) or (row.get('TIPO_DOC_SIBA') or '').strip(),
                }
                db.session.execute(text("""
                    UPDATE dbo.RSGUESTS
                    SET NACIONALIDADE_ICAO = :nacionalidade_icao,
                        PAIS_RESIDENCIA_ICAO = :pais_residencia_icao,
                        PAIS_EMISSOR_DOC_ICAO = :pais_emissor_doc_icao,
                        TIPO_DOC_SIBA = :tipo_doc_siba
                    WHERE RSGUESTSTAMP = :s
                """), values)
            db.session.commit()
            _rsguests_siba_columns_checked = True
        except Exception:
            db.session.rollback()
            raise

    @app.route('/r/<reserva_code>')
    @app.route('/r/<reserva_code>/')
    def public_reserva_page(reserva_code):
        public_code = (reserva_code or '').strip()
        if _public_reserva_code_invalid(public_code):
            return render_template('r_public.html', invalid=True, page_data={})
        row = _public_reserva_row(public_code)
        if not row:
            return render_template('r_public.html', invalid=True, page_data={})
        canonical_reserva_code = (row.get('RESERVA') or public_code).strip()

        lat = row.get('LAT')
        lon = row.get('LON')
        try:
            lat = float(lat) if lat is not None else None
            lon = float(lon) if lon is not None else None
        except Exception:
            lat, lon = None, None
        has_coords = (lat is not None and lon is not None and not (abs(lat) < 0.000001 and abs(lon) < 0.000001))

        morada = (row.get('MORADA') or '').strip()
        codpost = (row.get('CODPOST') or '').strip()
        local = (row.get('LOCAL') or '').strip()
        address_parts = [morada, codpost, local]
        address_text = ', '.join([p for p in address_parts if p])

        maps_query = f"{lat},{lon}" if has_coords else address_text
        maps_url = ''
        if maps_query:
            maps_url = f"https://www.google.com/maps/search/?api=1&query={quote(maps_query)}"

        adultos = int(row.get('ADULTOS') or 0)
        criancas = int(row.get('CRIANCAS') or 0)
        hospedes = adultos + criancas
        shop_state = _public_shop_state(row)

        page_data = {
            'public_code': canonical_reserva_code,
            'reserva': canonical_reserva_code,
            'alojamento': (row.get('ALOJAMENTO') or '').strip(),
            'alojamento_cover_url': _public_al_cover_url(row.get('ALSTAMP')),
            'checkin_data': _fmt_public_date(row.get('DATAIN')),
            'checkout_data': _fmt_public_date(row.get('DATAOUT')),
            'checkin_hora': (row.get('HORAIN') or '').strip(),
            'checkout_hora': (row.get('HORAOUT') or '').strip(),
            'berco': bool(row.get('BERCO') or 0),
            'adultos': adultos,
            'criancas': criancas,
            'hospedes': hospedes,
            'noites': int(row.get('NOITES') or 0),
            'morada': morada,
            'codpost': codpost,
            'local': local,
            'ftnome': (row.get('FTNOME') or '').strip(),
            'ftmorada': (row.get('FTMORADA') or '').strip(),
            'ftlocal': (row.get('FTLOCAL') or '').strip(),
            'ftcodpost': (row.get('FTCODPOST') or '').strip(),
            'ftncont': (row.get('FTNCONT') or '').strip(),
            'ftemail': (row.get('FTEMAIL') or '').strip(),
            'address_text': address_text,
            'lat': lat,
            'lon': lon,
            'maps_url': maps_url,
            'shop_enabled': bool(shop_state.get('is_enabled', True)),
            'shop_available': bool(shop_state.get('is_available')),
            'shop_message': shop_state.get('message') or '',
            'shop_deadline_label': shop_state.get('deadline_label') or '',
            'shop_url': url_for('public_reserva_shop_page', reserva_code=canonical_reserva_code),
        }

        # POI associados ao alojamento (agrupados por grupo)
        poi_rows = []
        try:
            poi_rows = db.session.execute(text("""
                SELECT
                    ISNULL(G.POIGSTAMP, '') AS POIGSTAMP,
                    ISNULL(G.NOME, 'Outros') AS GRUPO_NOME,
                    ISNULL(G.ORDEM, 9999) AS GRUPO_ORDEM,
                    P.POISTAMP,
                    ISNULL(P.NOME, '') AS POI_NOME,
                    ISNULL(P.TIPO, '') AS POI_TIPO,
                    ISNULL(P.DESCR, '') AS POI_DESCR,
                    ISNULL(P.MORADA, '') AS POI_MORADA,
                    ISNULL(P.CODPOSTAL, '') AS POI_CODPOSTAL,
                    ISNULL(P.CIDADE, '') AS POI_CIDADE,
                    ISNULL(P.PAIS, '') AS POI_PAIS,
                    P.LAT AS POI_LAT,
                    P.LNG AS POI_LNG,
                    ISNULL(P.TELEFONE, '') AS POI_TELEFONE,
                    ISNULL(P.URL, '') AS POI_URL,
                    ISNULL(P.URL_MAPS, '') AS POI_URL_MAPS,
                    ISNULL(P.HORARIO, '') AS POI_HORARIO,
                    ISNULL(P.PRECO_INFO, '') AS POI_PRECO,
                    ISNULL(X.ORDEM, 9999) AS ASSOC_ORDEM,
                    ISNULL(X.NOTA, '') AS ASSOC_NOTA
                FROM dbo.POIAL X
                INNER JOIN dbo.POI P
                  ON P.POISTAMP = X.POISTAMP
                LEFT JOIN dbo.POIG G
                  ON G.POIGSTAMP = P.POIGSTAMP
                WHERE
                  LTRIM(RTRIM(ISNULL(X.AL_NOME,''))) COLLATE SQL_Latin1_General_CP1_CI_AI
                    = LTRIM(RTRIM(:aloj)) COLLATE SQL_Latin1_General_CP1_CI_AI
                  AND ISNULL(X.ATIVO, 1) = 1
                  AND ISNULL(P.ATIVO, 1) = 1
                  AND ISNULL(G.ATIVO, 1) = 1
                ORDER BY
                  ISNULL(G.ORDEM, 9999),
                  ISNULL(G.NOME, 'Outros'),
                  ISNULL(X.ORDEM, 9999),
                  ISNULL(P.ORDEM_GLOBAL, 9999),
                  P.NOME
            """), {'aloj': page_data['alojamento']}).mappings().all()
        except Exception:
            poi_rows = []

        poi_groups_map = {}
        poi_groups_order = []
        for r in poi_rows:
            gkey = str(r.get('POIGSTAMP') or '').strip() or '__OUTROS__'
            if gkey not in poi_groups_map:
                poi_groups_map[gkey] = {
                    'name': str(r.get('GRUPO_NOME') or 'Outros').strip() or 'Outros',
                    'items': []
                }
                poi_groups_order.append(gkey)

            poi_lat = r.get('POI_LAT')
            poi_lng = r.get('POI_LNG')
            try:
                poi_lat = float(poi_lat) if poi_lat is not None else None
                poi_lng = float(poi_lng) if poi_lng is not None else None
            except Exception:
                poi_lat, poi_lng = None, None
            has_poi_coords = (poi_lat is not None and poi_lng is not None and not (abs(poi_lat) < 0.000001 and abs(poi_lng) < 0.000001))

            poi_morada = str(r.get('POI_MORADA') or '').strip()
            poi_cp = str(r.get('POI_CODPOSTAL') or '').strip()
            poi_city = str(r.get('POI_CIDADE') or '').strip()
            poi_country = str(r.get('POI_PAIS') or '').strip()
            poi_address = ', '.join([p for p in [poi_morada, poi_cp, poi_city, poi_country] if p])

            poi_maps_url = str(r.get('POI_URL_MAPS') or '').strip()
            if not poi_maps_url:
                q = f"{poi_lat},{poi_lng}" if has_poi_coords else poi_address
                if q:
                    poi_maps_url = f"https://www.google.com/maps/search/?api=1&query={quote(q)}"

            poi_groups_map[gkey]['items'].append({
                'name': str(r.get('POI_NOME') or '').strip(),
                'type': str(r.get('POI_TIPO') or '').strip(),
                'descr': str(r.get('POI_DESCR') or '').strip(),
                'address': poi_address,
                'phone': str(r.get('POI_TELEFONE') or '').strip(),
                'url': str(r.get('POI_URL') or '').strip(),
                'maps_url': poi_maps_url,
                'horario': str(r.get('POI_HORARIO') or '').strip(),
                'preco': str(r.get('POI_PRECO') or '').strip(),
                'nota': str(r.get('ASSOC_NOTA') or '').strip()
            })

        page_data['poi_groups'] = [poi_groups_map[k] for k in poi_groups_order]
        return render_template('r_public.html', invalid=False, page_data=page_data)

