    @app.route('/api/r/<reserva_code>/stay-plan', methods=['POST'])
    def public_reserva_stay_plan_save(reserva_code):
        public_code = (reserva_code or '').strip()
        row = _public_reserva_row(public_code)
        if not row:
            return jsonify({'error': 'Reserva inválida ou não encontrada'}), 404

        def _norm_hm(v):
            s = str(v or '').strip()
            if not s:
                return ''
            if not re.match(r'^\d{2}:\d{2}$', s):
                return None
            hh = int(s[:2])
            mm = int(s[3:5])
            if hh < 0 or hh > 23 or mm < 0 or mm > 59:
                return None
            return s

        body = request.get_json(silent=True) or {}
        horain = _norm_hm(body.get('horain'))
        horaout = _norm_hm(body.get('horaout'))
        if horain is None or horaout is None:
            return jsonify({'error': 'Hora inválida. Usa o formato HH:MM.'}), 400

        has_children = int(row.get('CRIANCAS') or 0) > 0
        berco = 1 if (has_children and bool(body.get('berco'))) else 0

        db.session.execute(text("""
            UPDATE dbo.RS
            SET
              HORAIN = :horain,
              HORAOUT = :horaout,
              BERCO = :berco
            WHERE RSSTAMP = :r
        """), {
            'horain': horain or '',
            'horaout': horaout or '',
            'berco': berco,
            'r': (row.get('RSSTAMP') or '').strip(),
        })
        db.session.commit()
        return public_reserva_stay_plan_get(reserva_code)

