    def _get_miseimp_options():
        rows = db.session.execute(text("""
            SELECT
                LTRIM(RTRIM(ISNULL(MISEIMPSTAMP,''))) AS MISEIMPSTAMP,
                UPPER(LTRIM(RTRIM(ISNULL(CODIGO,'')))) AS CODIGO,
                LTRIM(RTRIM(ISNULL(DESCRICAO,''))) AS DESCRICAO
            FROM dbo.MISEIMP
            WHERE LTRIM(RTRIM(ISNULL(CODIGO,''))) <> ''
            ORDER BY UPPER(LTRIM(RTRIM(ISNULL(CODIGO,''))))
        """)).mappings().all()
        return [dict(r) for r in rows]

    def _validate_ft_miseimp(lines):
        valid_codes = {
            str(item.get('CODIGO') or '').strip().upper()
            for item in _get_miseimp_options()
            if str(item.get('CODIGO') or '').strip()
        }
        missing = []
        invalid = []
        for idx, line in enumerate(lines or [], start=1):
            ref = str((line or {}).get('REF') or '').strip()
            design = str((line or {}).get('DESIGN') or '').strip()
            qtt = _num((line or {}).get('QTT'), 0)
            epv = _num((line or {}).get('EPV'), 0)
            total = _num((line or {}).get('ETILIQUIDO'), 0)
            meaningful = bool(
                ref or
                design or
                abs(epv) > 0.000001 or
                abs(total) > 0.000001 or
                (abs(qtt) > 0.000001 and (abs(epv) > 0.000001 or abs(total) > 0.000001))
            )
            if not meaningful:
                continue
            iva = round(_num((line or {}).get('IVA'), 0), 2)
            code = str((line or {}).get('MISEIMP') or '').strip().upper()
            if abs(iva) < 0.000001:
                if not code:
                    missing.append(idx)
                elif code not in valid_codes:
                    invalid.append(f'{idx} ({code})')
        if missing or invalid:
            parts = []
            if missing:
                parts.append('Linhas com IVA 0% sem motivo de isenção: ' + ', '.join(str(x) for x in missing))
            if invalid:
                parts.append('Linhas com motivo de isenção inválido: ' + ', '.join(invalid))
            return ' | '.join(parts)
        return ''

    def _get_current_fe_row():
        current_feid = get_current_feid()
        row = db.session.execute(text("""
            SELECT TOP 1
                FEID,
                LTRIM(RTRIM(ISNULL(FESTAMP, ''))) AS FESTAMP,
                LTRIM(RTRIM(ISNULL(NOME, ''))) AS NOME,
                LTRIM(RTRIM(ISNULL(NOMEFISCAL, ''))) AS NOMEFISCAL,
                CONVERT(varchar(20), ISNULL(NIF, 0)) AS NIF
            FROM dbo.FE
            WHERE FEID = :feid
        """), {'feid': int(current_feid)}).mappings().first()
        if not row:
            raise MissingCurrentEntityError('Empresa ativa não encontrada.')
        entity = dict(row)
        entity['FEID'] = int(entity.get('FEID') or 0)
        entity['FESTAMP'] = (entity.get('FESTAMP') or '').strip()
        entity['NOME'] = (entity.get('NOME') or '').strip()
        entity['NOMEFISCAL'] = (entity.get('NOMEFISCAL') or '').strip()
        entity['NIF'] = (entity.get('NIF') or '').strip()
        if not entity['FESTAMP']:
            raise MissingCurrentEntityError('Entidade ativa sem série/configuração associada.')
        return entity

    def _current_fe_or_json_error():
        try:
            return _get_current_fe_row(), None
        except MissingCurrentEntityError as exc:
            return None, (jsonify({'error': str(exc)}), 403)

    def _fetch_ecb_fx_options(force_refresh=False):
        now_ts = time.time()
        with _ecb_fx_cache_lock:
            cached_items = _ecb_fx_cache.get('items') or []
            loaded_at = float(_ecb_fx_cache.get('loaded_at') or 0)
            if not force_refresh and cached_items and (now_ts - loaded_at) < ECB_FX_CACHE_TTL_SECONDS:
                return [dict(item) for item in cached_items]

        request_obj = Request(
            ECB_FX_DAILY_URL,
            headers={
                'User-Agent': 'StationZero/1.0',
                'Accept': 'application/xml, text/xml;q=0.9, */*;q=0.1',
            }
        )
        try:
            with urlopen(request_obj, timeout=12) as response:
                payload = response.read()
        except Exception:
            with _ecb_fx_cache_lock:
                cached_items = _ecb_fx_cache.get('items') or []
                if cached_items:
                    return [dict(item) for item in cached_items]
            raise

        try:
            root = ET.fromstring(payload)
        except Exception as exc:
            with _ecb_fx_cache_lock:
                cached_items = _ecb_fx_cache.get('items') or []
                if cached_items:
                    return [dict(item) for item in cached_items]
            raise ValueError(f'Não foi possível ler a resposta do BCE: {exc}') from exc

        ns = {'fx': 'http://www.ecb.int/vocabulary/2002-08-01/eurofxref'}
        time_cube = root.find('.//fx:Cube[@time]', ns)
        if time_cube is None:
            with _ecb_fx_cache_lock:
                cached_items = _ecb_fx_cache.get('items') or []
                if cached_items:
                    return [dict(item) for item in cached_items]
            raise ValueError('O BCE não devolveu a data de referência dos câmbios.')

        rate_date = str(time_cube.attrib.get('time') or '').strip()
        items = [{
            'CODIGO': 'EUR',
            'DESCRICAO': ECB_FX_LABELS.get('EUR', 'EUR'),
            'CAMBIO': '1.000000',
            'DATA_REF': rate_date,
            'FONTE': 'ECB',
        }]
        dec6 = Decimal('0.000001')
        for cube in list(time_cube):
            code = str(cube.attrib.get('currency') or '').strip().upper()
            raw_rate = str(cube.attrib.get('rate') or '').strip()
            if not code or not raw_rate:
                continue
            try:
                rate = Decimal(raw_rate).quantize(dec6, rounding=ROUND_HALF_UP)
            except Exception:
                continue
            items.append({
                'CODIGO': code,
                'DESCRICAO': ECB_FX_LABELS.get(code, code),
                'CAMBIO': f'{rate:.6f}',
                'DATA_REF': rate_date,
                'FONTE': 'ECB',
            })
        items.sort(key=lambda row: (0 if row.get('CODIGO') == 'EUR' else 1, str(row.get('CODIGO') or '')))
        with _ecb_fx_cache_lock:
            _ecb_fx_cache['items'] = [dict(item) for item in items]
            _ecb_fx_cache['loaded_at'] = time.time()
        return items

    def _normalize_ft_cambio(moeda, cambio, default=None):
        moeda_code = str(moeda or 'EUR').strip().upper() or 'EUR'
        default_value = Decimal('1.000000') if moeda_code == 'EUR' else Decimal(str(default if default is not None else '0'))
        try:
            value = Decimal(str(cambio or '').strip().replace(',', '.')) if str(cambio or '').strip() else default_value
        except Exception:
            value = default_value
        if value < Decimal('0.000000'):
            value = Decimal('0.000000')
        return value.quantize(Decimal('0.000001'), rounding=ROUND_HALF_UP)

    def _fetch_oxr_currency_options(force_refresh=False):
        now_ts = time.time()
        with _oxr_currency_cache_lock:
            cached_items = _oxr_currency_cache.get('items') or []
            loaded_at = float(_oxr_currency_cache.get('loaded_at') or 0)
            if not force_refresh and cached_items and (now_ts - loaded_at) < ECB_FX_CACHE_TTL_SECONDS:
                return [dict(item) for item in cached_items]

        request_obj = Request(
            OXR_CURRENCIES_URL,
            headers={
                'User-Agent': 'StationZero/1.0',
                'Accept': 'application/json, text/plain;q=0.9, */*;q=0.1',
            }
        )
        try:
            with urlopen(request_obj, timeout=12) as response:
                payload = response.read().decode('utf-8', 'ignore')
            data = json.loads(payload or '{}')
        except Exception:
            with _oxr_currency_cache_lock:
                cached_items = _oxr_currency_cache.get('items') or []
                if cached_items:
                    return [dict(item) for item in cached_items]
            raise

        items = []
        if isinstance(data, dict):
            for code, description in data.items():
                code_norm = str(code or '').strip().upper()
                if not code_norm:
                    continue
                items.append({
                    'CODIGO': code_norm,
                    'DESCRICAO': str(description or '').strip() or code_norm,
                    'CAMBIO': '',
                    'DATA_REF': '',
                    'FONTE': 'OXR',
                    'MANUAL': True,
                })
        items.sort(key=lambda row: str(row.get('CODIGO') or ''))
        with _oxr_currency_cache_lock:
            _oxr_currency_cache['items'] = [dict(item) for item in items]
            _oxr_currency_cache['loaded_at'] = time.time()
        return items

    def _ft_entity_scope_sql(alias='FT'):
        prefix = f'{alias}.' if alias else ''
        return f"""
            AND (
                ISNULL({prefix}FEID, 0) = :current_feid
                OR (
                    ISNULL({prefix}FEID, 0) = 0
                    AND LTRIM(RTRIM(ISNULL({prefix}FESTAMP, ''))) = :current_festamp
                )
            )
        """

    def _calc_totals_and_breakdown(lines, header_discount=0):
        dec6 = Decimal('0.000001')
        dec2 = Decimal('0.01')

        def _to_dec(val, default='0'):
            if val is None:
                return Decimal(default)
            txt = str(val).strip().replace(',', '.')
            if txt == '':
                return Decimal(default)
            try:
                return Decimal(txt)
            except Exception:
                return Decimal(default)

        def _to_pct(val, default='0'):
            pct = _to_dec(val, default)
            if pct < Decimal('0.00'):
                return Decimal('0.00')
            if pct > Decimal('100.00'):
                return Decimal('100.00')
            return pct.quantize(dec6, rounding=ROUND_HALF_UP)

        normalized = []
        total_base = Decimal('0.000000')
        total_vat = Decimal('0.00')
        buckets = {}
        header_discount = _to_pct(header_discount, '0')
        for idx, line in enumerate(lines or []):
            qtt = _to_dec((line or {}).get('QTT'), '0').quantize(dec6, rounding=ROUND_HALF_UP)
            epv = _to_dec((line or {}).get('EPV'), '0').quantize(dec6, rounding=ROUND_HALF_UP)
            desconto = _to_pct((line or {}).get('DESCONTO'), '0')
            rate = _to_dec((line or {}).get('IVA'), '0')
            if rate < Decimal('0.00'):
                rate = Decimal('0.00')
            rate = rate.quantize(dec6, rounding=ROUND_HALF_UP)
            ivaincl = 1 if int(_num((line or {}).get('IVAINCL'), 0)) == 1 else 0

            gross_line_total = (qtt * epv).quantize(dec6, rounding=ROUND_HALF_UP)
            desconto_linha_valor = (gross_line_total * desconto / Decimal('100.00')).quantize(dec6, rounding=ROUND_HALF_UP)
            total_apos_desc_linha = (gross_line_total - desconto_linha_valor).quantize(dec6, rounding=ROUND_HALF_UP)
            desconto_cabecalho_valor = (total_apos_desc_linha * header_discount / Decimal('100.00')).quantize(dec6, rounding=ROUND_HALF_UP)
            total_liquido = (total_apos_desc_linha - desconto_cabecalho_valor).quantize(dec6, rounding=ROUND_HALF_UP)
            vat = (total_liquido * rate / Decimal('100.00')).quantize(dec2, rounding=ROUND_HALF_UP) if rate > 0 else Decimal('0.00')

            total_base += total_liquido
            total_vat += vat
            tabiva = _to_int((line or {}).get('TABIVA'), 0)
            row = dict(line or {})
            row['LORDEM'] = _to_int(row.get('LORDEM'), (idx + 1) * 10)
            row['QTT'] = float(qtt)
            row['EPV'] = float(epv)
            row['DESCONTO'] = float(desconto)
            row['IVA'] = float(rate)
            row['IVAINCL'] = ivaincl
            row['TABIVA'] = tabiva
            row['MISEIMP'] = (str(row.get('MISEIMP') or '').strip().upper() if rate == 0 else '')
            row['ETILIQUIDO'] = f"{total_liquido:.6f}"
            row['BRUTO'] = f"{gross_line_total:.6f}"
            row['DESCONTO_LINHA_VALOR'] = f"{desconto_linha_valor:.6f}"
            row['TOTAL_APOS_DESC_LINHA'] = f"{total_apos_desc_linha:.6f}"
            row['DESCONTO_CABECALHO_VALOR'] = f"{desconto_cabecalho_valor:.6f}"
            row['IVA_LINHA'] = f"{vat:.2f}"
            row['TOTAL_LINHA_COM_IVA'] = f"{(total_liquido + vat):.6f}"
            row['UNITPRICE_FISCAL'] = (f"{(total_liquido / qtt).quantize(dec6, rounding=ROUND_HALF_UP):.6f}" if qtt != 0 else None)
            normalized.append(row)
            rate_key = float(rate)
            if rate_key not in buckets:
                buckets[rate_key] = {'base': Decimal('0.000000'), 'vat': Decimal('0.00')}
            buckets[rate_key]['base'] += total_liquido
            buckets[rate_key]['vat'] += vat

        total_base_display = total_base.quantize(dec2, rounding=ROUND_HALF_UP)
        total_vat = total_vat.quantize(dec2, rounding=ROUND_HALF_UP)
        total = (total_base + total_vat).quantize(dec2, rounding=ROUND_HALF_UP)
        breakdown = sorted(buckets.items(), key=lambda x: x[0])[:9]
        ivatx = [0.0] * 9
        eivain = [0.0] * 9
        eivav = [0.0] * 9
        for idx, (tx, vals) in enumerate(breakdown):
            ivatx[idx] = round(float(tx), 2)
            eivain[idx] = round(float(vals.get('base', Decimal('0.00'))), 2)
            eivav[idx] = round(float(vals.get('vat', Decimal('0.00'))), 2)
        return normalized, float(total_base_display), float(total_vat), float(total), ivatx, eivain, eivav

    def _get_ft(ftstamp, entity=None):
        entity = entity or _get_current_fe_row()
        ft = db.session.execute(text("""
            SELECT *
            FROM dbo.FT
            WHERE FTSTAMP = :s
        """ + _ft_entity_scope_sql('FT')), {
            's': ftstamp,
            'current_feid': int(entity.get('FEID') or 0),
            'current_festamp': (entity.get('FESTAMP') or '').strip(),
        }).mappings().first()
        if not ft:
            return None, []
        ft = _ft_transport_enrich_header(entity, dict(ft))
        fi = db.session.execute(text("""
            SELECT *
            FROM dbo.FI
            WHERE FTSTAMP = :s
            ORDER BY ISNULL(LORDEM,0), FISTAMP
        """), {'s': ftstamp}).mappings().all()
        return dict(ft), _enrich_fi_fiscal_fields([dict(r) for r in fi])

    def _table_has_columns(table_name: str, *column_names: str) -> bool:
        wanted = {str(name or '').strip().upper() for name in (column_names or []) if str(name or '').strip()}
        if not wanted:
            return True
        rows = db.session.execute(text("""
            SELECT UPPER(COLUMN_NAME) AS CN
            FROM INFORMATION_SCHEMA.COLUMNS
            WHERE TABLE_SCHEMA = 'dbo'
              AND TABLE_NAME = :table_name
        """), {'table_name': str(table_name or '').strip()}).mappings().all()
        existing = {str(row.get('CN') or '').upper() for row in rows}
        return wanted.issubset(existing)

    def _table_exists(table_name: str) -> bool:
        row = db.session.execute(text("""
            SELECT TOP 1 1
            FROM INFORMATION_SCHEMA.TABLES
            WHERE TABLE_SCHEMA = 'dbo'
              AND TABLE_NAME = :table_name
        """), {'table_name': str(table_name or '').strip()}).first()
        return bool(row)

    def _ensure_fe_cluster_schema():
        if not _table_has_columns('FE', 'E_CLUSTER'):
            db.session.execute(text("""
                ALTER TABLE dbo.FE
                ADD E_CLUSTER bit NOT NULL
                    CONSTRAINT DF_FE_E_CLUSTER DEFAULT 0
            """))
            db.session.commit()

        if not _table_exists('FE_CLUSTER_ENTIDADES'):
            db.session.execute(text("""
                CREATE TABLE dbo.FE_CLUSTER_ENTIDADES
                (
                    FECLUSTERENTSTAMP varchar(25) NOT NULL,
                    FESTAMP_CLUSTER   varchar(25) NOT NULL,
                    FESTAMP_ENTIDADE  varchar(25) NOT NULL,
                    DTCRI             datetime2(0) NOT NULL
                        CONSTRAINT DF_FE_CLUSTER_ENTIDADES_DTCRI DEFAULT GETDATE(),
                    DTALT             datetime2(0) NULL,
                    USERCRIACAO       varchar(50) NOT NULL
                        CONSTRAINT DF_FE_CLUSTER_ENTIDADES_USERCRIACAO DEFAULT '',
                    USERALTERACAO     varchar(50) NOT NULL
                        CONSTRAINT DF_FE_CLUSTER_ENTIDADES_USERALTERACAO DEFAULT '',
                    CONSTRAINT PK_FE_CLUSTER_ENTIDADES PRIMARY KEY (FECLUSTERENTSTAMP),
                    CONSTRAINT CK_FE_CLUSTER_ENTIDADES_SELF CHECK (FESTAMP_CLUSTER <> FESTAMP_ENTIDADE)
                )
            """))
            db.session.commit()

        db.session.execute(text("""
            IF NOT EXISTS (
                SELECT 1
                FROM sys.indexes
                WHERE object_id = OBJECT_ID('dbo.FE_CLUSTER_ENTIDADES')
                  AND name = 'UX_FE_CLUSTER_ENTIDADES_CLUSTER_ENTIDADE'
            )
            BEGIN
                ALTER TABLE dbo.FE_CLUSTER_ENTIDADES
                ADD CONSTRAINT UX_FE_CLUSTER_ENTIDADES_CLUSTER_ENTIDADE
                    UNIQUE (FESTAMP_CLUSTER, FESTAMP_ENTIDADE);
            END
        """))
        db.session.execute(text("""
            IF NOT EXISTS (
                SELECT 1
                FROM sys.indexes
                WHERE object_id = OBJECT_ID('dbo.FE_CLUSTER_ENTIDADES')
                  AND name = 'IX_FE_CLUSTER_ENTIDADES_CLUSTER'
            )
            BEGIN
                CREATE INDEX IX_FE_CLUSTER_ENTIDADES_CLUSTER
                ON dbo.FE_CLUSTER_ENTIDADES (FESTAMP_CLUSTER);
            END
        """))
        db.session.execute(text("""
            IF NOT EXISTS (
                SELECT 1
                FROM sys.indexes
                WHERE object_id = OBJECT_ID('dbo.FE_CLUSTER_ENTIDADES')
                  AND name = 'IX_FE_CLUSTER_ENTIDADES_ENTIDADE'
            )
            BEGIN
                CREATE INDEX IX_FE_CLUSTER_ENTIDADES_ENTIDADE
                ON dbo.FE_CLUSTER_ENTIDADES (FESTAMP_ENTIDADE);
            END
        """))
        db.session.execute(text("""
            IF NOT EXISTS (
                SELECT 1
                FROM sys.foreign_keys
                WHERE parent_object_id = OBJECT_ID('dbo.FE_CLUSTER_ENTIDADES')
                  AND name = 'FK_FE_CLUSTER_ENTIDADES_CLUSTER'
            )
            BEGIN
                ALTER TABLE dbo.FE_CLUSTER_ENTIDADES
                ADD CONSTRAINT FK_FE_CLUSTER_ENTIDADES_CLUSTER
                    FOREIGN KEY (FESTAMP_CLUSTER) REFERENCES dbo.FE(FESTAMP);
            END
        """))
        db.session.execute(text("""
            IF NOT EXISTS (
                SELECT 1
                FROM sys.foreign_keys
                WHERE parent_object_id = OBJECT_ID('dbo.FE_CLUSTER_ENTIDADES')
                  AND name = 'FK_FE_CLUSTER_ENTIDADES_ENTIDADE'
            )
            BEGIN
                ALTER TABLE dbo.FE_CLUSTER_ENTIDADES
                ADD CONSTRAINT FK_FE_CLUSTER_ENTIDADES_ENTIDADE
                    FOREIGN KEY (FESTAMP_ENTIDADE) REFERENCES dbo.FE(FESTAMP);
            END
        """))
        db.session.execute(text("""
            IF OBJECT_ID('dbo.TR_FE_CLUSTER_ENTIDADES_VALIDATE', 'TR') IS NULL
            EXEC('CREATE TRIGGER dbo.TR_FE_CLUSTER_ENTIDADES_VALIDATE ON dbo.FE_CLUSTER_ENTIDADES
                  AFTER INSERT, UPDATE
                  AS
                  BEGIN
                      SET NOCOUNT ON;
                  END')
        """))
        db.session.execute(text("""
            ALTER TRIGGER dbo.TR_FE_CLUSTER_ENTIDADES_VALIDATE
            ON dbo.FE_CLUSTER_ENTIDADES
            AFTER INSERT, UPDATE
            AS
            BEGIN
                SET NOCOUNT ON;

                IF EXISTS (
                    SELECT 1
                    FROM inserted I
                    LEFT JOIN dbo.FE CL ON CL.FESTAMP = I.FESTAMP_CLUSTER
                    LEFT JOIN dbo.FE EN ON EN.FESTAMP = I.FESTAMP_ENTIDADE
                    WHERE CL.FESTAMP IS NULL
                       OR EN.FESTAMP IS NULL
                       OR ISNULL(CL.E_CLUSTER, 0) <> 1
                       OR ISNULL(EN.E_CLUSTER, 0) = 1
                       OR I.FESTAMP_CLUSTER = I.FESTAMP_ENTIDADE
                )
                BEGIN
                    RAISERROR('Associacao de cluster FE invalida.', 16, 1);
                    ROLLBACK TRANSACTION;
                    RETURN;
                END
            END
        """))
        db.session.commit()

