    @app.route('/api/reservas/rs/<rsstamp>/limpezas', methods=['GET'])
    @login_required
    def api_reservas_rs_limpezas(rsstamp):
        current_feid, error_response = _current_feid_or_json_error()
        if error_response:
            return error_response
        rs = db.session.execute(text("""
            SELECT
                RS.RSSTAMP,
                LTRIM(RTRIM(ISNULL(RS.ALOJAMENTO,''))) AS ALOJAMENTO,
                CAST(RS.DATAIN AS date) AS DATAIN,
                CAST(RS.DATAOUT AS date) AS DATAOUT,
                ISNULL(RS.HORAIN,'') AS HORAIN,
                ISNULL(RS.HORAOUT,'') AS HORAOUT,
                ISNULL(AL.TIPOLOGIA,'') AS TIPOLOGIA
            FROM dbo.RS AS RS
            LEFT JOIN dbo.AL AS AL
              ON LTRIM(RTRIM(ISNULL(AL.NOME,''))) = LTRIM(RTRIM(ISNULL(RS.ALOJAMENTO,'')))
            WHERE RS.RSSTAMP = :s
              AND (
                    ISNULL(RS.FEID, 0) = :current_feid
                 OR ISNULL(AL.FEID, 0) = :current_feid
                 OR ISNULL(AL.FEID_GESTOR, 0) = :current_feid
              )
        """), {'s': rsstamp, 'current_feid': current_feid}).mappings().first()
        if not rs:
            return jsonify({'error': 'Reserva não encontrada'}), 404

        alojamento = str(rs.get('ALOJAMENTO') or '').strip()
        if not alojamento:
            return jsonify({'before': None, 'after': None})

        def _time_to_min(value):
            raw = str(value or '').strip()
            if not raw:
                return None
            try:
                hh, mm = raw.split(':', 1)
                hh_i = max(0, min(23, int(hh)))
                mm_i = max(0, min(59, int(mm[:2])))
                return hh_i * 60 + mm_i
            except Exception:
                return None

        def _duration_for_tipologia(tipologia):
            tip = str(tipologia or '').strip().upper()
            if tip in ('T0', 'T1'):
                return 60
            if tip == 'T2':
                return 90
            if tip == 'T3':
                return 120
            if tip == 'T4':
                return 150
            return None

        def _task_start_min(task):
            return _time_to_min(task.get('HORA')) or _time_to_min(task.get('HORAINI')) or _time_to_min(task.get('HORAFIM'))

        def _task_end_min(task):
            return _time_to_min(task.get('HORAFIM')) or _time_to_min(task.get('HORAINI')) or _time_to_min(task.get('HORA'))

        def _serialize_task(task, planned_minutes):
            if not task:
                return None
            start_min = _time_to_min(task.get('HORAINI'))
            end_min = _time_to_min(task.get('HORAFIM'))
            actual_minutes = None
            if start_min is not None and end_min is not None:
                actual_minutes = max(0, end_min - start_min)
            return {
                'TAREFASSTAMP': str(task.get('TAREFASSTAMP') or '').strip(),
                'DATA': _fmt_rs_date(task.get('DATA')),
                'HORA': str(task.get('HORA') or '').strip(),
                'HORAINI': str(task.get('HORAINI') or '').strip(),
                'HORAFIM': str(task.get('HORAFIM') or '').strip(),
                'TRATADO': 1 if int(task.get('TRATADO') or 0) else 0,
                'UTILIZADOR': str(task.get('UTILIZADOR') or '').strip(),
                'UTILIZADOR_NOME': str(task.get('UTILIZADOR_NOME') or task.get('UTILIZADOR') or '').strip(),
                'PLANNED_MINUTES': planned_minutes,
                'ACTUAL_MINUTES': actual_minutes,
            }

        tasks = db.session.execute(text("""
            SELECT
                T.TAREFASSTAMP,
                CAST(T.DATA AS date) AS DATA,
                ISNULL(T.HORA,'') AS HORA,
                ISNULL(T.HORAINI,'') AS HORAINI,
                ISNULL(T.HORAFIM,'') AS HORAFIM,
                ISNULL(T.TRATADO,0) AS TRATADO,
                ISNULL(T.UTILIZADOR,'') AS UTILIZADOR,
                ISNULL(U.NOME, T.UTILIZADOR) AS UTILIZADOR_NOME
            FROM dbo.TAREFAS AS T
            LEFT JOIN dbo.US AS U
              ON U.LOGIN = T.UTILIZADOR
            WHERE LTRIM(RTRIM(ISNULL(T.ORIGEM,''))) = 'LP'
              AND LTRIM(RTRIM(ISNULL(T.ALOJAMENTO,''))) = LTRIM(RTRIM(:aloj))
            ORDER BY CAST(T.DATA AS date) DESC, ISNULL(T.HORA,'') DESC, T.TAREFASSTAMP DESC
        """), {'aloj': alojamento}).mappings().all()

        datain = rs.get('DATAIN')
        dataout = rs.get('DATAOUT')
        checkin_min = _time_to_min(rs.get('HORAIN'))
        checkout_min = _time_to_min(rs.get('HORAOUT'))
        planned_minutes = _duration_for_tipologia(rs.get('TIPOLOGIA'))

        before_task = None
        after_task = None
        before_key = None
        after_key = None

        for task in tasks:
            task_date = task.get('DATA')
            if not task_date:
                continue

            start_min = _task_start_min(task)
            end_min = _task_end_min(task)

            if datain:
                qualifies_before = task_date < datain
                if task_date == datain:
                    compare_end = end_min if end_min is not None else (start_min if start_min is not None else 0)
                    limit_end = checkin_min if checkin_min is not None else 1439
                    qualifies_before = compare_end <= limit_end
                if qualifies_before:
                    candidate_key = (task_date.toordinal(), end_min if end_min is not None else (start_min if start_min is not None else 0))
                    if before_key is None or candidate_key > before_key:
                        before_key = candidate_key
                        before_task = task

            if dataout:
                qualifies_after = task_date > dataout
                if task_date == dataout:
                    compare_start = start_min if start_min is not None else (end_min if end_min is not None else 0)
                    limit_start = checkout_min if checkout_min is not None else 0
                    qualifies_after = compare_start >= limit_start
                if qualifies_after:
                    candidate_key = (task_date.toordinal(), start_min if start_min is not None else (end_min if end_min is not None else 0))
                    if after_key is None or candidate_key < after_key:
                        after_key = candidate_key
                        after_task = task

        return jsonify({
            'before': _serialize_task(before_task, planned_minutes),
            'after': _serialize_task(after_task, planned_minutes),
        })

    @app.route('/api/reservas/cancelamentos', methods=['GET'])
    @login_required
    def api_reservas_cancelamentos():
        current_feid, error_response = _current_feid_or_json_error()
        if error_response:
            return error_response
        def _date_or_none(raw):
            s = str(raw or '').strip()
            if not s:
                return None
            try:
                return datetime.fromisoformat(s[:10]).date()
            except Exception:
                return None

        datain_from = _date_or_none(request.args.get('datain_from'))
        datain_to = _date_or_none(request.args.get('datain_to'))
        dataout_from = _date_or_none(request.args.get('dataout_from'))
        dataout_to = _date_or_none(request.args.get('dataout_to'))
        dias_cancel_max = _to_int(request.args.get('dias_cancel_max'), -1)
        dias_cancel_min = _to_int(request.args.get('dias_cancel_min'), -1)
        sem_pagamento = str(request.args.get('sem_pagamento') or '0').strip().lower() in ('1', 'true', 'yes', 'on')

        where = ["ISNULL(RS.CANCELADA,0)=1"]
        params = {}
        if datain_from:
            where.append("CAST(RS.DATAIN AS date) >= :datain_from")
            params['datain_from'] = datain_from
        if datain_to:
            where.append("CAST(RS.DATAIN AS date) <= :datain_to")
            params['datain_to'] = datain_to
        if dataout_from:
            where.append("CAST(RS.DATAOUT AS date) >= :dataout_from")
            params['dataout_from'] = dataout_from
        if dataout_to:
            where.append("CAST(RS.DATAOUT AS date) <= :dataout_to")
            params['dataout_to'] = dataout_to
        if dias_cancel_max >= 0:
            where.append("ISNULL(RS.DIASCANCEL,0) <= :dias_cancel_max")
            params['dias_cancel_max'] = dias_cancel_max
        if dias_cancel_min >= 0:
            where.append("ISNULL(RS.DIASCANCEL,0) >= :dias_cancel_min")
            params['dias_cancel_min'] = dias_cancel_min
        if sem_pagamento:
            where.append("CAST(ISNULL(RS.PCANCEL,0) AS decimal(18,2)) = 0")

        rows = db.session.execute(text(f"""
            SELECT
                ISNULL(RS.RSSTAMP,'') AS RSSTAMP,
                ISNULL(RS.RESERVA,'') AS RESERVA,
                ISNULL(RS.ALOJAMENTO,'') AS ALOJAMENTO,
                ISNULL(RS.NOME,'') AS NOME,
                ISNULL(RS.ORIGEM,'') AS ORIGEM,
                CAST(RS.RDATA AS date) AS RDATA,
                CAST(RS.DATAIN AS date) AS DATAIN,
                CAST(RS.DATAOUT AS date) AS DATAOUT,
                ISNULL(RS.NOITES,0) AS NOITES,
                ISNULL(RS.ADULTOS,0) AS ADULTOS,
                ISNULL(RS.CRIANCAS,0) AS CRIANCAS,
                ISNULL(RS.ESTADIA,0) AS ESTADIA,
                ISNULL(RS.LIMPEZA,0) AS LIMPEZA,
                ISNULL(RS.COMISSAO,0) AS COMISSAO,
                ISNULL(RS.DIASCANCEL,0) AS DIASCANCEL,
                CAST(RS.DTCANCEL AS date) AS DTCANCEL,
                CAST(ISNULL(RS.PCANCEL,0) AS decimal(18,2)) AS PCANCEL
            FROM dbo.RS RS
            WHERE {' AND '.join(where)}
              AND (
                    ISNULL(RS.FEID, 0) = :current_feid
                 OR EXISTS (
                        SELECT 1
                        FROM dbo.AL ALV
                        WHERE LTRIM(RTRIM(ISNULL(ALV.NOME,''))) = LTRIM(RTRIM(ISNULL(RS.ALOJAMENTO,'')))
                          AND (
                                ISNULL(ALV.FEID, 0) = :current_feid
                             OR ISNULL(ALV.FEID_GESTOR, 0) = :current_feid
                          )
                    )
              )
            ORDER BY CAST(RS.DATAIN AS date) DESC, CAST(RS.DATAOUT AS date) DESC, ISNULL(RS.RESERVA,'')
        """), {**params, 'current_feid': current_feid}).mappings().all()

        out = []
        for r in rows:
            reserva_code = str(r.get('RESERVA') or '').strip()
            out.append({
                'RSSTAMP': str(r.get('RSSTAMP') or '').strip(),
                'RESERVA': reserva_code,
                'ALOJAMENTO': str(r.get('ALOJAMENTO') or '').strip(),
                'NOME': str(r.get('NOME') or '').strip(),
                'ORIGEM': str(r.get('ORIGEM') or '').strip(),
                'RDATA': (r.get('RDATA').isoformat() if r.get('RDATA') else ''),
                'DATAIN': (r.get('DATAIN').isoformat() if r.get('DATAIN') else ''),
                'DATAOUT': (r.get('DATAOUT').isoformat() if r.get('DATAOUT') else ''),
                'NOITES': int(r.get('NOITES') or 0),
                'ADULTOS': int(r.get('ADULTOS') or 0),
                'CRIANCAS': int(r.get('CRIANCAS') or 0),
                'ESTADIA': round(float(r.get('ESTADIA') or 0), 2),
                'LIMPEZA': round(float(r.get('LIMPEZA') or 0), 2),
                'COMISSAO': round(float(r.get('COMISSAO') or 0), 2),
                'DIASCANCEL': int(r.get('DIASCANCEL') or 0),
                'DTCANCEL': (r.get('DTCANCEL').isoformat() if r.get('DTCANCEL') else ''),
                'PCANCEL': round(float(r.get('PCANCEL') or 0), 2),
                'ITINERARIO_URL': (f'https://www.airbnb.pt/hosting/stay/{reserva_code}' if reserva_code else ''),
            })
        return jsonify({'rows': out})

    @app.route('/api/reservas/cancelamentos/<rsstamp>/pcancel', methods=['POST'])
    @login_required
    def api_reservas_cancelamentos_set_pcancel(rsstamp):
        current_feid, error_response = _current_feid_or_json_error()
        if error_response:
            return error_response
        body = request.get_json(silent=True) or {}
        try:
            value = round(float(body.get('pcancel') or 0), 2)
        except Exception:
            return jsonify({'error': 'Valor inválido.'}), 400
        if value < 0:
            return jsonify({'error': 'Valor não pode ser negativo.'}), 400

        row = db.session.execute(text(f"""
            SELECT ISNULL(CANCELADA,0) AS CANCELADA
            FROM dbo.RS
            WHERE RSSTAMP=:s
              {_rs_write_clause('RS')}
        """), {'s': rsstamp, 'current_feid': current_feid}).mappings().first()
        if not row:
            if _rs_exists_any(rsstamp):
                return jsonify({'error': 'Sem permissão para alterar esta reserva na empresa ativa.'}), 403
            return jsonify({'error': 'Reserva não encontrada'}), 404
        if int(row.get('CANCELADA') or 0) != 1:
            return jsonify({'error': 'A reserva não está cancelada.'}), 400

        try:
            db.session.execute(text(f"""
                UPDATE dbo.RS
                SET PCANCEL=:v
                WHERE RSSTAMP=:s
                {_rs_write_clause('RS')}
            """), {'v': value, 's': rsstamp, 'current_feid': current_feid})
            db.session.commit()
        except Exception as e:
            db.session.rollback()
            return jsonify({'error': f'Erro ao gravar valor de cancelamento: {e}'}), 500
        return jsonify({'ok': True, 'pcancel': value})

    @app.route('/api/reservas/rs/<rsstamp>/save', methods=['POST'])
    @login_required
    def api_reservas_rs_save(rsstamp):
        current_feid, error_response = _current_feid_or_json_error()
        if error_response:
            return error_response
        body = request.get_json(silent=True) or {}
        header = dict(body.get('header') or {})
        guests = list(body.get('guests') or [])

        current = db.session.execute(text(f"""
            SELECT *
            FROM dbo.RS
            WHERE RSSTAMP = :s
              {_rs_write_clause('RS')}
        """), {'s': rsstamp, 'current_feid': current_feid}).mappings().first()
        if not current:
            if _rs_exists_any(rsstamp):
                return jsonify({'error': 'Sem permissão para alterar esta reserva na empresa ativa.'}), 403
            return jsonify({'error': 'Reserva não encontrada'}), 404
        current = dict(current)

        today = date.today()
        try:
            rdata = datetime.fromisoformat((header.get('RDATA') or current.get('RDATA') or today.isoformat()).replace('Z', '')).date()
        except Exception:
            rdata = today
        try:
            datain = datetime.fromisoformat((header.get('DATAIN') or current.get('DATAIN') or rdata.isoformat()).replace('Z', '')).date()
        except Exception:
            datain = rdata
        try:
            dataout = datetime.fromisoformat((header.get('DATAOUT') or current.get('DATAOUT') or (datain + timedelta(days=1)).isoformat()).replace('Z', '')).date()
        except Exception:
            dataout = datain + timedelta(days=1)
        if dataout < datain:
            dataout = datain
        noites_calc = max(0, (dataout - datain).days)
        noites = _to_int(header.get('NOITES'), noites_calc)
        if noites <= 0 and dataout > datain:
            noites = noites_calc

        dtcancel_raw = str(header.get('DTCANCEL') or '').strip()
        if dtcancel_raw:
            try:
                dtcancel = datetime.fromisoformat(dtcancel_raw.replace('Z', '')).date()
            except Exception:
                dtcancel = date(1900, 1, 1)
        else:
            dtcancel = date(1900, 1, 1)

        def _h(name, default=''):
            if name in header:
                return header.get(name)
            return current.get(name, default)

        db.session.execute(text(f"""
            UPDATE dbo.RS
            SET
                ALOJAMENTO=:ALOJAMENTO,
                RDATA=:RDATA,
                ORIGEM=:ORIGEM,
                RESERVA=:RESERVA,
                DATAIN=:DATAIN,
                DATAOUT=:DATAOUT,
                HORAIN=:HORAIN,
                HORAOUT=:HORAOUT,
                NOITES=:NOITES,
                NOME=:NOME,
                PAIS=:PAIS,
                ADULTOS=:ADULTOS,
                CRIANCAS=:CRIANCAS,
                BEBES=:BEBES,
                ESTADIA=:ESTADIA,
                LIMPEZA=:LIMPEZA,
                COMISSAO=:COMISSAO,
                READY=:READY,
                ENTROU=:ENTROU,
                SAIU=:SAIU,
                ALERTA=:ALERTA,
                OBS=:OBS,
                CANCELADA=:CANCELADA,
                DTCANCEL=:DTCANCEL,
                DIASCANCEL=:DIASCANCEL,
                NOTIF=:NOTIF,
                NOTIF2=:NOTIF2,
                PCANCEL=:PCANCEL,
                BERCO=:BERCO,
                SOFACAMA=:SOFACAMA,
                RTOTAL=:RTOTAL,
                USRCHECKIN=:USRCHECKIN,
                PRESENCIAL=:PRESENCIAL,
                SEF=:SEF,
                USRSEF=:USRSEF,
                USRINSRT=:USRINSRT,
                INSTR=:INSTR,
                USRINSTR=:USRINSTR,
                FTNOME=:FTNOME,
                FTMORADA=:FTMORADA,
                FTLOCAL=:FTLOCAL,
                FTCODPOST=:FTCODPOST,
                FTNCONT=:FTNCONT,
                FTEMAIL=:FTEMAIL
            WHERE RSSTAMP=:RSSTAMP
            {_rs_write_clause('RS')}
        """), {
            'RSSTAMP': rsstamp,
            'current_feid': current_feid,
            'ALOJAMENTO': str(_h('ALOJAMENTO') or '').strip(),
            'RDATA': rdata,
            'ORIGEM': str(_h('ORIGEM') or '').strip(),
            'RESERVA': str(_h('RESERVA') or '').strip(),
            'DATAIN': datain,
            'DATAOUT': dataout,
            'HORAIN': str(_h('HORAIN') or '').strip()[:5],
            'HORAOUT': str(_h('HORAOUT') or '').strip()[:5],
            'NOITES': noites,
            'NOME': str(_h('NOME') or '').strip(),
            'PAIS': str(_h('PAIS') or '').strip(),
            'ADULTOS': _to_int(_h('ADULTOS', 0), 0),
            'CRIANCAS': _to_int(_h('CRIANCAS', 0), 0),
            'BEBES': _to_int(_h('BEBES', 0), 0),
            'ESTADIA': _num(_h('ESTADIA', 0), 0),
            'LIMPEZA': _num(_h('LIMPEZA', 0), 0),
            'COMISSAO': _num(_h('COMISSAO', 0), 0),
            'READY': 1 if _to_int(_h('READY', 0), 0) == 1 else 0,
            'ENTROU': 1 if _to_int(_h('ENTROU', 0), 0) == 1 else 0,
            'SAIU': 1 if _to_int(_h('SAIU', 0), 0) == 1 else 0,
            'ALERTA': 1 if _to_int(_h('ALERTA', 0), 0) == 1 else 0,
            'OBS': str(_h('OBS') or '').strip(),
            'CANCELADA': 1 if _to_int(_h('CANCELADA', 0), 0) == 1 else 0,
            'DTCANCEL': dtcancel,
            'DIASCANCEL': _to_int(_h('DIASCANCEL', 0), 0),
            'NOTIF': 1 if _to_int(_h('NOTIF', 0), 0) == 1 else 0,
            'NOTIF2': 1 if _to_int(_h('NOTIF2', 0), 0) == 1 else 0,
            'PCANCEL': _num(_h('PCANCEL', 0), 0),
            'BERCO': 1 if _to_int(_h('BERCO', 0), 0) == 1 else 0,
            'SOFACAMA': 1 if _to_int(_h('SOFACAMA', 0), 0) == 1 else 0,
            'RTOTAL': 1 if _to_int(_h('RTOTAL', 0), 0) == 1 else 0,
            'USRCHECKIN': str(_h('USRCHECKIN') or '').strip(),
            'PRESENCIAL': 1 if _to_int(_h('PRESENCIAL', 0), 0) == 1 else 0,
            'SEF': 1 if _to_int(_h('SEF', 0), 0) == 1 else 0,
            'USRSEF': str(_h('USRSEF') or '').strip(),
            'USRINSRT': str(_h('USRINSRT') or '').strip(),
            'INSTR': 1 if _to_int(_h('INSTR', 0), 0) == 1 else 0,
            'USRINSTR': str(_h('USRINSTR') or '').strip(),
            'FTNOME': str(_h('FTNOME') or '').strip(),
            'FTMORADA': str(_h('FTMORADA') or '').strip(),
            'FTLOCAL': str(_h('FTLOCAL') or '').strip(),
            'FTCODPOST': str(_h('FTCODPOST') or '').strip(),
            'FTNCONT': str(_h('FTNCONT') or '').strip(),
            'FTEMAIL': str(_h('FTEMAIL') or '').strip(),
        })

        _ensure_rsguests_siba_columns()
        db.session.execute(text("DELETE FROM dbo.RSGUESTS WHERE RSSTAMP = :s"), {'s': rsstamp})
        for idx, guest in enumerate(guests):
            if not isinstance(guest, dict):
                continue
            birth_raw = str(guest.get('DTNASC') or '').strip()
            if birth_raw:
                try:
                    birth = datetime.fromisoformat(birth_raw.replace('Z', '')).date()
                except Exception:
                    birth = date(1900, 1, 1)
            else:
                birth = date(1900, 1, 1)

            dtcri_raw = str(guest.get('DTCRI') or '').strip()
            dtalt_raw = str(guest.get('DTALT') or '').strip()
            try:
                dtcri = datetime.fromisoformat(dtcri_raw.replace('Z', '')) if dtcri_raw else datetime.now()
            except Exception:
                dtcri = datetime.now()
            try:
                dtalt = datetime.fromisoformat(dtalt_raw.replace('Z', '')) if dtalt_raw else datetime.now()
            except Exception:
                dtalt = datetime.now()

            db.session.execute(text("""
                INSERT INTO dbo.RSGUESTS
                (RSGUESTSTAMP, RSSTAMP, NOME_COMPLETO, NOME, APELIDO, DTNASC, NACIONALIDADE, PAIS_RESIDENCIA,
                 TIPO_DOC, NUM_DOC, PAIS_EMISSOR_DOC, NACIONALIDADE_ICAO, PAIS_RESIDENCIA_ICAO,
                 PAIS_EMISSOR_DOC_ICAO, TIPO_DOC_SIBA, ATIVO, DTCRI, DTALT, HORAIN, HORAOUT, TRANSPORTE, VOO, BERCO)
                VALUES
                (:RSGUESTSTAMP, :RSSTAMP, :NOME_COMPLETO, :NOME, :APELIDO, :DTNASC, :NACIONALIDADE, :PAIS_RESIDENCIA,
                 :TIPO_DOC, :NUM_DOC, :PAIS_EMISSOR_DOC, :NACIONALIDADE_ICAO, :PAIS_RESIDENCIA_ICAO,
                 :PAIS_EMISSOR_DOC_ICAO, :TIPO_DOC_SIBA, :ATIVO, :DTCRI, :DTALT, :HORAIN, :HORAOUT, :TRANSPORTE, :VOO, :BERCO)
            """), {
                'RSGUESTSTAMP': str(guest.get('RSGUESTSTAMP') or '').strip() or _new_stamp_25(),
                'RSSTAMP': rsstamp,
                'NOME_COMPLETO': str(guest.get('NOME_COMPLETO') or f"{str(guest.get('NOME') or '').strip()} {str(guest.get('APELIDO') or '').strip()}").strip(),
                'NOME': str(guest.get('NOME') or '').strip()[:100],
                'APELIDO': str(guest.get('APELIDO') or '').strip()[:100],
                'DTNASC': birth,
                'NACIONALIDADE': str(guest.get('NACIONALIDADE') or '').strip()[:60],
                'PAIS_RESIDENCIA': str(guest.get('PAIS_RESIDENCIA') or '').strip()[:60],
                'TIPO_DOC': str(guest.get('TIPO_DOC') or '').strip()[:30],
                'NUM_DOC': str(guest.get('NUM_DOC') or '').strip()[:40],
                'PAIS_EMISSOR_DOC': str(guest.get('PAIS_EMISSOR_DOC') or '').strip()[:60],
                'NACIONALIDADE_ICAO': country_to_icao(guest.get('NACIONALIDADE_ICAO') or guest.get('nacionalidade_icao') or guest.get('NACIONALIDADE')),
                'PAIS_RESIDENCIA_ICAO': country_to_icao(guest.get('PAIS_RESIDENCIA_ICAO') or guest.get('pais_residencia_icao') or guest.get('PAIS_RESIDENCIA')),
                'PAIS_EMISSOR_DOC_ICAO': country_to_icao(guest.get('PAIS_EMISSOR_DOC_ICAO') or guest.get('pais_emissor_doc_icao') or guest.get('PAIS_EMISSOR_DOC')),
                'TIPO_DOC_SIBA': doc_type_to_siba(guest.get('TIPO_DOC_SIBA') or guest.get('tipo_doc_siba') or guest.get('TIPO_DOC')),
                'ATIVO': 1 if _to_int(guest.get('ATIVO'), 1) == 1 else 0,
                'DTCRI': dtcri,
                'DTALT': dtalt,
                'HORAIN': str(guest.get('HORAIN') or '').strip()[:5],
                'HORAOUT': str(guest.get('HORAOUT') or '').strip()[:5],
                'TRANSPORTE': str(guest.get('TRANSPORTE') or '').strip()[:30],
                'VOO': str(guest.get('VOO') or '').strip()[:20],
                'BERCO': 1 if _to_int(guest.get('BERCO'), 0) == 1 else 0,
            })

        db.session.commit()
        return jsonify({'ok': True})

    @app.route('/api/reservas/rs/<rsstamp>/siba/communicate', methods=['POST'])
    @login_required
    def api_reservas_rs_siba_communicate(rsstamp):
        current_feid, error_response = _current_feid_or_json_error()
        if error_response:
            return error_response

        _ensure_rsguests_siba_columns()
        flags = db.session.execute(text("""
            SELECT
                CASE WHEN COL_LENGTH('dbo.AL', 'SIBA_UH') IS NULL THEN 0 ELSE 1 END AS HAS_SIBA_UH,
                CASE WHEN COL_LENGTH('dbo.AL', 'SIBA_ESTAB') IS NULL THEN 0 ELSE 1 END AS HAS_SIBA_ESTAB,
                CASE WHEN COL_LENGTH('dbo.AL', 'SIBA_CHAVE') IS NULL THEN 0 ELSE 1 END AS HAS_SIBA_CHAVE
        """)).mappings().first() or {}
        siba_uh_sql = "ISNULL(AL.SIBA_UH, '')" if int(flags.get('HAS_SIBA_UH') or 0) else "CAST('' AS varchar(25))"
        siba_estab_sql = "ISNULL(AL.SIBA_ESTAB, 0)" if int(flags.get('HAS_SIBA_ESTAB') or 0) else "CAST(0 AS int)"
        siba_chave_sql = "ISNULL(AL.SIBA_CHAVE, '')" if int(flags.get('HAS_SIBA_CHAVE') or 0) else "CAST('' AS varchar(25))"

        rs = db.session.execute(text(f"""
            SELECT
                RS.RSSTAMP,
                ISNULL(RS.RESERVA, '') AS RESERVA,
                ISNULL(RS.ALOJAMENTO, '') AS ALOJAMENTO,
                CAST(RS.DATAIN AS date) AS DATAIN,
                CAST(RS.DATAOUT AS date) AS DATAOUT,
                ISNULL(RS.HORAIN, '') AS HORAIN,
                ISNULL(RS.HORAOUT, '') AS HORAOUT,
                ISNULL(RS.ADULTOS, 0) AS ADULTOS,
                ISNULL(RS.CRIANCAS, 0) AS CRIANCAS,
                ISNULL(RS.SEF, 0) AS SEF,
                ISNULL(RS.USRSEF, '') AS USRSEF,
                ISNULL(AL.NOME, RS.ALOJAMENTO) AS AL_NOME,
                ISNULL(AL.MORADA, '') AS AL_MORADA,
                ISNULL(AL.LOCAL, '') AS AL_LOCAL,
                ISNULL(AL.CODPOST, '') AS AL_CODPOST,
                ISNULL(FE.NOME, '') AS FE_NOME,
                ISNULL(FE.EMAIL, '') AS FE_EMAIL,
                ISNULL(FE.TELEFONE, '') AS FE_TELEFONE,
                {siba_uh_sql} AS SIBA_UH,
                {siba_estab_sql} AS SIBA_ESTAB,
                {siba_chave_sql} AS SIBA_CHAVE
            FROM dbo.RS AS RS
            LEFT JOIN dbo.AL AS AL
              ON LTRIM(RTRIM(ISNULL(AL.NOME, ''))) = LTRIM(RTRIM(ISNULL(RS.ALOJAMENTO, '')))
            LEFT JOIN dbo.FE AS FE
              ON ISNULL(FE.FEID, 0) = :current_feid
            WHERE RS.RSSTAMP = :s
              {_rs_write_clause('RS')}
        """), {'s': rsstamp, 'current_feid': current_feid}).mappings().first()
        if not rs:
            if _rs_exists_any(rsstamp):
                return jsonify({'error': 'Sem permissao para comunicar esta reserva na empresa ativa.'}), 403
            return jsonify({'error': 'Reserva nao encontrada'}), 404

        guest_rows = db.session.execute(text("""
            SELECT
                RSGUESTSTAMP,
                ISNULL(NOME_COMPLETO, '') AS NOME_COMPLETO,
                ISNULL(NOME, '') AS NOME,
                ISNULL(APELIDO, '') AS APELIDO,
                DTNASC,
                ISNULL(NACIONALIDADE, '') AS NACIONALIDADE,
                ISNULL(PAIS_RESIDENCIA, '') AS PAIS_RESIDENCIA,
                ISNULL(TIPO_DOC, '') AS TIPO_DOC,
                ISNULL(NUM_DOC, '') AS NUM_DOC,
                ISNULL(PAIS_EMISSOR_DOC, '') AS PAIS_EMISSOR_DOC,
                ISNULL(NACIONALIDADE_ICAO, '') AS NACIONALIDADE_ICAO,
                ISNULL(PAIS_RESIDENCIA_ICAO, '') AS PAIS_RESIDENCIA_ICAO,
                ISNULL(PAIS_EMISSOR_DOC_ICAO, '') AS PAIS_EMISSOR_DOC_ICAO,
                ISNULL(TIPO_DOC_SIBA, '') AS TIPO_DOC_SIBA
            FROM dbo.RSGUESTS
            WHERE RSSTAMP = :s
              AND ISNULL(ATIVO, 1) = 1
            ORDER BY ISNULL(DTCRI, '19000101'), RSGUESTSTAMP
        """), {'s': rsstamp}).mappings().all()

        missing = []

        def _missing(message):
            if message:
                missing.append(message)

        reserva = str(rs.get('RESERVA') or '').strip()
        alojamento = str(rs.get('ALOJAMENTO') or '').strip()
        siba_uh = str(rs.get('SIBA_UH') or '').strip()
        siba_chave = str(rs.get('SIBA_CHAVE') or '').strip()
        siba_estab = _to_int(rs.get('SIBA_ESTAB'), 0)
        siba_uh_digits = re.sub(r'\D+', '', siba_uh)
        siba_chave_digits = re.sub(r'\D+', '', siba_chave)
        unit_codpost_digits = re.sub(r'\D+', '', str(rs.get('AL_CODPOST') or ''))
        unit_phone_digits = re.sub(r'\D+', '', str(rs.get('FE_TELEFONE') or '')) or '000000000'
        unit_email = str(rs.get('FE_EMAIL') or '').strip()
        if not reserva:
            _missing('Reserva sem codigo.')
        if not alojamento:
            _missing('Reserva sem alojamento.')
        if not rs.get('DATAIN'):
            _missing('Reserva sem data de check-in.')
        if not rs.get('DATAOUT'):
            _missing('Reserva sem data de check-out.')
        if rs.get('DATAIN') and rs.get('DATAIN') > date.today():
            _missing('A data de entrada ainda e futura; o SIBA so aceita data de entrada igual ou anterior ao dia atual.')
        if len(siba_uh_digits) != 9:
            _missing('Alojamento sem SIBA_UH valido (NIPC com 9 digitos).')
        if siba_estab < 0 or siba_estab > 99:
            _missing('Alojamento sem SIBA_ESTAB valido (0 a 99).')
        if not siba_chave_digits:
            _missing('Alojamento sem SIBA_CHAVE valida.')
        if not str(rs.get('AL_NOME') or '').strip():
            _missing('Alojamento sem nome.')
        if not str(rs.get('AL_MORADA') or '').strip():
            _missing('Alojamento sem morada.')
        if not str(rs.get('AL_LOCAL') or '').strip():
            _missing('Alojamento sem localidade.')
        if len(unit_codpost_digits) < 7:
            _missing('Alojamento sem codigo postal completo.')
        if not unit_email:
            _missing('Entidade ativa sem email para contacto SIBA.')

        expected_guests = max(0, _to_int(rs.get('ADULTOS'), 0) + _to_int(rs.get('CRIANCAS'), 0))
        if expected_guests <= 0:
            _missing('Reserva sem numero de hospedes.')
        if expected_guests > 0 and len(guest_rows) < expected_guests:
            _missing(f'Faltam {expected_guests - len(guest_rows)} hospede(s) face ao total da reserva.')
        selected_guests = list(guest_rows)
        if not selected_guests:
            _missing('Reserva sem hospedes ativos.')

        guests_payload = []
        for idx, guest in enumerate(selected_guests, start=1):
            nome = str(guest.get('NOME') or '').strip()
            apelido = str(guest.get('APELIDO') or '').strip()
            nome_completo = str(guest.get('NOME_COMPLETO') or f'{nome} {apelido}').strip()
            birth = guest.get('DTNASC')
            if isinstance(birth, datetime):
                birth_text = birth.date().isoformat()
            elif isinstance(birth, date):
                birth_text = birth.isoformat()
            else:
                birth_text = str(birth or '').strip()[:10]
            nacionalidade_icao = (str(guest.get('NACIONALIDADE_ICAO') or '').strip()
                                  or country_to_icao(guest.get('NACIONALIDADE')))
            residencia_icao = (str(guest.get('PAIS_RESIDENCIA_ICAO') or '').strip()
                               or country_to_icao(guest.get('PAIS_RESIDENCIA')))
            emissor_icao = (str(guest.get('PAIS_EMISSOR_DOC_ICAO') or '').strip()
                            or country_to_icao(guest.get('PAIS_EMISSOR_DOC')))
            tipo_doc_siba = (str(guest.get('TIPO_DOC_SIBA') or '').strip()
                             or doc_type_to_siba(guest.get('TIPO_DOC')))
            num_doc = str(guest.get('NUM_DOC') or '').strip()
            label = f'Hospede {idx}'

            if not nome_completo:
                _missing(f'{label}: nome em falta.')
            if not nome:
                _missing(f'{label}: primeiro nome em falta.')
            if not apelido:
                _missing(f'{label}: apelido em falta.')
            if not birth_text or birth_text in ('1900-01-01', '0001-01-01'):
                _missing(f'{label}: data de nascimento em falta.')
            if not nacionalidade_icao:
                _missing(f'{label}: nacionalidade/local de nascimento sem codigo ICAO.')
            if not residencia_icao:
                _missing(f'{label}: pais de residencia sem codigo ICAO.')
            if not tipo_doc_siba:
                _missing(f'{label}: tipo de documento SIBA em falta.')
            if not num_doc:
                _missing(f'{label}: numero de documento em falta.')
            if not emissor_icao:
                _missing(f'{label}: pais emissor do documento sem codigo ICAO.')

            guests_payload.append({
                'rsgueststamp': str(guest.get('RSGUESTSTAMP') or '').strip(),
                'nome': nome,
                'apelido': apelido,
                'nome_completo': nome_completo,
                'data_nascimento': birth_text,
                'nacionalidade_icao': nacionalidade_icao,
                'pais_residencia_icao': residencia_icao,
                'tipo_doc_siba': tipo_doc_siba,
                'num_doc': num_doc,
                'pais_emissor_doc_icao': emissor_icao,
            })

        payload = {
            'reservation': {
                'rsstamp': str(rs.get('RSSTAMP') or '').strip(),
                'reserva': reserva,
                'alojamento': alojamento,
                'datain': rs.get('DATAIN').isoformat() if rs.get('DATAIN') else '',
                'dataout': rs.get('DATAOUT').isoformat() if rs.get('DATAOUT') else '',
                'horain': str(rs.get('HORAIN') or '').strip(),
                'horaout': str(rs.get('HORAOUT') or '').strip(),
            },
            'siba': {
                'uh': siba_uh_digits,
                'estabelecimento': siba_estab,
                'chave': siba_chave_digits,
                'chave_configurada': bool(siba_chave_digits),
            },
            'unit': {
                'codigo': siba_uh_digits,
                'estabelecimento': siba_estab,
                'nome': str(rs.get('AL_NOME') or alojamento).strip(),
                'abreviatura': str(rs.get('AL_NOME') or alojamento).strip(),
                'morada': str(rs.get('AL_MORADA') or '').strip(),
                'localidade': str(rs.get('AL_LOCAL') or '').strip(),
                'codpost': str(rs.get('AL_CODPOST') or '').strip(),
                'telefone': unit_phone_digits,
                'fax': '',
                'contacto_nome': str(rs.get('FE_NOME') or '').strip() or str(getattr(current_user, 'LOGIN', '') or '').strip(),
                'contacto_email': unit_email,
            },
            'guests': guests_payload,
            'numero_ficheiro': int(datetime.now().strftime('%H%M%S')[-5:]),
            'data_movimento': date.today().isoformat(),
        }

        if missing:
            payload['siba'].pop('chave', None)
            return jsonify({
                'ok': False,
                'error': 'Dados insuficientes para comunicar AIMA/SEF.',
                'missing': missing,
                'payload': payload,
            }), 400

        try:
            siba_result = send_siba_boletins(
                payload,
                endpoint=os.environ.get('SIBA_WS_URL', '').strip() or 'https://siba.ssi.gov.pt/baws/boletinsalojamento.asmx',
                timeout=_to_int(os.environ.get('SIBA_WS_TIMEOUT'), 45),
            )
        except SibaError as exc:
            payload['siba'].pop('chave', None)
            return jsonify({
                'ok': False,
                'sent': False,
                'error': str(exc),
                'payload': payload,
            }), 502

        user_login = str(getattr(current_user, 'LOGIN', '') or '').strip()
        db.session.execute(text(f"""
            UPDATE dbo.RS
            SET SEF = 1,
                USRSEF = :usrsef
            WHERE RSSTAMP = :s
              {_rs_write_clause('RS')}
        """), {'s': rsstamp, 'current_feid': current_feid, 'usrsef': user_login})
        db.session.commit()
        payload['siba'].pop('chave', None)
        return jsonify({
            'ok': True,
            'sent': True,
            'ready': True,
            'message': 'Boletins comunicados ao SIBA.',
            'siba_result': siba_result.get('result'),
            'payload': payload,
            'header': {
                'SEF': 1,
                'USRSEF': user_login,
            },
        })

    @app.route('/api/reservas/rs/<rsstamp>/delete', methods=['POST'])
    @login_required
    def api_reservas_rs_delete(rsstamp):
        current_feid, error_response = _current_feid_or_json_error()
        if error_response:
            return error_response
        exists = db.session.execute(text(f"""
            SELECT RSSTAMP
            FROM dbo.RS
            WHERE RSSTAMP=:s
            {_rs_write_clause('RS')}
        """), {'s': rsstamp, 'current_feid': current_feid}).mappings().first()
        if not exists:
            if _rs_exists_any(rsstamp):
                return jsonify({'error': 'Sem permissão para eliminar esta reserva na empresa ativa.'}), 403
            return jsonify({'error': 'Reserva não encontrada'}), 404
        db.session.execute(text("DELETE FROM dbo.RSGUESTS WHERE RSSTAMP=:s"), {'s': rsstamp})
        db.session.execute(text(f"DELETE FROM dbo.RS WHERE RSSTAMP=:s {_rs_write_clause('RS')}"), {'s': rsstamp, 'current_feid': current_feid})
        db.session.commit()
        return jsonify({'ok': True})

    def _rs_reservation_code(rsstamp):
        row = db.session.execute(text("""
            SELECT TOP 1 LTRIM(RTRIM(ISNULL(RESERVA,''))) AS RESERVA
            FROM dbo.RS
            WHERE RSSTAMP = :s
        """), {'s': rsstamp}).mappings().first()
        if not row:
            return None
        return str(row.get('RESERVA') or '').strip()

    def _sync_config():
        base = (
            os.environ.get('SYNC_ENGINE_BASE_URL')
            or os.environ.get('INTEGRATION_API_BASE_URL')
            or 'http://sync.szeroapp.com:8000'
        ).strip().rstrip('/')
        if base and not re.match(r'^https?://', base, flags=re.I):
            base = f"http://{base}"
        token = (
            os.environ.get('SYNC_ENGINE_TOKEN')
            or os.environ.get('INTEGRATION_API_TOKEN')
            or 'w2QBCh_4pNBvznHUTLngsQLWbICbnGeD7o2llLZP_oi1LywZSnVNj5UPByWsL6UC'
        ).strip()
        return base, token

    def _sync_call(path, method='GET', body=None, timeout=25):
        base, token = _sync_config()
        if not token:
            return 500, {'error': 'Token de integração não configurado'}, base, None
        url = f"{base}{path}"
        headers = {
            'Authorization': f'Bearer {token}',
            'Accept': 'application/json',
            'User-Agent': 'SZEROAPP/1.0',
        }
        data = None
        if body is not None:
            headers['Content-Type'] = 'application/json'
            data = json.dumps(body).encode('utf-8')
        req = Request(url, headers=headers, data=data, method=method)

        try:
            with urlopen(req, timeout=timeout) as resp:
                status = int(getattr(resp, 'status', 200) or 200)
                raw = resp.read()
                try:
                    payload = json.loads(raw.decode('utf-8', errors='ignore')) if raw else {}
                except Exception:
                    payload = {}
                return status, payload, base, url
        except HTTPError as e:
            status = int(getattr(e, 'code', 500) or 500)
            raw = b''
            try:
                raw = e.read() or b''
            except Exception:
                raw = b''
            try:
                payload = json.loads(raw.decode('utf-8', errors='ignore')) if raw else {}
            except Exception:
                payload = {'error': raw.decode('utf-8', errors='ignore') if raw else ''}
            return status, payload, base, url
        except (URLError, ConnectionResetError, TimeoutError, OSError) as e:
            try:
                app.logger.warning('Falha ao contactar sync_engine (%s): %s', url, e)
            except Exception:
                pass
            return 502, {'error': f'Falha de rede para {base}: {e}'}, base, url
        except Exception as e:
            try:
                app.logger.exception('Erro inesperado no sync_engine (%s): %s', url, e)
            except Exception:
                pass
            return 502, {'error': f'Erro inesperado: {e}'}, base, url

    def _normalize_chat_messages(payload):
        if isinstance(payload, dict):
            msg_list = payload.get('messages')
            if not isinstance(msg_list, list):
                msg_list = payload.get('data') if isinstance(payload.get('data'), list) else []
        elif isinstance(payload, list):
            msg_list = payload
        else:
            msg_list = []

        def _s(v):
            return str(v or '').strip()

        out = []
        for idx, item in enumerate(msg_list):
            if not isinstance(item, dict):
                continue
            sender_obj = item.get('sender') if isinstance(item.get('sender'), dict) else {}
            sender_role_raw = _s(
                item.get('sender_role')
                or item.get('role')
                or item.get('direction')
                or item.get('sender_type')
                or sender_obj.get('role')
            ).lower()
            sender_name = _s(
                item.get('sender_name')
                or item.get('author_name')
                or item.get('from_name')
                or item.get('author')
                or item.get('sender')
                or sender_obj.get('name')
            )
            text_msg = _s(
                item.get('message')
                or item.get('body')
                or item.get('content')
                or item.get('text')
            )
            created_at = _s(
                item.get('created_at')
                or item.get('createdAt')
                or item.get('date')
                or item.get('sent_at')
                or item.get('timestamp')
            )
            direction = 'guest'
            if sender_role_raw:
                if any(k in sender_role_raw for k in ('host', 'owner', 'team', 'admin', 'out', 'sent', 'agent')):
                    direction = 'host'
                elif any(k in sender_role_raw for k in ('guest', 'traveler', 'client', 'in', 'recv', 'received')):
                    direction = 'guest'
            out.append({
                'id': _s(item.get('id') or item.get('message_id') or item.get('uuid') or idx),
                'sender_name': sender_name or ('Nós' if direction == 'host' else 'Hóspede'),
                'sender_role': sender_role_raw,
                'direction': direction,
                'text': text_msg,
                'created_at': created_at,
            })
        return out

    @app.route('/api/reservas/rs/<rsstamp>/chat', methods=['GET'])
    @login_required
    def api_reservas_rs_chat(rsstamp):
        reservation_code = _rs_reservation_code(rsstamp)
        if reservation_code is None:
            return jsonify({'error': 'Reserva não encontrada'}), 404
        if not reservation_code:
            return jsonify({'reservation_code': '', 'messages': [], 'count': 0})

        path = f"/api/integrations/reservations/{quote(reservation_code)}/messages"
        status, payload, sync_base, _ = _sync_call(path, method='GET', timeout=25)
        if status != 200:
            msg = (payload or {}).get('error') if isinstance(payload, dict) else ''
            return jsonify({'error': msg or f'Erro de integração ({status})', 'sync_base': sync_base}), (status if status in (400, 401, 403, 404, 429, 503) else 502)

        out = _normalize_chat_messages(payload)
        return jsonify({
            'reservation_code': reservation_code,
            'messages': out,
            'count': len(out),
            'sync_base': sync_base,
        })

