    @app.route('/api/entidades/save', methods=['POST'])
    @login_required
    def api_entidades_save():
        _ensure_fe_cluster_schema()
        body = request.get_json(silent=True) or {}
        raw = body.get('row') if isinstance(body.get('row'), dict) else body
        raw_modules = body.get('modules') if isinstance(body.get('modules'), list) else []
        if not isinstance(raw, dict):
            return jsonify({'error': 'Payload inválido.'}), 400

        festamp = (raw.get('FESTAMP') or '').strip()
        exists = None
        if festamp:
            exists = db.session.execute(
                text("SELECT TOP 1 FESTAMP FROM dbo.FE WHERE FESTAMP=:festamp"),
                {'festamp': festamp}
            ).mappings().first()

        if exists:
            if not _fe_has_permission('editar'):
                return jsonify({'error': 'Sem permissão para editar entidades.'}), 403
        else:
            if not _fe_has_permission('inserir'):
                return jsonify({'error': 'Sem permissão para criar entidades.'}), 403

        user_login = (getattr(current_user, 'LOGIN', '') or '').strip()
        payload = _default_fe_payload(user_login)
        payload.update({
            'FESTAMP': festamp or payload['FESTAMP'],
            'NIF': _to_int(raw.get('NIF'), 0),
            'NOME': (raw.get('NOME') or '').strip(),
            'NOMEFISCAL': (raw.get('NOMEFISCAL') or '').strip(),
            'ATIVIDADE': (raw.get('ATIVIDADE') or '').strip(),
            'MORADA': (raw.get('MORADA') or '').strip(),
            'MORADA2': (raw.get('MORADA2') or '').strip(),
            'CODPOST': (raw.get('CODPOST') or '').strip(),
            'LOCAL': (raw.get('LOCAL') or '').strip(),
            'PAISISO2': (raw.get('PAISISO2') or 'PT').strip().upper()[:2],
            'EMAIL': (raw.get('EMAIL') or '').strip(),
            'TELEFONE': (raw.get('TELEFONE') or '').strip(),
            'ATIVA': 1 if raw.get('ATIVA') else 0,
            'OBS': (raw.get('OBS') or '').strip(),
            'CERTNUM': (raw.get('CERTNUM') or '').strip(),
            'ATCUD_PREFIX': (raw.get('ATCUD_PREFIX') or '').strip(),
            'QRVER': (raw.get('QRVER') or '').strip(),
            'HASHVER': (raw.get('HASHVER') or '').strip(),
            'KEYID': (raw.get('KEYID') or '').strip(),
            'RSA_PRIV_PATH': (raw.get('RSA_PRIV_PATH') or '').strip(),
            'RSA_PUB_PATH': (raw.get('RSA_PUB_PATH') or '').strip(),
            'AT_WS_ATIVO': 1 if raw.get('AT_WS_ATIVO') else 0,
            'AT_WS_AMBIENTE': (raw.get('AT_WS_AMBIENTE') or '').strip(),
            'AT_WS_USER': (raw.get('AT_WS_USER') or '').strip(),
            'AT_WS_PASS': (raw.get('AT_WS_PASS') or '').strip(),
            'E_CLUSTER': 1 if raw.get('E_CLUSTER') else 0,
            'LOGOTIPO_PATH': (raw.get('LOGOTIPO_PATH') or '').strip(),
            'USERALTERACAO': user_login,
        })

        if not payload['NOME']:
            return jsonify({'error': 'O campo Nome é obrigatório.'}), 400
        if not payload['NOMEFISCAL']:
            return jsonify({'error': 'O campo Nome fiscal é obrigatório.'}), 400
        if payload['NIF'] <= 0:
            return jsonify({'error': 'O campo NIF é obrigatório.'}), 400

        existing_cluster_members = _fe_cluster_members_count(payload['FESTAMP']) if exists else 0
        existing_cluster_parent_count = _fe_cluster_parent_count(payload['FESTAMP']) if exists else 0
        if not payload['E_CLUSTER'] and existing_cluster_members > 0:
            return jsonify({'error': 'Não pode desmarcar "É cluster" enquanto existirem entidades associadas.'}), 400
        if payload['E_CLUSTER'] and existing_cluster_parent_count > 0:
            return jsonify({'error': 'Uma FE que já pertence a um cluster não pode ser marcada como cluster.'}), 400

        normalized_modules = []
        seen_modstamps = set()
        for item in raw_modules:
            if not isinstance(item, dict):
                continue
            modstamp_value = (item.get('MODSTAMP') or '').strip()
            if not modstamp_value or modstamp_value in seen_modstamps:
                continue
            seen_modstamps.add(modstamp_value)
            normalized_modules.append({
                'MODSTAMP': modstamp_value,
                'ATIVO': 1 if item.get('ATIVO', item.get('ASSOCIADO', 0)) else 0,
                'OBS': (item.get('OBS') or '').strip()[:200],
            })

        try:
            logo_set_sql = "\n                        LOGOTIPO_PATH=:LOGOTIPO_PATH," if _fe_logo_column_available() else ""
            logo_insert_columns = ", LOGOTIPO_PATH" if _fe_logo_column_available() else ""
            logo_insert_values = ", :LOGOTIPO_PATH" if _fe_logo_column_available() else ""
            if exists:
                db.session.execute(text("""
                    UPDATE dbo.FE
                    SET NIF=:NIF,
                        NOME=:NOME,
                        NOMEFISCAL=:NOMEFISCAL,
                        ATIVIDADE=:ATIVIDADE,
                        MORADA=:MORADA,
                        MORADA2=:MORADA2,
                        CODPOST=:CODPOST,
                        LOCAL=:LOCAL,
                        PAISISO2=:PAISISO2,
                        EMAIL=:EMAIL,
                        TELEFONE=:TELEFONE,
                        ATIVA=:ATIVA,
                        OBS=:OBS,
                        CERTNUM=:CERTNUM,
                        ATCUD_PREFIX=:ATCUD_PREFIX,
                        QRVER=:QRVER,
                        HASHVER=:HASHVER,
                        KEYID=:KEYID,
                        RSA_PRIV_PATH=:RSA_PRIV_PATH,
                        RSA_PUB_PATH=:RSA_PUB_PATH,
                        AT_WS_ATIVO=:AT_WS_ATIVO,
                        AT_WS_AMBIENTE=:AT_WS_AMBIENTE,
                        AT_WS_USER=:AT_WS_USER,
                        AT_WS_PASS=:AT_WS_PASS,
                        E_CLUSTER=:E_CLUSTER,
                        """ + logo_set_sql + """
                        DTAlteracao=GETDATE(),
                        USERALTERACAO=:USERALTERACAO
                    WHERE FESTAMP=:FESTAMP
                """), payload)
            else:
                db.session.execute(text("""
                    INSERT INTO dbo.FE
                    (
                        FESTAMP, NIF, NOME, NOMEFISCAL, ATIVIDADE, MORADA, MORADA2, CODPOST, LOCAL, PAISISO2,
                        EMAIL, TELEFONE, ATIVA, OBS, CERTNUM, ATCUD_PREFIX, QRVER, HASHVER, KEYID,
                        RSA_PRIV_PATH, RSA_PUB_PATH, AT_WS_ATIVO, AT_WS_AMBIENTE, AT_WS_USER, AT_WS_PASS, E_CLUSTER,
                        DTCriacao, DTAlteracao, USERCRIACAO, USERALTERACAO""" + logo_insert_columns + """
                    )
                    VALUES
                    (
                        :FESTAMP, :NIF, :NOME, :NOMEFISCAL, :ATIVIDADE, :MORADA, :MORADA2, :CODPOST, :LOCAL, :PAISISO2,
                        :EMAIL, :TELEFONE, :ATIVA, :OBS, :CERTNUM, :ATCUD_PREFIX, :QRVER, :HASHVER, :KEYID,
                        :RSA_PRIV_PATH, :RSA_PUB_PATH, :AT_WS_ATIVO, :AT_WS_AMBIENTE, :AT_WS_USER, :AT_WS_PASS, :E_CLUSTER,
                        GETDATE(), GETDATE(), :USERCRIACAO, :USERALTERACAO""" + logo_insert_values + """
                    )
                """), payload)

            if normalized_modules:
                valid_mods = {
                    str(r['MODSTAMP']).strip()
                    for r in db.session.execute(text("""
                        SELECT MODSTAMP
                        FROM dbo.MODULOS
                        WHERE MODSTAMP IN :modstamps
                    """).bindparams(bindparam('modstamps', expanding=True)), {
                        'modstamps': [m['MODSTAMP'] for m in normalized_modules]
                    }).mappings().all()
                }
            else:
                valid_mods = set()

            if normalized_modules and len(valid_mods) != len(normalized_modules):
                invalid = [m['MODSTAMP'] for m in normalized_modules if m['MODSTAMP'] not in valid_mods]
                db.session.rollback()
                return jsonify({'error': f'Módulos inválidos: {", ".join(invalid)}'}), 400

            db.session.execute(text("""
                DELETE FROM dbo.FE_MODULOS
                WHERE FESTAMP=:festamp
            """), {'festamp': payload['FESTAMP']})

            for module_row in normalized_modules:
                if not module_row['ATIVO']:
                    continue
                db.session.execute(text("""
                    INSERT INTO dbo.FE_MODULOS
                    (
                        FEMODSTAMP, FESTAMP, MODSTAMP, ATIVO, OBS,
                        DTCRI, DTALT, USERCRIACAO, USERALTERACAO
                    )
                    VALUES
                    (
                        :FEMODSTAMP, :FESTAMP, :MODSTAMP, :ATIVO, :OBS,
                        GETDATE(), GETDATE(), :USERCRIACAO, :USERALTERACAO
                    )
                """), {
                    'FEMODSTAMP': _new_stamp_25(),
                    'FESTAMP': payload['FESTAMP'],
                    'MODSTAMP': module_row['MODSTAMP'],
                    'ATIVO': 1,
                    'OBS': module_row['OBS'],
                    'USERCRIACAO': user_login,
                    'USERALTERACAO': user_login,
                })
            db.session.commit()
            return jsonify({'ok': True, 'festamp': payload['FESTAMP']})
        except Exception as e:
            db.session.rollback()
            app.logger.exception('Erro ao gravar entidade.')
            return jsonify({'error': str(e)}), 500

    @app.route('/api/entidades/<festamp>/delete', methods=['POST'])
    @login_required
    def api_entidades_delete(festamp):
        if not _fe_has_permission('eliminar'):
            return jsonify({'error': 'Sem permissão para eliminar entidades.'}), 403
        _ensure_fe_cluster_schema()
        festamp = (festamp or '').strip()
        if not festamp:
            return jsonify({'error': 'FESTAMP obrigatório.'}), 400
        if _fe_cluster_members_count(festamp) > 0:
            return jsonify({'error': 'Não pode eliminar uma FE cluster com entidades associadas.'}), 400
        if _fe_cluster_parent_count(festamp) > 0:
            return jsonify({'error': 'Não pode eliminar uma FE que está associada a um cluster.'}), 400
        try:
            res = db.session.execute(text("DELETE FROM dbo.FE WHERE FESTAMP=:festamp"), {'festamp': festamp})
            if not res.rowcount:
                db.session.rollback()
                return jsonify({'error': 'Entidade não encontrada.'}), 404
            db.session.commit()
            return jsonify({'ok': True})
        except Exception as e:
            db.session.rollback()
            app.logger.exception('Erro ao eliminar entidade.')
            return jsonify({'error': str(e)}), 500

    def _fts_user_login() -> str:
        return (getattr(current_user, 'LOGIN', '') or '').strip()

    def _fts_json_value(value):
        if isinstance(value, datetime):
            return value.isoformat(sep=' ', timespec='seconds')
        if isinstance(value, date):
            return value.isoformat()
        if isinstance(value, Decimal):
            try:
                if value == value.to_integral_value():
                    return int(value)
            except Exception:
                pass
            return float(value)
        return value

    def _fts_serialize_row(row):
        return {key: _fts_json_value(val) for key, val in dict(row or {}).items()}

    def _fts_parse_int(value, default=0):
        try:
            if value is None or str(value).strip() == '':
                return int(default)
            return int(float(str(value).replace(',', '.')))
        except Exception:
            return int(default)

    def _fts_parse_bit(value, default=0):
        raw = str(value if value is not None else '').strip().lower()
        if raw in ('1', 'true', 'sim', 'yes', 'on'):
            return 1
        if raw in ('0', 'false', 'nao', 'não', 'no', 'off'):
            return 0
        return 1 if int(default or 0) == 1 else 0

    def _fts_parse_datetime(value):
        raw = str(value or '').strip()
        if not raw:
            return datetime(1900, 1, 1)
        normalized = raw.replace('T', ' ')
        try:
            return datetime.fromisoformat(normalized[:19])
        except Exception:
            try:
                return datetime.combine(date.fromisoformat(normalized[:10]), datetime.min.time())
            except Exception:
                return datetime(1900, 1, 1)

    FTS_TIPOSAFT_OPTIONS = [
        {'value': '', 'label': '--'},
        {'value': 'FT', 'label': 'FT · Fatura'},
        {'value': 'FS', 'label': 'FS · Fatura simplificada'},
        {'value': 'FR', 'label': 'FR · Fatura-recibo'},
        {'value': 'GT', 'label': 'GT · Guia de transporte'},
        {'value': 'GR', 'label': 'GR · Guia de remessa'},
        {'value': 'NC', 'label': 'NC · Nota de crédito'},
        {'value': 'OR', 'label': 'OR · Orçamento'},
        {'value': 'PF', 'label': 'PF · Pro-Forma'},
    ]
    FTS_ALLOWED_TIPOSAFT = {str(item['value']).strip().upper() for item in FTS_TIPOSAFT_OPTIONS}
    FTS_ESTADO_OPTIONS = [
        {'value': 0, 'label': '0'},
        {'value': 1, 'label': '1'},
    ]
    FTS_ALLOWED_ESTADOS = {int(item['value']) for item in FTS_ESTADO_OPTIONS}
    FTSX_AT_ESTADO_OPTIONS = [
        {'value': 0, 'label': '0'},
        {'value': 1, 'label': '1'},
    ]
    FTSX_ALLOWED_AT_ESTADOS = {int(item['value']) for item in FTSX_AT_ESTADO_OPTIONS}
    FTS_FISCAL_TIPOSAFT = {'FT', 'FS', 'FR', 'NC', 'GT', 'GR'}

    def _fts_tiposaft_requires_atcud(tiposaft: str) -> bool:
        return str(tiposaft or '').strip().upper() in FTS_FISCAL_TIPOSAFT

    def _fts_base_query():
        transport_select = "ISNULL(S.IS_DOC_TRANSPORTE, 0) AS IS_DOC_TRANSPORTE" if _fts_transport_flag_available() else "CAST(0 AS bit) AS IS_DOC_TRANSPORTE"
        codigo_validacao_select = "ISNULL(S.CODIGO_VALIDACAO_AT, '') AS CODIGO_VALIDACAO_AT," if _fts_codigo_validacao_at_available() else "CAST('' AS varchar(50)) AS CODIGO_VALIDACAO_AT,"
        return """
            SELECT
                S.FTSSTAMP,
                S.FESTAMP,
                ISNULL(S.FEID, 0) AS FEID,
                ISNULL(S.NDOC, 0) AS NDOC,
                ISNULL(T.NMDOC, '') AS NMDOC,
                ISNULL(S.SERIE, '') AS SERIE,
                ISNULL(S.DESCR, '') AS DESCR,
                ISNULL(S.ATIVA, 0) AS ATIVA,
                ISNULL(S.ESTADO, 0) AS ESTADO,
                ISNULL(S.ANO, 0) AS ANO,
                ISNULL(S.ULTIMO_FNO, 0) AS ULTIMO_FNO,
                ISNULL(S.NO_SAFT, 0) AS NO_SAFT,
                ISNULL(S.TIPOSAFT, '') AS TIPOSAFT,
                """ + codigo_validacao_select + """
                """ + transport_select + """,
                S.DTCriacao,
                S.DTAlteracao,
                ISNULL(S.USERCRIACAO, '') AS USERCRIACAO,
                ISNULL(S.USERALTERACAO, '') AS USERALTERACAO,
                X.FTSXSTAMP,
                ISNULL(X.HASHVER, '') AS HASHVER,
                ISNULL(X.LAST_HASH, '') AS LAST_HASH,
                ISNULL(X.COD_VALIDACAO_SERIE, '') AS COD_VALIDACAO_SERIE,
                ISNULL(X.ATCUD_PREFIX, '') AS ATCUD_PREFIX,
                ISNULL(X.AT_SERIE_ESTADO, 0) AS AT_SERIE_ESTADO,
                X.AT_SERIE_DATA,
                ISNULL(X.AT_SERIE_MSG, '') AS AT_SERIE_MSG,
                X.DTCriacao AS FTSX_DTCriacao,
                X.DTAlteracao AS FTSX_DTAlteracao,
                ISNULL(X.USERCRIACAO, '') AS FTSX_USERCRIACAO,
                ISNULL(X.USERALTERACAO, '') AS FTSX_USERALTERACAO,
                ISNULL(X.FEID, 0) AS FTSX_FEID,
                CASE WHEN X.FTSXSTAMP IS NULL THEN 0 ELSE 1 END AS HAS_FTSX
            FROM dbo.FTS AS S
            LEFT JOIN dbo.V_TD AS T
              ON T.NDOC = S.NDOC
            LEFT JOIN dbo.FTSX AS X
              ON X.FTSSTAMP = S.FTSSTAMP
        """

    def _fts_fetch_row(ftsstamp: str, current_entity: dict):
        row = db.session.execute(text(f"""
            {_fts_base_query()}
            WHERE S.FTSSTAMP = :ftsstamp
              AND S.FESTAMP = :festamp
        """), {
            'ftsstamp': (ftsstamp or '').strip(),
            'festamp': (current_entity.get('FESTAMP') or '').strip(),
        }).mappings().first()
        return _fts_serialize_row(row) if row else None

    def _fts_fetch_parent_for_write(ftsstamp: str, current_entity: dict):
        return db.session.execute(text("""
            SELECT TOP 1
                FTSSTAMP,
                FESTAMP,
                ISNULL(FEID, 0) AS FEID,
                ISNULL(ANO, 0) AS ANO,
                ISNULL(ULTIMO_FNO, 0) AS ULTIMO_FNO
            FROM dbo.FTS
            WHERE FTSSTAMP = :ftsstamp
              AND FESTAMP = :festamp
        """), {
            'ftsstamp': (ftsstamp or '').strip(),
            'festamp': (current_entity.get('FESTAMP') or '').strip(),
        }).mappings().first()

    def _fts_duplicate_exists(current_entity: dict, ndoc: int, serie: str, ano: int, exclude_stamp: str = '') -> bool:
        row = db.session.execute(text("""
            SELECT TOP 1 1
            FROM dbo.FTS
            WHERE FESTAMP = :festamp
              AND NDOC = :ndoc
              AND ISNULL(SERIE, '') = :serie
              AND ANO = :ano
              AND (:exclude_stamp = '' OR FTSSTAMP <> :exclude_stamp)
        """), {
            'festamp': (current_entity.get('FESTAMP') or '').strip(),
            'ndoc': ndoc,
            'serie': (serie or '').strip(),
            'ano': ano,
            'exclude_stamp': (exclude_stamp or '').strip(),
        }).first()
        return bool(row)

    def _fts_validate_payload(payload: dict):
        ndoc = _fts_parse_int(payload.get('NDOC'), 0)
        serie = str(payload.get('SERIE') or '').strip()
        descr = str(payload.get('DESCR') or '').strip()
        estado = _fts_parse_int(payload.get('ESTADO'), 0)
        ativa = _fts_parse_bit(payload.get('ATIVA'), 0)
        no_saft = _fts_parse_bit(payload.get('NO_SAFT'), 0)
        is_doc_transporte = _fts_parse_bit(payload.get('IS_DOC_TRANSPORTE'), 0)
        tiposaft = str(payload.get('TIPOSAFT') or '').strip().upper()
        codigo_validacao_at = str(payload.get('CODIGO_VALIDACAO_AT') or '').strip().upper()
        if ndoc <= 0:
            raise ValueError('NDOC obrigatório.')
        if not serie:
            raise ValueError('Série obrigatória.')
        if not descr:
            raise ValueError('Descrição obrigatória.')
        if estado not in FTS_ALLOWED_ESTADOS:
            raise ValueError('ESTADO inválido.')
        if tiposaft not in FTS_ALLOWED_TIPOSAFT:
            raise ValueError('TIPOSAFT inválido.')
        if _fts_tiposaft_requires_atcud(tiposaft) and ativa == 1 and no_saft != 1:
            try:
                codigo_validacao_at = qr_validate_validation_code(codigo_validacao_at)
            except ValueError:
                raise ValueError('Série não comunicada à AT ou sem código de validação.')
        return {
            'NDOC': ndoc,
            'SERIE': serie,
            'DESCR': descr,
            'ATIVA': ativa,
            'ESTADO': estado,
            'NO_SAFT': no_saft,
            'TIPOSAFT': tiposaft,
            'IS_DOC_TRANSPORTE': is_doc_transporte,
            'CODIGO_VALIDACAO_AT': codigo_validacao_at,
        }

    def _ftsx_payload_from_request(payload: dict, existing: dict | None = None):
        at_serie_estado = _fts_parse_int(payload.get('AT_SERIE_ESTADO'), 0)
        if at_serie_estado not in FTSX_ALLOWED_AT_ESTADOS:
            raise ValueError('AT_SERIE_ESTADO inválido.')
        existing = dict(existing or {})
        return {
            'COD_VALIDACAO_SERIE': str(payload.get('COD_VALIDACAO_SERIE') if 'COD_VALIDACAO_SERIE' in payload else existing.get('COD_VALIDACAO_SERIE') or '').strip(),
            'ATCUD_PREFIX': str(payload.get('ATCUD_PREFIX') if 'ATCUD_PREFIX' in payload else existing.get('ATCUD_PREFIX') or '').strip(),
            'AT_SERIE_ESTADO': at_serie_estado,
            'AT_SERIE_DATA': _fts_parse_datetime(payload.get('AT_SERIE_DATA')),
            'AT_SERIE_MSG': str(payload.get('AT_SERIE_MSG') or '').strip(),
        }

    @app.route('/api/fts', methods=['GET'])
    @login_required
    def api_fts_list():
        if not _fe_has_permission('consultar'):
            return jsonify({'error': 'Sem permissão para consultar séries.'}), 403
        current_entity, error_response = _current_fe_or_json_error()
        if error_response:
            return error_response

        serie = str(request.args.get('serie') or '').strip()
        tiposaft = str(request.args.get('tiposaft') or '').strip().upper()
        ativa = str(request.args.get('ativa') or '').strip().lower()
        has_ftsx = str(request.args.get('has_ftsx') or '').strip().lower()
        ano = _fts_parse_int(request.args.get('ano'), 0)
        ndoc = _fts_parse_int(request.args.get('ndoc'), 0)

        sql = f"""
            {_fts_base_query()}
            WHERE S.FESTAMP = :festamp
        """
        params = {'festamp': (current_entity.get('FESTAMP') or '').strip()}
        if serie:
            sql += " AND ISNULL(S.SERIE, '') LIKE :serie"
            params['serie'] = f"%{serie}%"
        if tiposaft == '__NONE__':
            sql += " AND LTRIM(RTRIM(ISNULL(S.TIPOSAFT, ''))) = ''"
        elif tiposaft:
            sql += " AND UPPER(LTRIM(RTRIM(ISNULL(S.TIPOSAFT, '')))) = :tiposaft"
            params['tiposaft'] = tiposaft
        if ativa in ('1', 'true', 'ativa', 'ativas'):
            sql += " AND ISNULL(S.ATIVA, 0) = 1"
        elif ativa in ('0', 'false', 'inativa', 'inativas'):
            sql += " AND ISNULL(S.ATIVA, 0) = 0"
        if has_ftsx in ('1', 'true', 'com'):
            sql += " AND X.FTSXSTAMP IS NOT NULL"
        elif has_ftsx in ('0', 'false', 'sem'):
            sql += " AND X.FTSXSTAMP IS NULL"
        if ano > 0:
            sql += " AND ISNULL(S.ANO, 0) = :ano"
            params['ano'] = ano
        if ndoc > 0:
            sql += " AND ISNULL(S.NDOC, 0) = :ndoc"
            params['ndoc'] = ndoc

        sql += " ORDER BY ISNULL(S.ANO, 0) DESC, ISNULL(S.NDOC, 0), ISNULL(S.SERIE, '')"
        rows = db.session.execute(text(sql), params).mappings().all()
        return jsonify({'rows': [_fts_serialize_row(row) for row in rows]})

