    @app.route('/api/lookups/fts', methods=['GET'])
    @login_required
    def api_lookup_fts():
        feid = _to_int(request.args.get('feid'), 0)
        festamp = (request.args.get('festamp') or '').strip()
        ano = _to_int(request.args.get('ano'), 0)
        if not feid and not festamp:
            return jsonify([])
        transport_select = ", ISNULL(S.IS_DOC_TRANSPORTE, 0) AS IS_DOC_TRANSPORTE" if _fts_transport_flag_available() else ", CAST(0 AS bit) AS IS_DOC_TRANSPORTE"
        sql = """
            SELECT
                S.FTSSTAMP,
                S.FESTAMP,
                ISNULL(S.FEID, 0) AS FEID,
                S.NDOC,
                LTRIM(RTRIM(ISNULL(S.DESCR, ''))) AS NMDOC,
                S.SERIE,
                LTRIM(RTRIM(ISNULL(S.DESCR, ''))) AS DESCR,
                S.ANO,
                S.ESTADO,
                S.ULTIMO_FNO,
                ISNULL(S.NO_SAFT, 0) AS NO_SAFT,
                UPPER(LTRIM(RTRIM(ISNULL(S.TIPOSAFT, '')))) AS TIPOSAFT
                """ + transport_select + """
            FROM dbo.FTS S
            WHERE
                ISNULL(S.ATIVA, 0) = 1
                AND (:ano = 0 OR S.ANO = :ano)
        """
        params = {'feid': feid, 'festamp': festamp, 'ano': ano}
        if feid:
            sql += " AND ISNULL(S.FEID, 0) = :feid"
        else:
            sql += " AND S.FESTAMP = :festamp"
        sql += " ORDER BY S.NDOC, S.SERIE"
        rows = db.session.execute(text(sql), params).mappings().all()
        return jsonify([dict(r) for r in rows])

    @app.route('/api/faturacao/ft/list', methods=['GET'])
    @login_required
    def api_faturacao_ft_list():
        ano = _to_int(request.args.get('ano'), 0)
        mes = _to_int(request.args.get('mes'), 0)
        q = (request.args.get('q') or '').strip()
        sql = """
            SELECT TOP 300
                FTSTAMP, NDOC, NMDOC, FNO, SERIE, FDATA, PDATA, NO, NOME, ETTILIQ, ETTIVA, ETOTAL, ESTADO, ANULADA
            FROM dbo.FT
            WHERE 1=1
        """
        params = {}
        if ano > 0:
            sql += " AND YEAR(FDATA) = :ano"
            params['ano'] = ano
        if 1 <= mes <= 12:
            sql += " AND MONTH(FDATA) = :mes"
            params['mes'] = mes
        if q:
            sql += " AND (ISNULL(NOME,'') LIKE :q OR ISNULL(NMDOC,'') LIKE :q OR ISNULL(SERIE,'') LIKE :q OR CONVERT(varchar(20), ISNULL(FNO,0)) LIKE :q)"
            params['q'] = f"%{q}%"
        sql += " ORDER BY ISNULL(FDATA,'19000101') DESC, ISNULL(FNO,0) DESC"
        rows = db.session.execute(text(sql), params).mappings().all()
        return jsonify([dict(r) for r in rows])

