    @app.route('/api/faturacao/ft/<ftstamp>/cancelar', methods=['POST'])
    @login_required
    def api_faturacao_ft_cancelar(ftstamp):
        current_entity, error_response = _current_fe_or_json_error()
        if error_response:
            return error_response
        row = db.session.execute(text("""
            SELECT ISNULL(ESTADO,0) AS ESTADO
            FROM dbo.FT
            WHERE FTSTAMP=:s
        """ + _ft_entity_scope_sql('FT')), {
            's': ftstamp,
            'current_feid': int(current_entity.get('FEID') or 0),
            'current_festamp': (current_entity.get('FESTAMP') or '').strip(),
        }).mappings().first()
        if not row:
            return jsonify({'error': 'Documento não encontrado'}), 404
        if int(row.get('ESTADO') or 0) != 0:
            return jsonify({'ok': True, 'deleted': False, 'message': 'Documento não é rascunho.'})

        db.session.execute(text("DELETE FROM dbo.FI WHERE FTSTAMP=:s"), {'s': ftstamp})
        db.session.execute(text("""
            DELETE FROM dbo.FT
            WHERE FTSTAMP=:s
        """ + _ft_entity_scope_sql('FT')), {
            's': ftstamp,
            'current_feid': int(current_entity.get('FEID') or 0),
            'current_festamp': (current_entity.get('FESTAMP') or '').strip(),
        })
        db.session.commit()
        return jsonify({'ok': True, 'deleted': True})

    @app.route('/')
    @login_required
    def home_page():
        home = getattr(current_user, 'HOME', '').lower().strip().lstrip('/')
        print(f"HOME do utilizador: {home}")

        # Se o utilizador regista tempos e tiver tarefas LP hoje, entre 08:00 e 20:00,
        # abre o ecrã de tempos em vez do monitor.
        try:
            tempos_enabled = int(getattr(current_user, 'TEMPOS', 0) or 0) == 1
        except Exception:
            tempos_enabled = False
        try:
            now_t = datetime.now().time()
            in_window = (dtime(8, 0) <= now_t <= dtime(20, 0))
        except Exception:
            in_window = False

        if tempos_enabled and in_window and (home == 'monitor' or not home):
            try:
                user_login = (getattr(current_user, 'LOGIN', '') or '').strip()
                if user_login:
                    has_lp_today = db.session.execute(text("""
                        SELECT TOP 1 1 AS X
                        FROM dbo.TAREFAS
                        WHERE LTRIM(RTRIM(ISNULL(ORIGEM,''))) = 'LP'
                          AND CAST(DATA AS date) = CAST(GETDATE() AS date)
                          AND ISNULL(UTILIZADOR,'') = :u
                          AND LTRIM(RTRIM(ISNULL(HORAFIM,''))) = ''
                    """), {'u': user_login}).fetchone()
                    if has_lp_today:
                        return redirect(url_for('tempos_limpeza_page'))
            except Exception:
                pass

        if home == 'dashboard':
            return redirect(url_for('dashboard_page'))
        elif home == 'monitor' or not home:
            return redirect(url_for('monitor_page'))

        return redirect(url_for('dashboard_page'))


