    @app.route('/api/mapa_gestao/adr_diario')
    @login_required
    def api_mapa_gestao_adr_diario():
        from datetime import timedelta

        try:
            ano = request.args.get('ano', type=int) or date.today().year
        except Exception:
            ano = date.today().year
        try:
            mes = request.args.get('mes', type=int) or date.today().month
        except Exception:
            mes = date.today().month
        if mes < 1 or mes > 12:
            return jsonify({'error': 'mes invalido'}), 400

        ccustos_raw = (request.args.get('ccustos') or '').strip()
        ccustos = [c.strip() for c in ccustos_raw.split(',') if c.strip()]

        try:
            start = date(ano, mes, 1)
            end = (date(ano + 1, 1, 1) if mes == 12 else date(ano, mes + 1, 1))
        except Exception:
            return jsonify({'error': 'ano/mes invalidos'}), 400

        where_parts = [
            "ISNULL(RS.CANCELADA,0) = 0",
            "ISNULL(RS.NOITES,0) > 0",
            "RS.DATAIN IS NOT NULL",
            # excluir reservas do proprietario (valor medio/noite = 0)
            "ABS(((ISNULL(RS.ESTADIA,0) + ISNULL(RS.LIMPEZA,0)) - ISNULL(RS.COMISSAO,0))) > 0.005",
        ]
        params = {'start': start, 'end': end}
        if ccustos:
            keys = []
            for idx, cc in enumerate(ccustos):
                k = f"cc{idx}"
                params[k] = cc
                keys.append(f":{k}")
            where_parts.append(
                "LTRIM(RTRIM(ISNULL(a.CCUSTO,''))) COLLATE SQL_Latin1_General_CP1_CI_AI IN ("
                + ",".join(keys)
                + ")"
            )

        sql = f"""
            WITH nums AS (
                SELECT TOP (60) ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) - 1 AS n
                FROM sys.all_objects
            ),
            exp AS (
                SELECT
                    CAST(DATEADD(day, nums.n, CAST(RS.DATAIN AS date)) AS date) AS DIA,
                    (
                        (ISNULL(RS.ESTADIA,0) + ISNULL(RS.LIMPEZA,0)) - ISNULL(RS.COMISSAO,0)
                    ) / NULLIF(CAST(ISNULL(RS.NOITES,0) AS float), 0) AS PER_NOITE
                FROM RS
                LEFT JOIN AL a
                  ON LTRIM(RTRIM(a.NOME)) COLLATE SQL_Latin1_General_CP1_CI_AI
                   = LTRIM(RTRIM(ISNULL(RS.ALOJAMENTO,''))) COLLATE SQL_Latin1_General_CP1_CI_AI
                INNER JOIN nums
                  ON nums.n < ISNULL(RS.NOITES,0)
                WHERE {" AND ".join(where_parts)}
            )
            SELECT
                DIA,
                AVG(PER_NOITE) AS ADR,
                COUNT(1) AS NOITES,
                SUM(PER_NOITE) AS NET
            FROM exp
            WHERE DIA >= :start AND DIA < :end
            GROUP BY DIA
            ORDER BY DIA
        """

        try:
            rows = db.session.execute(text(sql), params).mappings().all()
        except Exception as e:
            return jsonify({'error': f'Erro ao obter ADR diario: {e}'}), 500

        adr_by_day = {}
        net_by_day = {}
        nights_by_day = {}
        total_net = 0.0
        total_nights = 0
        for r in rows:
            d = r.get('DIA')
            adr = float(r.get('ADR') or 0)
            nights = int(r.get('NOITES') or 0)
            net = float(r.get('NET') or 0)
            try:
                day_num = int(d.day)
            except Exception:
                continue
            adr_by_day[day_num] = adr
            net_by_day[day_num] = net
            nights_by_day[day_num] = nights
            total_net += net
            total_nights += nights

        last_day = (end - timedelta(days=1)).day
        labels = list(range(1, last_day + 1))
        values = []
        noites_arr = []
        net_arr = []
        for i in labels:
            k = int(nights_by_day.get(i, 0))
            n = float(net_by_day.get(i, 0.0))
            a = adr_by_day.get(i)
            values.append(None if a is None or k <= 0 else round(float(a), 2))
            noites_arr.append(k)
            net_arr.append(round(float(n), 2))

        adr_total = (round(total_net / float(total_nights), 2) if total_nights else None)
        return jsonify({
            'ano': ano,
            'mes': mes,
            'labels': labels,
            'values': values,
            'noites_by_day': noites_arr,
            'net_by_day': net_arr,
            'noites': int(total_nights or 0),
            'net': round(float(total_net or 0), 2),
            'adr': adr_total
        })

    @app.route('/api/mapa_gestao/vendas_alojamentos')
    @login_required
    def api_mapa_gestao_vendas_alojamentos():
        try:
            ano = request.args.get('ano', type=int) or date.today().year
        except Exception:
            ano = date.today().year
        try:
            mes = request.args.get('mes', type=int) or date.today().month
        except Exception:
            mes = date.today().month
        if mes < 1 or mes > 12:
            return jsonify({'error': 'mes invalido'}), 400

        ccustos_raw = (request.args.get('ccustos') or '').strip()
        ccustos = [c.strip() for c in ccustos_raw.split(',') if c.strip()]

        where_parts = [
            "ISNULL(a.INATIVO,0) = 0",
            "UPPER(LTRIM(RTRIM(ISNULL(a.TIPO,'')))) = 'EXPLORACAO'",
        ]
        params = {'ano': ano, 'mes': mes}
        if ccustos:
            keys = []
            for idx, cc in enumerate(ccustos):
                k = f"cc{idx}"
                params[k] = cc
                keys.append(f":{k}")
            where_parts.append(
                "LTRIM(RTRIM(ISNULL(a.CCUSTO,''))) COLLATE SQL_Latin1_General_CP1_CI_AI IN ("
                + ",".join(keys)
                + ")"
            )

        sql = f"""
            WITH vc AS (
                SELECT
                    LTRIM(RTRIM(CCUSTO)) AS CCUSTO,
                    SUM(ISNULL(TOTAL,0)) AS REAL
                FROM v_custo
                WHERE YEAR(DATA) = :ano
                  AND MONTH(DATA) = :mes
                  AND FAMILIA LIKE '9%'
                GROUP BY LTRIM(RTRIM(CCUSTO))
            ),
            ovm AS (
                SELECT
                    LTRIM(RTRIM(CCUSTO)) AS CCUSTO,
                    SUM(
                        CASE :mes
                          WHEN 1 THEN ISNULL(JANEIRO,0)
                          WHEN 2 THEN ISNULL(FEVEREIRO,0)
                          WHEN 3 THEN ISNULL(MARCO,0)
                          WHEN 4 THEN ISNULL(ABRIL,0)
                          WHEN 5 THEN ISNULL(MAIO,0)
                          WHEN 6 THEN ISNULL(JUNHO,0)
                          WHEN 7 THEN ISNULL(JULHO,0)
                          WHEN 8 THEN ISNULL(AGOSTO,0)
                          WHEN 9 THEN ISNULL(SETEMBRO,0)
                          WHEN 10 THEN ISNULL(OUTUBRO,0)
                          WHEN 11 THEN ISNULL(NOVEMBRO,0)
                          WHEN 12 THEN ISNULL(DEZEMBRO,0)
                          ELSE 0
                        END
                    ) AS OBJETIVO
                FROM OV
                WHERE ANO = :ano
                GROUP BY LTRIM(RTRIM(CCUSTO))
            )
            SELECT
                LTRIM(RTRIM(ISNULL(a.NOME,''))) AS ALOJAMENTO,
                LTRIM(RTRIM(ISNULL(a.CCUSTO,''))) AS CCUSTO,
                ISNULL(vc.REAL,0) AS REAL,
                ISNULL(ovm.OBJETIVO,0) AS OBJETIVO
            FROM AL a
            LEFT JOIN vc
              ON LTRIM(RTRIM(vc.CCUSTO)) COLLATE SQL_Latin1_General_CP1_CI_AI
               = LTRIM(RTRIM(a.CCUSTO)) COLLATE SQL_Latin1_General_CP1_CI_AI
            LEFT JOIN ovm
              ON LTRIM(RTRIM(ovm.CCUSTO)) COLLATE SQL_Latin1_General_CP1_CI_AI
               = LTRIM(RTRIM(a.CCUSTO)) COLLATE SQL_Latin1_General_CP1_CI_AI
            WHERE {" AND ".join(where_parts)}
            ORDER BY LTRIM(RTRIM(ISNULL(a.NOME,'')))
        """

        try:
            rows = db.session.execute(text(sql), params).mappings().all()
        except Exception as e:
            return jsonify({'error': f'Erro ao obter vendas por alojamento: {e}'}), 500

        out = []
        total_real = 0.0
        total_obj = 0.0
        for r in rows:
            aloj = str(r.get('ALOJAMENTO') or '').strip()
            cc = str(r.get('CCUSTO') or '').strip()
            real = float(r.get('REAL') or 0)
            obj = float(r.get('OBJETIVO') or 0)
            total_real += real
            total_obj += obj
            out.append({
                'alojamento': aloj,
                'ccusto': cc,
                'real': round(real, 2),
                'objetivo': round(obj, 2),
            })

        return jsonify({
            'ano': ano,
            'mes': mes,
            'rows': out,
            'total_real': round(total_real, 2),
            'total_objetivo': round(total_obj, 2),
        })

    @app.route('/api/mapa_gestao/margem_alojamentos')
    @login_required
    def api_mapa_gestao_margem_alojamentos():
        try:
            ano = request.args.get('ano', type=int) or date.today().year
        except Exception:
            ano = date.today().year
        try:
            mes = request.args.get('mes', type=int) or date.today().month
        except Exception:
            mes = date.today().month
        if mes < 1 or mes > 12:
            return jsonify({'error': 'mes invalido'}), 400

        ccustos_raw = (request.args.get('ccustos') or '').strip()
        ccustos = [c.strip() for c in ccustos_raw.split(',') if c.strip()]

        where_parts = [
            "ISNULL(a.INATIVO,0) = 0",
            "UPPER(LTRIM(RTRIM(ISNULL(a.TIPO,'')))) = 'EXPLORACAO'",
        ]
        params = {'ano': ano, 'mes': mes}
        if ccustos:
            keys = []
            for idx, cc in enumerate(ccustos):
                k = f"cc{idx}"
                params[k] = cc
                keys.append(f":{k}")
            where_parts.append(
                "LTRIM(RTRIM(ISNULL(a.CCUSTO,''))) COLLATE SQL_Latin1_General_CP1_CI_AI IN ("
                + ",".join(keys)
                + ")"
            )

        sql = f"""
            WITH sales AS (
                SELECT
                    LTRIM(RTRIM(CCUSTO)) AS CCUSTO,
                    SUM(ISNULL(TOTAL,0)) AS VENDAS
                FROM v_custo
                WHERE YEAR(DATA) = :ano
                  AND MONTH(DATA) = :mes
                  AND FAMILIA LIKE '9%'
                GROUP BY LTRIM(RTRIM(CCUSTO))
            ),
            costs AS (
                SELECT
                    LTRIM(RTRIM(CCUSTO)) AS CCUSTO,
                    SUM(ISNULL(TOTAL,0)) AS CUSTOS
                FROM v_custo
                WHERE YEAR(DATA) = :ano
                  AND MONTH(DATA) = :mes
                  AND (FAMILIA NOT LIKE '9%')
                GROUP BY LTRIM(RTRIM(CCUSTO))
            )
            SELECT
                LTRIM(RTRIM(ISNULL(a.NOME,''))) AS ALOJAMENTO,
                LTRIM(RTRIM(ISNULL(a.CCUSTO,''))) AS CCUSTO,
                ISNULL(sales.VENDAS,0) AS VENDAS,
                ISNULL(costs.CUSTOS,0) AS CUSTOS,
                ISNULL(sales.VENDAS,0) - ISNULL(costs.CUSTOS,0) AS MARGEM
            FROM AL a
            LEFT JOIN sales
              ON LTRIM(RTRIM(sales.CCUSTO)) COLLATE SQL_Latin1_General_CP1_CI_AI
               = LTRIM(RTRIM(a.CCUSTO)) COLLATE SQL_Latin1_General_CP1_CI_AI
            LEFT JOIN costs
              ON LTRIM(RTRIM(costs.CCUSTO)) COLLATE SQL_Latin1_General_CP1_CI_AI
               = LTRIM(RTRIM(a.CCUSTO)) COLLATE SQL_Latin1_General_CP1_CI_AI
            WHERE {" AND ".join(where_parts)}
            ORDER BY LTRIM(RTRIM(ISNULL(a.NOME,'')))
        """

        try:
            rows = db.session.execute(text(sql), params).mappings().all()
        except Exception as e:
            return jsonify({'error': f'Erro ao obter margem por alojamento: {e}'}), 500

        out = []
        total_sales = 0.0
        total_costs = 0.0
        total_margin = 0.0
        for r in rows:
            aloj = str(r.get('ALOJAMENTO') or '').strip()
            cc = str(r.get('CCUSTO') or '').strip()
            vendas = float(r.get('VENDAS') or 0)
            custos = float(r.get('CUSTOS') or 0)
            margem = float(r.get('MARGEM') or 0)
            total_sales += vendas
            total_costs += custos
            total_margin += margem
            out.append({
                'alojamento': aloj,
                'ccusto': cc,
                'vendas': round(vendas, 2),
                'custos': round(custos, 2),
                'margem': round(margem, 2),
            })

        return jsonify({
            'ano': ano,
            'mes': mes,
            'rows': out,
            'total_vendas': round(total_sales, 2),
            'total_custos': round(total_costs, 2),
            'total_margem': round(total_margin, 2),
        })

    @app.route('/api/mapa_gestao/reservas_paises')
    @login_required
    def api_mapa_gestao_reservas_paises():
        from datetime import timedelta

        try:
            ano = request.args.get('ano', type=int) or date.today().year
        except Exception:
            ano = date.today().year

        ccustos_raw = (request.args.get('ccustos') or '').strip()
        ccustos = [c.strip() for c in ccustos_raw.split(',') if c.strip()]

        try:
            start = date(ano, 1, 1)
            end = date(ano + 1, 1, 1)
        except Exception:
            return jsonify({'error': 'ano invalido'}), 400

        where_parts = [
            "RS.DATAIN >= :start",
            "RS.DATAIN < :end",
            "ISNULL(RS.NOITES,0) > 0",
            "ISNULL(RS.CANCELADA,0) = 0",
        ]
        params = {'start': start, 'end': end}
        if ccustos:
            keys = []
            for idx, cc in enumerate(ccustos):
                k = f"cc{idx}"
                params[k] = cc
                keys.append(f":{k}")
            where_parts.append(
                "LTRIM(RTRIM(ISNULL(a.CCUSTO,''))) COLLATE SQL_Latin1_General_CP1_CI_AI IN ("
                + ",".join(keys)
                + ")"
            )

        sql = f"""
            SELECT
                LTRIM(RTRIM(ISNULL(RS.PAIS,''))) AS PAIS,
                COUNT(1) AS RESERVAS,
                SUM(ISNULL(RS.NOITES,0)) AS NOITES,
                SUM(ISNULL(RS.ADULTOS,0) + ISNULL(RS.CRIANCAS,0)) AS HOSPEDES,
                AVG(CAST(ISNULL(RS.NOITES,0) AS float)) AS MEDIA_NOITES,
                AVG(CAST((ISNULL(RS.ADULTOS,0) + ISNULL(RS.CRIANCAS,0)) AS float)) AS MEDIA_HOSPEDES,
                AVG(CAST(DATEDIFF(day, CAST(ISNULL(RS.RDATA, RS.DATAIN) AS date), CAST(RS.DATAIN AS date)) AS float)) AS MEDIA_ANTECIP,
                SUM(
                    CASE
                        WHEN UPPER(LTRIM(RTRIM(ISNULL(a.TIPO,'')))) = 'GESTAO' THEN
                            CASE WHEN ISNULL(a.FTLIMPEZA,0) = 0 THEN
                                (CASE WHEN ISNULL(RS.CANCELADA,0) = 1 THEN ISNULL(RS.PCANCEL,0)
                                      ELSE ROUND(ISNULL(RS.ESTADIA,0)/1.06,2) + ROUND(ISNULL(RS.LIMPEZA,0)/1.23,2) - ISNULL(RS.COMISSAO,0)
                                 END) * (ISNULL(a.COMISSAO,0) / 100.0)
                            ELSE
                                (CASE WHEN ISNULL(RS.CANCELADA,0) = 1 THEN ISNULL(RS.PCANCEL,0)
                                      ELSE ROUND(ISNULL(RS.ESTADIA,0)/1.06,2) - ISNULL(RS.COMISSAO,0)
                                 END) * (ISNULL(a.COMISSAO,0) / 100.0)
                                + ROUND(ISNULL(RS.LIMPEZA,0)/1.23,2)
                            END
                        ELSE
                            CASE WHEN ISNULL(RS.CANCELADA,0) = 1 THEN ISNULL(RS.PCANCEL,0)
                                 ELSE ROUND(ISNULL(RS.ESTADIA,0)/1.06,2) + ROUND(ISNULL(RS.LIMPEZA,0)/1.23,2) - ISNULL(RS.COMISSAO,0)
                            END
                    END
                ) AS VALOR
            FROM RS
            LEFT JOIN AL a
              ON LTRIM(RTRIM(a.NOME)) COLLATE SQL_Latin1_General_CP1_CI_AI
               = LTRIM(RTRIM(ISNULL(RS.ALOJAMENTO,''))) COLLATE SQL_Latin1_General_CP1_CI_AI
            WHERE {" AND ".join(where_parts)}
            GROUP BY LTRIM(RTRIM(ISNULL(RS.PAIS,'')))
            ORDER BY SUM(
                CASE
                    WHEN UPPER(LTRIM(RTRIM(ISNULL(a.TIPO,'')))) = 'GESTAO' THEN
                        CASE WHEN ISNULL(a.FTLIMPEZA,0) = 0 THEN
                            (CASE WHEN ISNULL(RS.CANCELADA,0) = 1 THEN ISNULL(RS.PCANCEL,0)
                                  ELSE ROUND(ISNULL(RS.ESTADIA,0)/1.06,2) + ROUND(ISNULL(RS.LIMPEZA,0)/1.23,2) - ISNULL(RS.COMISSAO,0)
                             END) * (ISNULL(a.COMISSAO,0) / 100.0)
                        ELSE
                            (CASE WHEN ISNULL(RS.CANCELADA,0) = 1 THEN ISNULL(RS.PCANCEL,0)
                                  ELSE ROUND(ISNULL(RS.ESTADIA,0)/1.06,2) - ISNULL(RS.COMISSAO,0)
                             END) * (ISNULL(a.COMISSAO,0) / 100.0)
                            + ROUND(ISNULL(RS.LIMPEZA,0)/1.23,2)
                        END
                    ELSE
                        CASE WHEN ISNULL(RS.CANCELADA,0) = 1 THEN ISNULL(RS.PCANCEL,0)
                             ELSE ROUND(ISNULL(RS.ESTADIA,0)/1.06,2) + ROUND(ISNULL(RS.LIMPEZA,0)/1.23,2) - ISNULL(RS.COMISSAO,0)
                        END
                END
            ) DESC, LTRIM(RTRIM(ISNULL(RS.PAIS,'')))
        """

        try:
            rows = db.session.execute(text(sql), params).mappings().all()
        except Exception as e:
            return jsonify({'error': f'Erro ao obter reservas por pais: {e}'}), 500

        out = []
        total_valor = 0.0
        total_res = 0
        for r in rows:
            pais = str(r.get('PAIS') or '').strip()
            valor = float(r.get('VALOR') or 0)
            noites = int(r.get('NOITES') or 0)
            reservas = int(r.get('RESERVAS') or 0)
            total_valor += valor
            total_res += reservas
            out.append({
                'pais': pais,
                'reservas': reservas,
                'valor': round(valor, 2),
                'media_noites': round(float(r.get('MEDIA_NOITES') or 0), 2),
                'media_noite': (None if noites <= 0 else round(valor / float(noites), 2)),
                'media_hospedes': round(float(r.get('MEDIA_HOSPEDES') or 0), 2),
                'media_antecip': round(float(r.get('MEDIA_ANTECIP') or 0), 1),
            })

        return jsonify({
            'ano': ano,
            'total_valor': round(total_valor, 2),
            'total_reservas': total_res,
            'rows': out
        })

    @app.route('/turnover')
    @login_required
    def turnover_page():
        return render_template('turnover.html', page_title='Turnover Diário', today=date.today().isoformat())

    @app.route('/api/turnover')
    @login_required
    def api_turnover():
        try:
            data_str = (request.args.get('data') or '').strip()
            dia = datetime.strptime(data_str, '%Y-%m-%d').date() if data_str else date.today()
            dia_iso = dia.isoformat()

            reservas_out = db.session.execute(text("""
                SELECT LTRIM(RTRIM(ALOJAMENTO)) AS ALOJAMENTO, ISNULL(HORAOUT,'') AS HORAOUT, NOITES,
                       ISNULL(ADULTOS,0) AS ADULTOS, ISNULL(CRIANCAS,0) AS CRIANCAS,
                       ISNULL(BERCO,0) AS BERCO, ISNULL(SOFACAMA,0) AS SOFACAMA
                FROM RS
                WHERE CAST(DATAOUT AS date) = :dia
                  AND ISNULL(CANCELADA,0) = 0
            """), {'dia': dia_iso}).mappings().all()

            reservas_in = db.session.execute(text("""
                SELECT LTRIM(RTRIM(RS.ALOJAMENTO)) AS ALOJAMENTO, ISNULL(RS.HORAIN,'') AS HORAIN, RS.NOITES,
                       ISNULL(RS.ADULTOS,0) AS ADULTOS, ISNULL(RS.CRIANCAS,0) AS CRIANCAS,
                       ISNULL(RS.BERCO,0) AS BERCO, ISNULL(RS.SOFACAMA,0) AS SOFACAMA,
                       ISNULL(RS.SEF,0) AS SEF, ISNULL(RS.USRSEF,'') AS USRSEF,
                       ISNULL(RS.INSTR,0) AS INSTR, ISNULL(RS.USRINSTR,'') AS USRINSTR,
                       ISNULL(RS.PRESENCIAL,0) AS PRESENCIAL,
                       ISNULL(RS.ENTROU,0) AS ENTROU,
                       ISNULL(RS.USRCHECKIN,'') AS USRCHECKIN,
                       ISNULL(uc.NOME, RS.USRCHECKIN) AS USRCHECKIN_NOME
                FROM RS
                LEFT JOIN US uc ON uc.LOGIN = RS.USRCHECKIN
                WHERE CAST(RS.DATAIN AS date) = :dia
                  AND ISNULL(RS.CANCELADA,0) = 0
            """), {'dia': dia_iso}).mappings().all()

            tarefas = db.session.execute(text("""
                SELECT LTRIM(RTRIM(t.ALOJAMENTO)) AS ALOJAMENTO,
                       t.UTILIZADOR,
                       ISNULL(t.TRATADO,0) AS TRATADO,
                       ISNULL(t.TAREFA,'') AS OBS,
                       ISNULL(u.NOME, t.UTILIZADOR) AS NOME,
                       ISNULL(t.HORA,'') AS HORA,
                       ISNULL(al.TIPOLOGIA,'') AS TIPOLOGIA
                FROM TAREFAS t
                LEFT JOIN US u ON u.LOGIN = t.UTILIZADOR
                LEFT JOIN AL al ON LTRIM(RTRIM(al.NOME)) = LTRIM(RTRIM(t.ALOJAMENTO))
                WHERE LTRIM(RTRIM(ISNULL(t.ORIGEM,''))) = 'LP'
                  AND CAST(t.DATA AS date) = :dia
            """), {'dia': dia_iso}).mappings().all()

            ultimas_limpezas = db.session.execute(text("""
                WITH cte AS (
                    SELECT LTRIM(RTRIM(t.ALOJAMENTO)) AS ALOJAMENTO,
                           CAST(t.DATA AS date) AS DIA,
                           ISNULL(t.HORA,'') AS HORA,
                           ISNULL(u.NOME, t.UTILIZADOR) AS NOME,
                           ROW_NUMBER() OVER (
                               PARTITION BY LTRIM(RTRIM(t.ALOJAMENTO))
                               ORDER BY CAST(t.DATA AS date) DESC, ISNULL(t.HORA,'') DESC
                           ) AS rn
                    FROM TAREFAS t
                    LEFT JOIN US u ON u.LOGIN = t.UTILIZADOR
                    WHERE LTRIM(RTRIM(ISNULL(t.ORIGEM,''))) = 'LP'
                      AND ISNULL(t.TRATADO,0) = 1
                      AND CAST(t.DATA AS date) <= :dia
                )
                SELECT ALOJAMENTO, DIA, HORA, NOME FROM cte WHERE rn = 1
            """), {'dia': dia_iso}).mappings().all()

            def norm_aloj(v: str) -> str:
                try:
                    return (v or '').strip().upper()
                except Exception:
                    return ''

            map_out, map_in, map_tasks, map_last = {}, {}, {}, {}
            for r in reservas_out:
                aloj = norm_aloj(r.get('ALOJAMENTO'))
                if aloj:
                    map_out.setdefault(aloj, []).append(r)
            for r in reservas_in:
                aloj = norm_aloj(r.get('ALOJAMENTO'))
                if aloj:
                    map_in.setdefault(aloj, []).append(r)
            for r in tarefas:
                aloj = norm_aloj(r.get('ALOJAMENTO'))
                if aloj:
                    map_tasks.setdefault(aloj, []).append(r)
            for r in ultimas_limpezas:
                aloj = norm_aloj(r.get('ALOJAMENTO'))
                if aloj and aloj not in map_last:
                    map_last[aloj] = r

            now_dt = datetime.now()
            all_aloj = set(map_out.keys()) | set(map_in.keys()) | set(map_tasks.keys())

            # Helpers to cache last checkout and next checkin dates
            cache_last_out = {}
            cache_next_in = {}
            cache_future_clean = {}

            def get_last_out(aloj):
                if aloj in cache_last_out:
                    return cache_last_out[aloj]
                try:
                    row = db.session.execute(text("""
                        SELECT TOP 1 CAST(DATAOUT AS date) AS DIA
                        FROM RS
                        WHERE CAST(DATAOUT AS date) < :dia
                          AND LTRIM(RTRIM(ALOJAMENTO)) = LTRIM(RTRIM(:aloj))
                          AND ISNULL(CANCELADA,0) = 0
                        ORDER BY DATAOUT DESC
                    """), {'dia': dia_iso, 'aloj': aloj}).first()
                    cache_last_out[aloj] = row[0] if row else None
                except Exception:
                    cache_last_out[aloj] = None
                return cache_last_out[aloj]

            def get_next_in(aloj):
                if aloj in cache_next_in:
                    return cache_next_in[aloj]
                try:
                    row = db.session.execute(text("""
                        SELECT TOP 1 CAST(DATAIN AS date) AS DIA
                        FROM RS
                        WHERE CAST(DATAIN AS date) > :dia
                          AND LTRIM(RTRIM(ALOJAMENTO)) = LTRIM(RTRIM(:aloj))
                          AND ISNULL(CANCELADA,0) = 0
                        ORDER BY DATAIN ASC
                    """), {'dia': dia_iso, 'aloj': aloj}).first()
                    cache_next_in[aloj] = row[0] if row else None
                except Exception:
                    cache_next_in[aloj] = None
                return cache_next_in[aloj]

            def get_future_clean(aloj, limite):
                if aloj in cache_future_clean:
                    return cache_future_clean[aloj]
                try:
                    params = {'dia': dia_iso, 'aloj': aloj}
                    sql = """
                        SELECT TOP 1 CAST(t.DATA AS date) AS DIA,
                               ISNULL(u.NOME, t.UTILIZADOR) AS NOME
                        FROM TAREFAS t
                        LEFT JOIN US u ON u.LOGIN = t.UTILIZADOR
                        WHERE LTRIM(RTRIM(t.ALOJAMENTO)) = LTRIM(RTRIM(:aloj))
                          AND LTRIM(RTRIM(ISNULL(t.ORIGEM,''))) = 'LP'
                          AND CAST(t.DATA AS date) > :dia
                          AND ISNULL(t.TRATADO,0) = 0
                    """
                    if limite:
                        sql += " AND CAST(t.DATA AS date) <= :limite"
                        params['limite'] = limite
                    sql += " ORDER BY t.DATA ASC"
                    row = db.session.execute(text(sql), params).first()
                    if row:
                        cache_future_clean[aloj] = {'dia': row[0], 'nome': row[1]}
                    else:
                        cache_future_clean[aloj] = None
                except Exception:
                    cache_future_clean[aloj] = None
                return cache_future_clean[aloj]

            dow_pt = ['SEG', 'TER', 'QUA', 'QUI', 'SEX', 'SAB', 'DOM']

            def fmt_date_parts(dval):
                try:
                    if isinstance(dval, datetime):
                        d = dval.date()
                    else:
                        d = dval
                    dow = dow_pt[d.weekday()]
                    dat = d.strftime('%d/%m')
                    return {'dow': dow, 'date': dat}
                except Exception:
                    return None

            cards = []
            for aloj in sorted(all_aloj):
                out_list = map_out.get(aloj, [])
                in_list = map_in.get(aloj, [])
                task_list = map_tasks.get(aloj, [])

                aloj_display = ''
                for src in (out_list, in_list, task_list):
                    if src:
                        aloj_display = src[0].get('ALOJAMENTO') or ''
                        break

                def first_val(lst, key):
                    try:
                        return lst[0].get(key) if lst else ''
                    except Exception:
                        return ''

                chk_out = first_val(out_list, 'HORAOUT') or ''
                chk_in = first_val(in_list, 'HORAIN') or ''
                noites = first_val(in_list, 'NOITES') or 0
                try:
                    hospedes = int(first_val(in_list, 'ADULTOS') or 0) + int(first_val(in_list, 'CRIANÇAS') or first_val(in_list, 'CRIANCAS') or 0)
                except Exception:
                    hospedes = 0
                berco = bool(first_val(in_list, 'BERCO'))
                sof = bool(first_val(in_list, 'SOFACAMA'))

                status = 'Já limpo'
                tem_planeada = False
                tem_concluida = False
                if task_list:
                    tem_planeada = any(int(t.get('TRATADO') or 0) == 0 for t in task_list)
                    tem_concluida = any(int(t.get('TRATADO') or 0) == 1 for t in task_list)
                    if tem_planeada:
                        status = 'Planeada'
                    elif tem_concluida:
                        status = 'Concluída'
                equipa = first_val(task_list, 'NOME') or ''
                hora_lp = first_val(task_list, 'HORA') or ''
                tipologia = (first_val(task_list, 'TIPOLOGIA') or '').strip().upper()
                dur_map = {'T0': 60, 'T1': 60, 'T2': 90, 'T3': 120, 'T4': 150}
                dur_min = dur_map.get(tipologia)
                hora_fim = ''
                try:
                    if hora_lp and dur_min:
                        s = str(hora_lp).strip()
                        hh = mm = 0
                        if ':' in s:
                            parts = s.split(':')
                            hh = int(parts[0])
                            mm = int(parts[1] if len(parts) > 1 else 0)
                        else:
                            digits = ''.join(ch for ch in s if ch.isdigit())
                            if len(digits) >= 3:
                                mm = int(digits[-2:])
                                hh = int(digits[:-2])
                            elif digits:
                                hh = int(digits)
                        total = hh * 60 + mm + dur_min
                        hora_fim = f"{(total // 60) % 24:02d}:{total % 60:02d}"
                except Exception:
                    hora_fim = ''
                atrasada = False
                if tem_planeada and not tem_concluida:
                    if dia < now_dt.date():
                        atrasada = True
                    elif dia == now_dt.date():
                        try:
                            if hora_fim:
                                h_end = datetime.strptime(hora_fim, '%H:%M').time()
                                if now_dt.time() > h_end:
                                    atrasada = True
                        except Exception:
                            pass
                if atrasada:
                    status = 'Atrasada'
                if out_list and not task_list:
                    status = 'Por atribuir'
                last_info = False
                if not task_list:
                    last = map_last.get(aloj)
                    if last:
                        try:
                            dia_last = last.get('DIA')
                            dia_str = ''
                            if dia_last:
                                try:
                                    dia_str = dia_last.strftime('%d/%m/%Y')
                                except Exception:
                                    dia_str = str(dia_last)[:10]
                            nome_last = last.get('NOME') or ''
                            if nome_last or dia_str:
                                equipa = f"{nome_last} ({dia_str})".strip()
                            last_info = True
                        except Exception:
                            pass
                extras_obs = []
                if berco:
                    extras_obs.append('Berço')
                if sof:
                    extras_obs.append('Sofá-cama')
                obs = ' • '.join(extras_obs)
                fallback_out = None
                if not out_list:
                    d_last = get_last_out(aloj)
                    if d_last:
                        fmt = fmt_date_parts(d_last)
                        if fmt:
                            fallback_out = fmt
                fallback_in = None
                if not in_list:
                    d_next = get_next_in(aloj)
                    if d_next:
                        fmt = fmt_date_parts(d_next)
                        if fmt:
                            fallback_in = fmt
                    else:
                        fallback_in = {'text': 'Sem Reservas'}
                # Se existe checkout e nÇõo hÇ  limpeza hoje, verificar limpeza planeada antes/prÇüx checkin
                if out_list and not task_list:
                    limite = get_next_in(aloj) or (dia + timedelta(days=14))
                    prox_limpeza = get_future_clean(aloj, limite)
                    if prox_limpeza:
                        dia_fut = prox_limpeza.get('dia')
                        nome_fut = prox_limpeza.get('nome') or ''
                        try:
                            data_fmt = dia_fut.strftime('%d/%m') if dia_fut else ''
                            status = f"Planeada {data_fmt}" if data_fmt else 'Planeada'
                        except Exception:
                            status = 'Planeada'
                        try:
                            if dia_fut:
                                data_lbl = dia_fut.strftime('%d/%m')
                            else:
                                data_lbl = ''
                            if nome_fut or data_lbl:
                                equipa = f"{nome_fut} ({data_lbl})".strip()
                                last_info = True
                        except Exception:
                            pass

                cards.append({
                    'alojamento': aloj_display or aloj,
                    'status': status,
                    'check_out': chk_out,
                    'has_check_out': bool(out_list),
                    'check_in': chk_in,
                    'has_check_in': bool(in_list),
                    'entrou': bool(first_val(in_list, 'ENTROU') or 0),
                    'equipa': equipa,
                    'last_info': last_info,
                    'hora_lp': hora_lp,
                    'hora_fim': hora_fim,
                    'noites': noites,
                    'hospedes': hospedes,
                    'berco': berco,
                    'sofacama': sof,
                    'obs': obs,
                    'sef': bool(first_val(in_list, 'SEF') or 0),
                    'instr': bool(first_val(in_list, 'INSTR') or 0),
                    'presencial': bool(first_val(in_list, 'PRESENCIAL') or 0),
                    'usrcheckin': first_val(in_list, 'USRCHECKIN') or '',
                    'usrcheckin_nome': first_val(in_list, 'USRCHECKIN_NOME') or '',
                    'fallback_out': fallback_out,
                    'fallback_in': fallback_in
                })

            return jsonify({'data': dia_iso, 'cards': cards})
        except Exception as e:
            try:
                app.logger.exception('Erro em api_turnover')
            except Exception:
                pass
            return jsonify({'error': str(e)}), 500

    @app.route('/api/turnover/checkin', methods=['GET', 'POST'])
    @login_required
    def api_turnover_checkin():
        try:
            if request.method == 'GET':
                data_str = (request.args.get('data') or '').strip()
                aloj = (request.args.get('alojamento') or '').strip()
                if not data_str or not aloj:
                    return jsonify({'error': 'Parâmetros em falta'}), 400
                try:
                    dia = datetime.strptime(data_str, '%Y-%m-%d').date()
                except Exception:
                    return jsonify({'error': 'Data inválida'}), 400

                users_rows = db.session.execute(text(
                    "SELECT LOGIN, NOME FROM US WHERE ISNULL(INATIVO,0)=0 ORDER BY NOME"
                )).fetchall()
                users = [{'value': r[0], 'label': r[1] or r[0]} for r in users_rows]

                row = db.session.execute(text("""
                    SELECT TOP 1 ISNULL(PRESENCIAL,0) AS PRESENCIAL,
                           ISNULL(ENTROU,0) AS ENTROU,
                           ISNULL(USRCHECKIN,'') AS USRCHECKIN,
                           ISNULL(SEF,0) AS SEF,
                           ISNULL(USRSEF,'') AS USRSEF,
                           ISNULL(INSTR,0) AS INSTR,
                           ISNULL(USRINSTR,'') AS USRINSTR
                    FROM RS
                    WHERE CAST(DATAIN AS date) = :dia
                      AND LTRIM(RTRIM(ALOJAMENTO)) = LTRIM(RTRIM(:aloj))
                      AND ISNULL(CANCELADA,0) = 0
                    ORDER BY DATAIN DESC
                """), {'dia': dia, 'aloj': aloj}).mappings().first()
                if not row:
                    return jsonify({'error': 'Reserva não encontrada'}), 404

                data = {
                    'presencial': bool(row.get('PRESENCIAL') or 0),
                    'entrou': bool(row.get('ENTROU') or 0),
                    'usrcheckin': row.get('USRCHECKIN') or '',
                    'sef': bool(row.get('SEF') or 0),
                    'usrsef': row.get('USRSEF') or '',
                    'instr': bool(row.get('INSTR') or 0),
                    'usrinstr': row.get('USRINSTR') or ''
                }
                return jsonify({'data': data, 'users': users, 'alojamento': aloj})

            # POST
            body = request.get_json(silent=True) or {}
            data_str = (body.get('data') or '').strip()
            aloj = (body.get('alojamento') or '').strip()
            if not data_str or not aloj:
                return jsonify({'error': 'Parâmetros em falta'}), 400
            try:
                dia = datetime.strptime(data_str, '%Y-%m-%d').date()
            except Exception:
                return jsonify({'error': 'Data inválida'}), 400
            sef = 1 if body.get('sef') else 0
            instr = 1 if body.get('instr') else 0
            presencial = 1 if body.get('presencial') else 0
            entrou = 1 if body.get('entrou') else 0
            usrcheckin = (body.get('usrcheckin') or '').strip()
            usrsef = getattr(current_user, 'LOGIN', '')
            usrinstr = getattr(current_user, 'LOGIN', '')

            upd = text("""
                UPDATE RS
                   SET PRESENCIAL = :p,
                       ENTROU = :e,
                       USRCHECKIN = :u,
                       SEF = :sef,
                       USRSEF = CASE WHEN :sef = 1 THEN :usrsef ELSE USRSEF END,
                       INSTR = :instr,
                       USRINSTR = CASE WHEN :instr = 1 THEN :usrinstr ELSE USRINSTR END
                 WHERE CAST(DATAIN AS date) = :dia
                   AND LTRIM(RTRIM(ALOJAMENTO)) = LTRIM(RTRIM(:aloj))
                   AND ISNULL(CANCELADA,0) = 0
            """)
            res = db.session.execute(upd, {
                'p': presencial,
                'e': entrou,
                'u': usrcheckin,
                'sef': sef,
                'usrsef': usrsef,
                'instr': instr,
                'usrinstr': usrinstr,
                'dia': dia,
                'aloj': aloj
            })
            db.session.commit()
            return jsonify({'ok': True, 'updated': res.rowcount})
        except Exception as e:
            db.session.rollback()
            try:
                app.logger.exception('Erro em api_turnover_checkin')
            except Exception:
                pass
            return jsonify({'error': str(e)}), 500


    def _ensure_rh_kms_schema():
        db.session.execute(text("""
            IF OBJECT_ID('dbo.RH_KMS', 'U') IS NULL
            BEGIN
                CREATE TABLE dbo.RH_KMS
                (
                    RH_KMSSTAMP VARCHAR(25) NOT NULL
                        CONSTRAINT DF_RH_KMS_RH_KMSSTAMP DEFAULT LEFT(CONVERT(varchar(36), NEWID()), 25),
                    ANO INT NOT NULL CONSTRAINT DF_RH_KMS_ANO DEFAULT 0,
                    MES INT NOT NULL CONSTRAINT DF_RH_KMS_MES DEFAULT 0,
                    UTILIZADOR VARCHAR(50) NOT NULL CONSTRAINT DF_RH_KMS_UTILIZADOR DEFAULT '',
                    RESERVA VARCHAR(25) NOT NULL CONSTRAINT DF_RH_KMS_RESERVA DEFAULT '',
                    ORIGEM NVARCHAR(200) NOT NULL CONSTRAINT DF_RH_KMS_ORIGEM DEFAULT '',
                    DESTINO NVARCHAR(200) NOT NULL CONSTRAINT DF_RH_KMS_DESTINO DEFAULT '',
                    KMS DECIMAL(12,2) NOT NULL CONSTRAINT DF_RH_KMS_KMS DEFAULT 0,
                    VALOR_KM DECIMAL(12,2) NOT NULL CONSTRAINT DF_RH_KMS_VALOR_KM DEFAULT 0,
                    VALOR_TOTAL DECIMAL(12,2) NOT NULL CONSTRAINT DF_RH_KMS_VALOR_TOTAL DEFAULT 0,
                    OBS VARCHAR(200) NOT NULL CONSTRAINT DF_RH_KMS_OBS DEFAULT '',
                    CONSTRAINT PK_RH_KMS PRIMARY KEY CLUSTERED (RH_KMSSTAMP)
                );
            END
        """))
        db.session.execute(text("""
            IF OBJECT_ID('dbo.RH_KMS', 'U') IS NOT NULL
               AND NOT EXISTS (
                    SELECT 1
                    FROM sys.indexes
                    WHERE object_id = OBJECT_ID('dbo.RH_KMS')
                      AND name = 'UX_RH_KMS_RESERVA'
               )
            BEGIN
                CREATE UNIQUE NONCLUSTERED INDEX UX_RH_KMS_RESERVA
                    ON dbo.RH_KMS (RESERVA);
            END
        """))
        db.session.commit()


    def _kms_is_admin():
        return bool(getattr(current_user, 'ADMIN', False))


    def _kms_parse_ano(raw_value, default_value=None):
        default_year = default_value or date.today().year
        try:
            year = int(raw_value or default_year)
        except Exception:
            year = default_year
        return max(2000, min(2100, year))


    def _kms_parse_mes(raw_value, default_value=None):
        default_month = default_value or date.today().month
        try:
            month = int(raw_value or default_month)
        except Exception:
            month = default_month
        return max(1, min(12, month))


    def _kms_decimal(value, default='0.00'):
        try:
            text_value = str(value or '').strip().replace(',', '.')
            if not text_value:
                return Decimal(default)
            return Decimal(text_value)
        except Exception:
            return Decimal(default)


    def _kms_round(value):
        return _kms_decimal(value).quantize(Decimal('0.01'), rounding=ROUND_HALF_UP)


    def _kms_float(value):
        try:
            return float(_kms_round(value))
        except Exception:
            return 0.0


    def _kms_read_preco_km():
        row = db.session.execute(text("""
            SELECT TOP 1 PARAMETRO, TIPO, CVALOR, DVALOR, NVALOR, LVALOR
            FROM dbo.PARA
            WHERE UPPER(LTRIM(RTRIM(PARAMETRO))) = 'PRECO_KM'
        """)).mappings().first()
        if not row:
            return Decimal('0.00')
        try:
            value = _para_value_from_row(row)
        except Exception:
            value = 0
        return _kms_round(value)


    def _kms_company_info():
        current_feid = None
        try:
            current_feid = get_current_feid()
        except Exception:
            current_feid = None

        fe_name = ''
        if current_feid not in (None, ''):
            fe_row = db.session.execute(text("""
                SELECT TOP 1
                    ISNULL(NOMEFISCAL, '') AS NOMEFISCAL,
                    ISNULL(NOME, '') AS NOME
                FROM dbo.FE
                WHERE FEID = :feid
            """), {'feid': int(current_feid)}).mappings().first() or {}
            fe_name = str(fe_row.get('NOMEFISCAL') or '').strip() or str(fe_row.get('NOME') or '').strip()

        rows = db.session.execute(text("""
            SELECT PARAMETRO, TIPO, CVALOR, DVALOR, NVALOR, LVALOR
            FROM dbo.PARA
            WHERE UPPER(LTRIM(RTRIM(PARAMETRO))) IN (
                'EMP_NOME_COM',
                'EMP_NOME',
                'EMP_MORADA',
                'EMP_CODPOST',
                'EMP_LOCAL',
                'EMP_NIF',
                'EMP_NCONT'
            )
        """)).mappings().all()
        values = {}
        for row in rows:
            key = str(row.get('PARAMETRO') or '').strip().upper()
            if not key:
                continue
            try:
                values[key] = str(_para_value_from_row(row) or '').strip()
            except Exception:
                values[key] = str(row.get('CVALOR') or '').strip()
        morada_parts = [values.get('EMP_MORADA', ''), values.get('EMP_CODPOST', ''), values.get('EMP_LOCAL', '')]
        morada_parts = [part for part in morada_parts if part]
        return {
            'nome': fe_name or values.get('EMP_NOME_COM') or values.get('EMP_NOME') or 'StationZero',
            'morada': ' '.join(morada_parts).strip(),
            'nif': values.get('EMP_NIF') or values.get('EMP_NCONT') or ''
        }


    def _kms_sede_label():
        rows = db.session.execute(text("""
            SELECT PARAMETRO, TIPO, CVALOR, NVALOR
            FROM dbo.PARA
            WHERE UPPER(LTRIM(RTRIM(PARAMETRO))) IN ('EMP_MORADA', 'EMP_CODPOST', 'EMP_LOCAL')
        """)).mappings().all()
        values = {}
        for row in rows:
            key = (row.get('PARAMETRO') or '').strip().upper()
            tipo = (row.get('TIPO') or '').strip().upper()
            if tipo == 'N':
                raw = row.get('NVALOR')
            else:
                raw = row.get('CVALOR')
            values[key] = str(raw or '').strip()
        parts = [values.get('EMP_MORADA', ''), values.get('EMP_CODPOST', ''), values.get('EMP_LOCAL', '')]
        parts = [part for part in parts if part]
        return f"SEDE - {', '.join(parts)}" if parts else 'SEDE'


    def _kms_user_options():
        if not _kms_is_admin():
            login = str(getattr(current_user, 'LOGIN', '') or '').strip()
            name = str(getattr(current_user, 'NOME', '') or '').strip() or login
            return [{'login': login, 'nome': name}]
        rows = db.session.execute(text("""
            SELECT LOGIN, ISNULL(NOME,'') AS NOME
            FROM dbo.US
            WHERE ISNULL(INATIVO,0) = 0
            ORDER BY NOME, LOGIN
        """)).mappings().all()
        out = []
        for row in rows:
            login = str(row.get('LOGIN') or '').strip()
            if not login:
                continue
            out.append({
                'login': login,
                'nome': str(row.get('NOME') or '').strip() or login
            })
        if not out:
            login = str(getattr(current_user, 'LOGIN', '') or '').strip()
            if login:
                out.append({'login': login, 'nome': str(getattr(current_user, 'NOME', '') or '').strip() or login})
        return out


    def _kms_resolve_selected_user(requested_login=None, user_options=None):
        options = user_options if user_options is not None else _kms_user_options()
        current_login = str(getattr(current_user, 'LOGIN', '') or '').strip()
        if not _kms_is_admin():
            return current_login
        requested = str(requested_login or '').strip()
        valid = {str(item.get('login') or '').strip().upper(): str(item.get('login') or '').strip() for item in options if str(item.get('login') or '').strip()}
        if requested and requested.upper() in valid:
            return valid[requested.upper()]
        if current_login and current_login.upper() in valid:
            return valid[current_login.upper()]
        return next(iter(valid.values()), current_login)


    def _kms_selected_user_name(utilizador, user_options=None):
        login = str(utilizador or '').strip()
        options = user_options if user_options is not None else _kms_user_options()
        for item in options:
            option_login = str(item.get('login') or '').strip()
            if option_login and option_login.upper() == login.upper():
                return str(item.get('nome') or '').strip() or option_login
        if login and str(getattr(current_user, 'LOGIN', '') or '').strip().upper() == login.upper():
            return str(getattr(current_user, 'NOME', '') or '').strip() or login
        return login


    def _kms_month_totals(ano, mes, utilizador):
        row = db.session.execute(text("""
            SELECT
                ISNULL(SUM(KMS), 0) AS TOTAL_KMS,
                ISNULL(SUM(VALOR_TOTAL), 0) AS TOTAL_VALOR
            FROM dbo.RH_KMS
            WHERE ANO = :ano
              AND MES = :mes
              AND LTRIM(RTRIM(ISNULL(UTILIZADOR,''))) = LTRIM(RTRIM(:utilizador))
        """), {
            'ano': ano,
            'mes': mes,
            'utilizador': utilizador
        }).mappings().first() or {}
        return {
            'total_kms': _kms_float(row.get('TOTAL_KMS')),
            'total_valor': _kms_float(row.get('TOTAL_VALOR'))
        }


    def _kms_claim_payload(marked_login, marked_name, selected_login):
        login = str(marked_login or '').strip()
        name = str(marked_name or '').strip() or login
        if not login:
            return {
                'estado': 'free',
                'estado_label': 'Livre',
                'checked': False,
                'disabled': False,
                'marcado_por': '',
                'marcado_por_nome': ''
            }
        if login.upper() == str(selected_login or '').strip().upper():
            return {
                'estado': 'mine',
                'estado_label': 'Registado',
                'checked': True,
                'disabled': False,
                'marcado_por': login,
                'marcado_por_nome': name
            }
        return {
            'estado': 'other',
            'estado_label': 'Bloqueado',
            'checked': False,
            'disabled': True,
            'marcado_por': login,
            'marcado_por_nome': name
        }


    def _kms_reservation_claim(rsstamp, selected_login):
        row = db.session.execute(text("""
            SELECT TOP 1
                ISNULL(K.UTILIZADOR,'') AS UTILIZADOR,
                ISNULL(U.NOME, K.UTILIZADOR) AS UTILIZADOR_NOME
            FROM dbo.RH_KMS K
            LEFT JOIN dbo.US U ON U.LOGIN = K.UTILIZADOR
            WHERE LTRIM(RTRIM(ISNULL(K.RESERVA,''))) = LTRIM(RTRIM(:reserva))
        """), {'reserva': rsstamp}).mappings().first() or {}
        return _kms_claim_payload(row.get('UTILIZADOR'), row.get('UTILIZADOR_NOME'), selected_login)


    def _kms_unique_violation(exc):
        message = str(exc or '').lower()
        return ('2601' in message) or ('2627' in message) or ('duplicate key' in message) or ('unique' in message)


    def _kms_fetch_reservation_rows(ano, mes, utilizador, current_feid):
        sede_label = _kms_sede_label()
        rows = db.session.execute(text("""
            SELECT
                RS.RSSTAMP,
                ISNULL(RS.RESERVA,'') AS RESERVA_CODIGO,
                CAST(RS.DATAIN AS date) AS DATA_CHECKIN,
                ISNULL(RS.ALOJAMENTO,'') AS ALOJAMENTO,
                ISNULL(RS.NOME,'') AS HOSPEDE,
                ISNULL(RS.PRESENCIAL,0) AS PRESENCIAL,
                ISNULL(RS.USRCHECKIN,'') AS USRCHECKIN,
                ISNULL(UC.NOME, RS.USRCHECKIN) AS USRCHECKIN_NOME,
                ISNULL(AL.ALSTAMP,'') AS ALSTAMP,
                ISNULL(AL.CCUSTO,'') AS CCUSTO,
                ISNULL(AL.MORADA,'') AS AL_MORADA,
                ISNULL(AL.CODPOST,'') AS AL_CODPOST,
                ISNULL(AL.LOCAL,'') AS AL_LOCAL,
                rota.KM AS DISTANCIA_SEDE,
                ISNULL(K.UTILIZADOR,'') AS KMS_UTILIZADOR,
                ISNULL(U.NOME, K.UTILIZADOR) AS KMS_UTILIZADOR_NOME
            FROM dbo.RS RS
            INNER JOIN dbo.AL AL
                ON LTRIM(RTRIM(AL.NOME)) = LTRIM(RTRIM(ISNULL(RS.ALOJAMENTO,'')))
            LEFT JOIN dbo.US UC
                ON UC.LOGIN = RS.USRCHECKIN
            OUTER APPLY (
                SELECT TOP 1 CAST(R.Km AS DECIMAL(12,2)) AS KM
                FROM dbo.ROTAS R
                WHERE (
                        LTRIM(RTRIM(ISNULL(R.OrigemStamp,''))) = '__SEDE__'
                    AND LTRIM(RTRIM(ISNULL(R.DestinoStamp,''))) = LTRIM(RTRIM(AL.ALSTAMP))
                ) OR (
                        LTRIM(RTRIM(ISNULL(R.DestinoStamp,''))) = '__SEDE__'
                    AND LTRIM(RTRIM(ISNULL(R.OrigemStamp,''))) = LTRIM(RTRIM(AL.ALSTAMP))
                )
                ORDER BY ISNULL(R.UpdatedAt, GETDATE()) DESC
            ) rota
            LEFT JOIN dbo.RH_KMS K
                ON LTRIM(RTRIM(ISNULL(K.RESERVA,''))) = LTRIM(RTRIM(RS.RSSTAMP))
            LEFT JOIN dbo.US U
                ON U.LOGIN = K.UTILIZADOR
            WHERE YEAR(CAST(RS.DATAIN AS date)) = :ano
              AND MONTH(CAST(RS.DATAIN AS date)) = :mes
              AND ISNULL(RS.CANCELADA,0) = 0
              AND (
                    ISNULL(AL.FEID, 0) = :current_feid
                 OR ISNULL(AL.FEID_GESTOR, 0) = :current_feid
              )
            ORDER BY CAST(RS.DATAIN AS date), ISNULL(RS.ALOJAMENTO,''), ISNULL(RS.RESERVA,''), RS.RSSTAMP
        """), {
            'ano': ano,
            'mes': mes,
            'utilizador': utilizador,
            'current_feid': current_feid
        }).mappings().all()

        result = []
        for row in rows:
            distance_raw = row.get('DISTANCIA_SEDE')
            has_distance = distance_raw is not None
            distance = _kms_round(distance_raw if has_distance else 0)
            kms_value = _kms_round(distance * Decimal('2'))
            claim = _kms_claim_payload(row.get('KMS_UTILIZADOR'), row.get('KMS_UTILIZADOR_NOME'), utilizador)
            destination_parts = [
                str(row.get('ALOJAMENTO') or '').strip(),
                str(row.get('AL_MORADA') or '').strip(),
                str(row.get('AL_CODPOST') or '').strip(),
                str(row.get('AL_LOCAL') or '').strip()
            ]
            destination_parts = [part for part in destination_parts if part]
            result.append({
                'rsstamp': str(row.get('RSSTAMP') or '').strip(),
                'reserva_codigo': str(row.get('RESERVA_CODIGO') or '').strip() or str(row.get('RSSTAMP') or '').strip(),
                'data_checkin': row.get('DATA_CHECKIN').strftime('%Y-%m-%d') if isinstance(row.get('DATA_CHECKIN'), (date, datetime)) else '',
                'alojamento': str(row.get('ALOJAMENTO') or '').strip(),
                'hospede': str(row.get('HOSPEDE') or '').strip(),
                'presencial': bool(row.get('PRESENCIAL') or 0),
                'usrcheckin': str(row.get('USRCHECKIN') or '').strip(),
                'usrcheckin_nome': str(row.get('USRCHECKIN_NOME') or '').strip(),
                'ccusto': str(row.get('CCUSTO') or '').strip(),
                'alstamp': str(row.get('ALSTAMP') or '').strip(),
                'origem': sede_label,
                'destino': ' - '.join(destination_parts),
                'distancia': _kms_float(distance),
                'kms': _kms_float(kms_value),
                'has_distance': bool(has_distance),
                **claim
            })
        return result


    def _kms_pdf_rows(ano, mes, utilizador):
        rows = db.session.execute(text("""
            SELECT
                K.RH_KMSSTAMP,
                K.RESERVA,
                ISNULL(K.ORIGEM,'') AS ORIGEM,
                ISNULL(K.DESTINO,'') AS DESTINO,
                CAST(ISNULL(K.KMS, 0) AS DECIMAL(12,2)) AS KMS,
                ISNULL(K.OBS,'') AS OBS,
                CAST(RS.DATAIN AS date) AS DATA_CHECKIN,
                ISNULL(RS.RESERVA,'') AS RESERVA_CODIGO,
                ISNULL(RS.ALOJAMENTO,'') AS ALOJAMENTO,
                ISNULL(RS.NOME,'') AS HOSPEDE
            FROM dbo.RH_KMS K
            LEFT JOIN dbo.RS RS
                ON LTRIM(RTRIM(ISNULL(RS.RSSTAMP,''))) = LTRIM(RTRIM(ISNULL(K.RESERVA,'')))
            WHERE K.ANO = :ano
              AND K.MES = :mes
              AND LTRIM(RTRIM(ISNULL(K.UTILIZADOR,''))) = LTRIM(RTRIM(:utilizador))
            ORDER BY CAST(RS.DATAIN AS date), ISNULL(RS.RESERVA,''), K.RESERVA
        """), {
            'ano': ano,
            'mes': mes,
            'utilizador': utilizador
        }).mappings().all()

        days_in_month = calendar.monthrange(int(ano), int(mes))[1]
        result = []

        for row in rows:
            checkin_date = row.get('DATA_CHECKIN')
            day = checkin_date.day if isinstance(checkin_date, (date, datetime)) else None
            reserva_codigo = str(row.get('RESERVA_CODIGO') or row.get('RESERVA') or '').strip()
            alojamento = str(row.get('ALOJAMENTO') or '').strip()
            obs = str(row.get('OBS') or '').strip()
            justificacao_parts = [part for part in [reserva_codigo, alojamento, obs] if part]
            result.append({
                'dia': day or '',
                'origem': str(row.get('ORIGEM') or '').strip(),
                'destino': str(row.get('DESTINO') or '').strip(),
                'justificacao': ' • '.join(justificacao_parts) or 'Check-in presencial',
                'kms': _kms_float(row.get('KMS'))
            })

        if not result:
            result.append({
                'dia': '',
                'origem': '',
                'destino': '',
                'justificacao': '',
                'kms': 0.0
            })

        return result


    def _kms_reservation_candidate(rsstamp, ano, mes, utilizador, current_feid):
        rows = _kms_fetch_reservation_rows(ano, mes, utilizador, current_feid)
        for row in rows:
            if str(row.get('rsstamp') or '').strip().upper() == str(rsstamp or '').strip().upper():
                return row
        return None


