    @app.route('/performance')
    @login_required
    def performance_page():
        return render_template('performance.html', page_title='Performance')

    def _performance_parse_dates(qs_ini, qs_fim):
        today = date.today()
        first_day = date(today.year, today.month, 1)
        if today.month == 12:
            next_month_first = date(today.year + 1, 1, 1)
        else:
            next_month_first = date(today.year, today.month + 1, 1)
        last_day = next_month_first - timedelta(days=1)

        def parse_d(dstr, fallback):
            try:
                return datetime.strptime(dstr, '%Y-%m-%d').date()
            except Exception:
                return fallback

        return parse_d(qs_ini, first_day), parse_d(qs_fim, last_day)

    def _performance_allowed_alojamentos(current_feid):
        rows = db.session.execute(
            text(
                """
                SELECT
                    LTRIM(RTRIM(ISNULL(A.NOME, ''))) AS NOME,
                    UPPER(LTRIM(RTRIM(ISNULL(A.TIPO, '')))) AS TIPO
                FROM dbo.AL AS A
                WHERE ISNULL(A.INATIVO, 0) = 0
                  AND ISNULL(A.FECHADO, 0) = 0
                  AND (
                        ISNULL(A.FEID, 0) = :current_feid
                     OR ISNULL(A.FEID_GESTOR, 0) = :current_feid
                  )
                ORDER BY LTRIM(RTRIM(ISNULL(A.NOME, '')))
                """
            ),
            {'current_feid': current_feid},
        ).mappings().all()

        alojamentos = []
        for row in rows:
            nome = str(row.get('NOME') or '').strip()
            if not nome:
                continue
            tipo = str(row.get('TIPO') or '').strip().upper()
            grupo = 'GESTAO' if tipo == 'GESTAO' else 'EXPLORACAO'
            alojamentos.append({'nome': nome, 'grupo': grupo})
        return alojamentos

    def _performance_occ_map(current_feid, data_inicio, data_fim):
        sql = text(
            """
            SELECT DISTINCT
                LTRIM(RTRIM(ISNULL(V.CCUSTO, ''))) AS NOME,
                CAST(V.data AS date) AS DIA
            FROM dbo.v_diario_all AS V
            JOIN dbo.AL AS A
              ON V.CCUSTO = A.NOME
             AND ISNULL(A.INATIVO, 0) = 0
             AND ISNULL(A.FECHADO, 0) = 0
             AND (
                   ISNULL(A.FEID, 0) = :current_feid
                OR ISNULL(A.FEID_GESTOR, 0) = :current_feid
             )
            WHERE ISNULL(V.valor, 0) <> 0
              AND V.data BETWEEN :data_inicio AND :data_fim
            """
        )
        rows = db.session.execute(
            sql,
            {
                'current_feid': current_feid,
                'data_inicio': data_inicio,
                'data_fim': data_fim,
            },
        ).mappings().all()

        occ_map = {}
        for row in rows:
            nome = str(row.get('NOME') or '').strip()
            dia = row.get('DIA')
            if not nome or not dia:
                continue
            occ_map.setdefault(nome, set()).add(dia)
        return occ_map

    def _performance_segment_stats(segment_start, segment_end, alojamentos, occ_map):
        if not segment_start or not segment_end or segment_end < segment_start:
            return {
                'start': '',
                'end': '',
                'gestao_pct': None,
                'exploracao_pct': None,
            }

        segment_days = (segment_end - segment_start).days + 1
        segment_set = {segment_start + timedelta(days=offset) for offset in range(segment_days)}
        gestao_names = [item['nome'] for item in alojamentos if item['grupo'] == 'GESTAO']
        exploracao_names = [item['nome'] for item in alojamentos if item['grupo'] == 'EXPLORACAO']

        def calc_pct(names):
            total_slots = len(names) * segment_days
            if total_slots <= 0:
                return None
            occupied_slots = 0
            for nome in names:
                occupied_slots += len((occ_map.get(nome) or set()) & segment_set)
            return round((occupied_slots / total_slots) * 100.0, 2)

        return {
            'start': segment_start.strftime('%Y-%m-%d'),
            'end': segment_end.strftime('%Y-%m-%d'),
            'gestao_pct': calc_pct(gestao_names),
            'exploracao_pct': calc_pct(exploracao_names),
        }

    # API: Alojamentos performance aggregation
    @app.route('/api/performance')
    @login_required
    def api_performance():
        try:
            current_feid, error_response = _current_feid_or_json_error()
            if error_response:
                return error_response
            # Parse dates or default to current month
            qs_ini = (request.args.get('data_inicio') or '').strip()
            qs_fim = (request.args.get('data_fim') or '').strip()
            today = date.today()
            first_day = date(today.year, today.month, 1)
            data_inicio, data_fim = _performance_parse_dates(qs_ini, qs_fim)

            # Nights total in the period (1 per day, inclusive)
            noites_totais = (data_fim - data_inicio).days + 1
            if noites_totais < 0:
                return jsonify({'error': 'Intervalo de datas inválido'}), 400

            # Future window: from max(today, start) to end (inclusive)
            future_start = first_day if data_inicio < first_day else data_inicio
            if today > future_start:
                future_start = today
            noites_futuras_totais = (data_fim - future_start).days + 1 if data_fim >= future_start else 0

            # Next 2/4/7 nights windows for alert (from today, capped to selected period)
            next_start = today if today > data_inicio else data_inicio
            next2_end_raw = today + timedelta(days=1)
            next4_end_raw = today + timedelta(days=3)
            next7_end_raw = today + timedelta(days=6)
            next2_end = next2_end_raw if next2_end_raw < data_fim else data_fim
            next4_end = next4_end_raw if next4_end_raw < data_fim else data_fim
            next7_end = next7_end_raw if next7_end_raw < data_fim else data_fim
            total_next2_days = (next2_end - next_start).days + 1 if next2_end >= next_start else 0
            total_next4_days = (next4_end - next_start).days + 1 if next4_end >= next_start else 0
            total_next7_days = (next7_end - next_start).days + 1 if next7_end >= next_start else 0

            # SQL Server aggregation with LEFT JOIN and filters in ON to preserve AL rows.
            # Exclude closed lodgings, and later compute sellable availability as 2+ night runs.
            sql = text(
                """
                SELECT
                    A.NOME AS nome,
                    A.TIPOLOGIA AS tipologia,
                    A.TIPO AS tipo,
                    COUNT(DISTINCT V.data) AS noites_ocupadas,
                    SUM(ISNULL(V.valor, 0)) AS total_liquido,
                    CASE WHEN COUNT(DISTINCT V.data) > 0
                         THEN SUM(ISNULL(V.valor,0)) / NULLIF(COUNT(DISTINCT V.data), 0)
                         ELSE 0 END AS preco_medio_noite,
                    COUNT(DISTINCT CASE WHEN V.data >= :future_start THEN V.data END) AS noites_futuras_ocupadas,
                    COUNT(DISTINCT CASE WHEN V.data BETWEEN :next_start AND :next2_end THEN V.data END) AS next2_ocupadas,
                    COUNT(DISTINCT CASE WHEN V.data BETWEEN :next_start AND :next4_end THEN V.data END) AS next4_ocupadas,
                    COUNT(DISTINCT CASE WHEN V.data BETWEEN :next_start AND :next7_end THEN V.data END) AS next7_ocupadas
                FROM AL AS A
                LEFT JOIN v_diario_all AS V
                  ON V.CCUSTO = A.NOME
                 AND ISNULL(V.valor, 0) <> 0
                 AND V.data BETWEEN :data_inicio AND :data_fim
                WHERE ISNULL(A.INATIVO, 0) = 0
                  AND ISNULL(A.FECHADO, 0) = 0
                  AND (
                        ISNULL(A.FEID, 0) = :current_feid
                     OR ISNULL(A.FEID_GESTOR, 0) = :current_feid
                  )
                GROUP BY A.NOME, A.TIPOLOGIA, A.TIPO
                ORDER BY A.NOME
                """
            )

            rows = db.session.execute(sql, {
                'data_inicio': data_inicio,
                'data_fim': data_fim,
                'hoje': today,
                'future_start': future_start,
                'next_start': next_start,
                'next2_end': next2_end,
                'next4_end': next4_end,
                'next7_end': next7_end,
                'current_feid': current_feid,
            }).mappings().all()
            # Build occupancy map for the future selected horizon so availability only counts
            # sellable runs of >= 2 nights, consistent with radar/detail logic.
            from datetime import datetime as _dt
            sql_occ = text(
                """
                SELECT V.CCUSTO AS nome, CAST(V.data AS date) AS dia
                FROM v_diario_all V
                JOIN AL A
                  ON V.CCUSTO = A.NOME
                 AND ISNULL(A.INATIVO,0)=0
                 AND ISNULL(A.FECHADO,0)=0
                 AND (
                       ISNULL(A.FEID, 0) = :current_feid
                    OR ISNULL(A.FEID_GESTOR, 0) = :current_feid
                 )
                WHERE ISNULL(V.valor,0) <> 0
                  AND V.data BETWEEN :start AND :end
                """
            )
            occ_rows = db.session.execute(sql_occ, {
                'start': future_start,
                'end': data_fim,
                'current_feid': current_feid,
            }).fetchall()
            occ_map = {}
            for nome, dia in occ_rows:
                # Ensure date object
                if isinstance(dia, _dt):
                    dkey = dia.date()
                else:
                    dkey = dia
                occ_map.setdefault(nome, set()).add(dkey)

            result = []
            for r in rows:
                nome = r.get('nome')
                tipologia = r.get('tipologia')
                tipo = r.get('tipo')
                noites_ocupadas = float(r.get('noites_ocupadas') or 0)
                total_liquido = float(r.get('total_liquido') or 0)
                preco_medio_noite = float(r.get('preco_medio_noite') or 0)
                noites_futuras_ocupadas = int(r.get('noites_futuras_ocupadas') or 0)
                # Occupancy map for this lodging in next horizon
                occ_set = occ_map.get(nome, set())
                future_keys = []
                if data_fim >= future_start:
                    for offset in range((data_fim - future_start).days + 1):
                        future_keys.append(future_start + timedelta(days=offset))

                def sellable_nights(days):
                    run = 0
                    total = 0
                    for d in days:
                        if d in occ_set:
                            if run >= 2:
                                total += run
                            run = 0
                        else:
                            run += 1
                    if run >= 2:
                        total += run
                    return total

                # Helper to detect if there exists a run of >=2 empty nights within first L days
                def has_two_plus_gap(L):
                    if L is None or L < 2:
                        return False
                    run = 0
                    for i in range(L):
                        d = next_start + timedelta(days=i)
                        if d in occ_set:
                            run = 0
                        else:
                            run += 1
                            if run >= 2:
                                return True
                    return False
                noites_disponiveis = sellable_nights(future_keys)
                taxa = (noites_ocupadas / noites_totais * 100.0) if noites_totais > 0 else 0.0
                # Determine alert level based on first window that contains a 2+ empty-night run
                alert_level = ''
                if has_two_plus_gap(total_next2_days):
                    alert_level = 'red'
                elif has_two_plus_gap(total_next4_days):
                    alert_level = 'orange'
                elif has_two_plus_gap(total_next7_days):
                    alert_level = 'yellow'

                result.append({
                    'nome': nome,
                    'tipologia': tipologia,
                    'tipo': tipo,
                    'noites_ocupadas': round(noites_ocupadas, 2),
                    'noites_totais': noites_totais,
                    'taxa_ocupacao': round(taxa, 2),
                    'total_liquido': round(total_liquido, 2),
                    'preco_medio_noite': round(preco_medio_noite, 2),
                    'noites_futuras_ocupadas': noites_futuras_ocupadas,
                    'noites_futuras_totais': noites_futuras_totais,
                    'noites_disponiveis': noites_disponiveis,
                    'alert_level': alert_level
                })

            return jsonify({
                'rows': result,
                'data_inicio': data_inicio.strftime('%Y-%m-%d'),
                'data_fim': data_fim.strftime('%Y-%m-%d')
            })
        except Exception as e:
            return jsonify({'error': str(e)}), 500

    @app.route('/api/performance/ocupacao-resumo')
    @login_required
    def api_performance_ocupacao_resumo():
        try:
            current_feid, error_response = _current_feid_or_json_error()
            if error_response:
                return error_response

            qs_ini = (request.args.get('data_inicio') or '').strip()
            qs_fim = (request.args.get('data_fim') or '').strip()
            data_inicio, data_fim = _performance_parse_dates(qs_ini, qs_fim)
            if data_fim < data_inicio:
                return jsonify({'error': 'Intervalo de datas inválido'}), 400

            today = date.today()
            alojamentos = _performance_allowed_alojamentos(current_feid)
            occ_map = _performance_occ_map(current_feid, data_inicio, data_fim)

            until_today = _performance_segment_stats(
                data_inicio,
                min(data_fim, today),
                alojamentos,
                occ_map,
            )
            from_today = _performance_segment_stats(
                max(data_inicio, today),
                data_fim,
                alojamentos,
                occ_map,
            )

            return jsonify({
                'until_today': until_today,
                'from_today': from_today,
                'data_inicio': data_inicio.strftime('%Y-%m-%d'),
                'data_fim': data_fim.strftime('%Y-%m-%d'),
                'today': today.strftime('%Y-%m-%d'),
            })
        except Exception as e:
            return jsonify({'error': str(e)}), 500

