    @app.route('/api/extratos')
    @login_required
    def api_extratos_list():
        try:
            cols = set(
                r[0] for r in db.session.execute(
                    text("SELECT UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'EXT'")
                ).fetchall()
            )
            need = {'EXTSTAMP', 'NOCONTA', 'DATAINI', 'DATAFIM'}
            missing = sorted(list(need - cols))
            if missing:
                return jsonify({'error': f"Campos em falta na EXT: {', '.join(missing)}"}), 400

            rows = db.session.execute(text("""
                SELECT EXTSTAMP, NOCONTA, DATAINI, DATAFIM, ISNULL(RECONCILIADO,0) AS RECONCILIADO
                FROM dbo.EXT
                ORDER BY DATAFIM DESC, DATAINI DESC, EXTSTAMP DESC
            """)).mappings().all()
            out = []
            for r in rows:
                di = r.get('DATAINI')
                df = r.get('DATAFIM')
                out.append({
                    'EXTSTAMP': r.get('EXTSTAMP') or '',
                    'NOCONTA': int(r.get('NOCONTA') or 0),
                    'DATAINI': di.strftime('%Y-%m-%d') if isinstance(di, (date, datetime)) else (str(di) if di else ''),
                    'DATAFIM': df.strftime('%Y-%m-%d') if isinstance(df, (date, datetime)) else (str(df) if df else ''),
                    'RECONCILIADO': int(r.get('RECONCILIADO') or 0),
                })
            return jsonify(out)
        except Exception as e:
            return jsonify({'error': str(e)}), 500

    @app.route('/api/extratos/contas')
    @login_required
    def api_extratos_contas():
        try:
            rows = db.session.execute(text("""
                WITH CONTAS AS (
                    SELECT
                        EXT.NOCONTA,
                        COUNT(*) AS EXT_COUNT,
                        MIN(CAST(EXT.DATAINI AS date)) AS DATAINI_MIN,
                        MAX(CAST(EXT.DATAFIM AS date)) AS DATAFIM_MAX
                    FROM dbo.EXT AS EXT
                    GROUP BY EXT.NOCONTA
                ),
                BANCOS AS (
                    SELECT
                        V.NOCONTA,
                        MAX(ISNULL(V.BANCO, '')) AS BANCO,
                        MAX(ISNULL(V.CONTA, '')) AS CONTA,
                        MIN(TRY_CONVERT(int, NULLIF(CONVERT(varchar(50), V.ORDEM), ''))) AS ORDEM
                    FROM dbo.V_BL AS V
                    GROUP BY V.NOCONTA
                )
                SELECT
                    C.NOCONTA,
                    ISNULL(B.BANCO, '') AS BANCO,
                    ISNULL(B.CONTA, '') AS CONTA,
                    ISNULL(B.ORDEM, 999999) AS ORDEM,
                    C.EXT_COUNT,
                    C.DATAINI_MIN,
                    C.DATAFIM_MAX
                FROM CONTAS AS C
                LEFT JOIN BANCOS AS B
                  ON B.NOCONTA = C.NOCONTA
                ORDER BY
                    CASE WHEN B.ORDEM IS NULL THEN 1 ELSE 0 END,
                    B.ORDEM,
                    ISNULL(B.BANCO, ''),
                    ISNULL(B.CONTA, ''),
                    C.NOCONTA
            """)).mappings().all()
            out = []
            for r in rows:
                di = r.get('DATAINI_MIN')
                df = r.get('DATAFIM_MAX')
                out.append({
                    'NOCONTA': int(r.get('NOCONTA') or 0),
                    'BANCO': r.get('BANCO') or '',
                    'CONTA': r.get('CONTA') or '',
                    'ORDEM': int(r.get('ORDEM') or 0),
                    'EXT_COUNT': int(r.get('EXT_COUNT') or 0),
                    'DATAINI_MIN': di.strftime('%Y-%m-%d') if isinstance(di, (date, datetime)) else (str(di) if di else ''),
                    'DATAFIM_MAX': df.strftime('%Y-%m-%d') if isinstance(df, (date, datetime)) else (str(df) if df else ''),
                })
            return jsonify(out)
        except Exception as e:
            return jsonify({'error': str(e)}), 500

    @app.route('/api/extratos/agrupar', methods=['POST'])
    @login_required
    def api_extratos_agrupar():
        import uuid
        from sqlalchemy import bindparam

        try:
            body = request.get_json(silent=True) or {}

            try:
                noconta = int(body.get('NOCONTA') or 0)
            except Exception:
                noconta = 0
            try:
                ano = int(body.get('ANO') or 0)
            except Exception:
                ano = 0
            try:
                mes = int(body.get('MES') or 0)
            except Exception:
                mes = 0

            if noconta <= 0:
                return jsonify({'error': 'Conta obrigatória.'}), 400
            if ano < 2000 or ano > 2100:
                return jsonify({'error': 'Ano inválido.'}), 400
            if mes < 1 or mes > 12:
                return jsonify({'error': 'Mês inválido.'}), 400

            el_cols = set(
                r[0] for r in db.session.execute(
                    text("SELECT UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'EL'")
                ).fetchall()
            )
            ext_cols = set(
                r[0] for r in db.session.execute(
                    text("SELECT UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'EXT'")
                ).fetchall()
            )
            need_ext = {'EXTSTAMP', 'NOCONTA', 'DATAINI', 'DATAFIM', 'SALDOINI', 'SALDOFIM', 'RECONCILIADO'}
            missing_ext = sorted(list(need_ext - ext_cols))
            if missing_ext:
                return jsonify({'error': f"Campos em falta na EXT: {', '.join(missing_ext)}"}), 400
            if 'EXTSTAMP' not in el_cols:
                return jsonify({'error': 'A tabela EL precisa do campo EXTSTAMP.'}), 400
            stamp_col = 'ELSTAMP' if 'ELSTAMP' in el_cols else ('ELSATMP' if 'ELSATMP' in el_cols else None)
            if not stamp_col:
                return jsonify({'error': 'A tabela EL precisa de um campo stamp (ELSTAMP ou ELSATMP).'}), 400

            moved_rows = db.session.execute(text(f"""
                SELECT
                    LTRIM(RTRIM(EL.{stamp_col})) AS STAMP,
                    LTRIM(RTRIM(EL.EXTSTAMP)) AS SRC_EXTSTAMP,
                    CAST(EL.DATA AS date) AS DATA,
                    CAST(EL.DTVALOR AS date) AS DTVALOR,
                    ISNULL(EL.DESCRICAO, '') AS DESCRICAO,
                    CAST(EL.VALOR AS numeric(12,2)) AS VALOR
                FROM dbo.EL AS EL
                INNER JOIN dbo.EXT AS EXT
                  ON EXT.EXTSTAMP = EL.EXTSTAMP
                WHERE EXT.NOCONTA = :acc
                  AND YEAR(CAST(EL.DATA AS date)) = :ano
                  AND MONTH(CAST(EL.DATA AS date)) = :mes
                ORDER BY CAST(EL.DATA AS date), CAST(EL.DTVALOR AS date), EL.EXTSTAMP, EL.{stamp_col}
            """), {'acc': noconta, 'ano': ano, 'mes': mes}).mappings().all()

            if not moved_rows:
                return jsonify({'error': 'Não existem movimentos de extrato para a conta/mês/ano escolhidos.'}), 400

            moved_stamps = [(r.get('STAMP') or '').strip() for r in moved_rows if (r.get('STAMP') or '').strip()]
            source_exts = sorted({(r.get('SRC_EXTSTAMP') or '').strip() for r in moved_rows if (r.get('SRC_EXTSTAMP') or '').strip()})
            if not moved_stamps or not source_exts:
                return jsonify({'error': 'Não foi possível determinar os estratos de origem.'}), 400

            source_meta = db.session.execute(text("""
                SELECT
                    LTRIM(RTRIM(EXTSTAMP)) AS EXTSTAMP,
                    CAST(DATAINI AS date) AS DATAINI,
                    CAST(DATAFIM AS date) AS DATAFIM,
                    ISNULL(SALDOINI, '') AS SALDOINI,
                    ISNULL(SALDOFIM, '') AS SALDOFIM
                FROM dbo.EXT
                WHERE LTRIM(RTRIM(EXTSTAMP)) IN :ids
                ORDER BY CAST(DATAINI AS date), CAST(DATAFIM AS date), EXTSTAMP
            """).bindparams(bindparam('ids', expanding=True)), {'ids': source_exts}).mappings().all()

            if len(source_meta) != len(source_exts):
                return jsonify({'error': 'Um ou mais estratos de origem não foram encontrados.'}), 400

            has_rec = db.session.execute(text("""
                SELECT 1 AS X
                FROM INFORMATION_SCHEMA.TABLES
                WHERE TABLE_NAME = 'REC'
            """)).fetchone()

            affected_groups = []
            if has_rec:
                touched_groups = db.session.execute(text("""
                    SELECT
                        R.EXTSTAMP,
                        R.GROUPID,
                        COUNT(*) AS TOTAL_EL,
                        SUM(CASE WHEN LTRIM(RTRIM(R.STAMP)) IN :stamps THEN 1 ELSE 0 END) AS MOVED_EL
                    FROM dbo.REC AS R
                    WHERE R.ORIGEM = 'EL'
                      AND LTRIM(RTRIM(R.EXTSTAMP)) IN :exts
                    GROUP BY R.EXTSTAMP, R.GROUPID
                    HAVING SUM(CASE WHEN LTRIM(RTRIM(R.STAMP)) IN :stamps THEN 1 ELSE 0 END) > 0
                """).bindparams(
                    bindparam('stamps', expanding=True),
                    bindparam('exts', expanding=True),
                ), {'stamps': moved_stamps, 'exts': source_exts}).mappings().all()

                conflicts = [g for g in touched_groups if int(g.get('TOTAL_EL') or 0) != int(g.get('MOVED_EL') or 0)]
                if conflicts:
                    return jsonify({
                        'error': 'Existem reconciliações que misturam movimentos do mês escolhido com movimentos fora desse mês. Desfaça essas reconciliações antes de agrupar.'
                    }), 400

                affected_groups = [
                    {
                        'EXTSTAMP': (g.get('EXTSTAMP') or '').strip(),
                        'GROUPID': int(g.get('GROUPID') or 0),
                    }
                    for g in touched_groups
                    if int(g.get('GROUPID') or 0) > 0
                ]

            first_row = moved_rows[0]
            last_row = moved_rows[-1]
            data_ini = first_row.get('DATA')
            data_fim = last_row.get('DATA')
            saldo_ini = source_meta[0].get('SALDOINI') if source_meta else ''
            saldo_fim = source_meta[-1].get('SALDOFIM') if source_meta else ''
            new_extstamp = uuid.uuid4().hex[:25].upper()

            db.session.execute(text("""
                INSERT INTO dbo.EXT (EXTSTAMP, NOCONTA, DATAINI, DATAFIM, SALDOINI, SALDOFIM, RECONCILIADO)
                VALUES (:s, :n, :di, :df, :si, :sf, 0)
            """), {
                's': new_extstamp,
                'n': noconta,
                'di': data_ini,
                'df': data_fim,
                'si': saldo_ini or '',
                'sf': saldo_fim or '',
            })

            db.session.execute(text(f"""
                UPDATE dbo.EL
                SET EXTSTAMP = :new_ext
                WHERE EXTSTAMP IN :exts
                  AND LTRIM(RTRIM({stamp_col})) IN :stamps
            """).bindparams(
                bindparam('exts', expanding=True),
                bindparam('stamps', expanding=True),
            ), {'new_ext': new_extstamp, 'exts': source_exts, 'stamps': moved_stamps})

            if affected_groups:
                db.session.execute(text("""
                    UPDATE dbo.REC
                    SET EXTSTAMP = :new_ext
                    WHERE EXTSTAMP = :old_ext
                      AND GROUPID = :gid
                """), [
                    {'new_ext': new_extstamp, 'old_ext': g['EXTSTAMP'], 'gid': g['GROUPID']}
                    for g in affected_groups
                ])

            def recalculate_ext(extstamp_value):
                remaining = db.session.execute(text(f"""
                    SELECT
                        COUNT(1) AS N,
                        MIN(CAST(EL.DATA AS date)) AS DATAINI,
                        MAX(CAST(EL.DATA AS date)) AS DATAFIM
                    FROM dbo.EL AS EL
                    WHERE EL.EXTSTAMP = :s
                """), {'s': extstamp_value}).mappings().first()
                count_rows = int((remaining or {}).get('N') or 0)
                if count_rows <= 0:
                    if has_rec:
                        db.session.execute(text("DELETE FROM dbo.REC WHERE EXTSTAMP = :s"), {'s': extstamp_value})
                    db.session.execute(text("DELETE FROM dbo.EXT WHERE EXTSTAMP = :s"), {'s': extstamp_value})
                    return

                not_done = count_rows
                if has_rec:
                    not_done = int(db.session.execute(text(f"""
                        SELECT COUNT(1) AS N
                        FROM dbo.EL AS EL
                        LEFT JOIN dbo.REC AS R
                          ON R.EXTSTAMP = EL.EXTSTAMP
                         AND R.ORIGEM = 'EL'
                         AND LTRIM(RTRIM(R.STAMP)) = LTRIM(RTRIM(EL.{stamp_col}))
                        WHERE EL.EXTSTAMP = :s
                          AND R.RECSTAMP IS NULL
                    """), {'s': extstamp_value}).scalar() or 0)

                db.session.execute(text("""
                    UPDATE dbo.EXT
                    SET DATAINI = :di,
                        DATAFIM = :df,
                        RECONCILIADO = :rec
                    WHERE EXTSTAMP = :s
                """), {
                    's': extstamp_value,
                    'di': remaining.get('DATAINI'),
                    'df': remaining.get('DATAFIM'),
                    'rec': 1 if not_done == 0 else 0,
                })

            recalculate_ext(new_extstamp)
            for src_extstamp in source_exts:
                recalculate_ext(src_extstamp)

            db.session.commit()
            return jsonify({
                'ok': True,
                'EXTSTAMP': new_extstamp,
                'moved_lines': len(moved_stamps),
                'source_exts': len(source_exts),
                'periodo': {
                    'ANO': ano,
                    'MES': mes,
                },
            })
        except Exception as e:
            db.session.rollback()
            return jsonify({'error': str(e)}), 500

    @app.route('/api/extratos/<extstamp>')
    @login_required
    def api_extrato_detail(extstamp):
        """
        Devolve:
          - ext: cabeçalho
          - el: linhas do extrato (EL) com flag de reconciliado + groupid (se existir)
          - ba: movimentos BA no período/conta com flag de reconciliado + groupid (se existir)
        """
        try:
            extstamp = (extstamp or '').strip()
            if not extstamp:
                return jsonify({'error': 'EXTSTAMP obrigatório'}), 400

            ext = db.session.execute(text("""
                SELECT EXTSTAMP, NOCONTA, DATAINI, DATAFIM
                FROM dbo.EXT
                WHERE EXTSTAMP = :s
            """), {'s': extstamp}).mappings().first()
            if not ext:
                return jsonify({'error': 'Extrato não encontrado.'}), 404

            noconta = int(ext.get('NOCONTA') or 0)
            di = ext.get('DATAINI')
            df = ext.get('DATAFIM')
            di_s = di.strftime('%Y-%m-%d') if isinstance(di, (date, datetime)) else str(di)
            df_s = df.strftime('%Y-%m-%d') if isinstance(df, (date, datetime)) else str(df)

            el_cols = set(
                r[0] for r in db.session.execute(
                    text("SELECT UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'EL'")
                ).fetchall()
            )
            if 'EXTSTAMP' not in el_cols:
                return jsonify({'error': 'A tabela EL precisa do campo EXTSTAMP.'}), 400
            stamp_col = 'ELSTAMP' if 'ELSTAMP' in el_cols else ('ELSATMP' if 'ELSATMP' in el_cols else None)
            if not stamp_col:
                return jsonify({'error': 'A tabela EL precisa de um campo stamp (ELSTAMP ou ELSATMP).'}), 400

            has_rec = db.session.execute(text("""
                SELECT 1 AS X
                FROM INFORMATION_SCHEMA.TABLES
                WHERE TABLE_NAME = 'REC'
            """)).fetchone()
            if not has_rec:
                return jsonify({'error': 'Tabela REC não existe.'}), 400

            # EL lines + reconciled info
            el_rows = db.session.execute(text(f"""
                SELECT
                  LTRIM(RTRIM(EL.{stamp_col})) AS STAMP,
                  CAST(EL.DATA AS date) AS DATA,
                  CAST(EL.DTVALOR AS date) AS DTVALOR,
                  ISNULL(EL.DESCRICAO,'') AS DESCRICAO,
                  CAST(EL.VALOR AS numeric(12,2)) AS VALOR,
                  ISNULL(R.GROUPID, 0) AS GROUPID
                FROM dbo.EL AS EL
                LEFT JOIN (
                  SELECT LTRIM(RTRIM(STAMP)) AS STAMP, MAX(GROUPID) AS GROUPID
                  FROM dbo.REC
                  WHERE EXTSTAMP = :s AND ORIGEM = 'EL'
                  GROUP BY LTRIM(RTRIM(STAMP))
                ) AS R ON R.STAMP = LTRIM(RTRIM(EL.{stamp_col}))
                WHERE EL.EXTSTAMP = :s
                ORDER BY CAST(EL.DATA AS date), CAST(EL.DTVALOR AS date), EL.{stamp_col}
            """), {'s': extstamp}).mappings().all()
            el_out = []
            for r in el_rows:
                d0 = r.get('DATA')
                dv = r.get('DTVALOR')
                gid = int(r.get('GROUPID') or 0)
                el_out.append({
                    'STAMP': r.get('STAMP') or '',
                    'DATA': d0.strftime('%Y-%m-%d') if isinstance(d0, (date, datetime)) else (str(d0) if d0 else ''),
                    'DTVALOR': dv.strftime('%Y-%m-%d') if isinstance(dv, (date, datetime)) else (str(dv) if dv else ''),
                    'DESCRICAO': r.get('DESCRICAO') or '',
                    'VALOR': float(r.get('VALOR') or 0),
                    'RECONCILIADO': 1 if gid > 0 else 0,
                    'GROUPID': gid,
                })

            # BA movements normalized (signed) + reconciled info
            ba_rows = db.session.execute(text("""
                SELECT
                  LTRIM(RTRIM(ISNULL(BA.BASTAMP,''))) AS BASTAMP,
                  CAST(BA.DATA AS date) AS DATA,
                  ISNULL(BA.DOCUMENTO,'') AS DOCUMENTO,
                  ISNULL(BA.DESCRICAO,'') AS DESCRICAO,
                  CAST(ISNULL(BA.EENTRADA,0) - ISNULL(BA.ESAIDA,0) AS numeric(12,2)) AS VALOR
                FROM dbo.V_BA AS BA
                WHERE CAST(BA.DATA AS date) BETWEEN :di AND :df
                  AND (ISNULL(BA.EENTRADA,0) <> 0 OR ISNULL(BA.ESAIDA,0) <> 0)
                  AND BA.NOCONTA = :acc
                  AND LTRIM(RTRIM(ISNULL(BA.BASTAMP,''))) <> ''
                ORDER BY CAST(BA.DATA AS date), ISNULL(BA.DOCUMENTO,''), ISNULL(BA.DESCRICAO,''), ISNULL(BA.BASTAMP,'')
            """), {'di': di_s, 'df': df_s, 'acc': noconta}).mappings().all()

            # groupid by BA stamp for this ext
            ba_rec = db.session.execute(text("""
                SELECT LTRIM(RTRIM(STAMP)) AS STAMP, MAX(GROUPID) AS GROUPID
                FROM dbo.REC
                WHERE EXTSTAMP = :s AND ORIGEM = 'BA'
                GROUP BY LTRIM(RTRIM(STAMP))
            """), {'s': extstamp}).mappings().all()
            ba_gid = { (r.get('STAMP') or '').strip(): int(r.get('GROUPID') or 0) for r in ba_rec }

            ba_out = []
            for r in ba_rows:
                d0 = r.get('DATA')
                bastamp = (r.get('BASTAMP') or '').strip()
                gid = ba_gid.get(bastamp, 0)
                ba_out.append({
                    'BASTAMP': bastamp,
                    'DATA': d0.strftime('%Y-%m-%d') if isinstance(d0, (date, datetime)) else (str(d0) if d0 else ''),
                    'DOCUMENTO': r.get('DOCUMENTO') or '',
                    'DESCRICAO': r.get('DESCRICAO') or '',
                    'VALOR': float(r.get('VALOR') or 0),
                    'RECONCILIADO': 1 if gid > 0 else 0,
                    'GROUPID': gid,
                })

            return jsonify({
                'ext': {
                    'EXTSTAMP': extstamp,
                    'NOCONTA': noconta,
                    'DATAINI': di_s,
                    'DATAFIM': df_s,
                },
                'el': el_out,
                'ba': ba_out,
            })
        except Exception as e:
            return jsonify({'error': str(e)}), 500

    @app.route('/api/reconciliacao', methods=['POST'])
    @login_required
    def api_reconciliar():
        """
        Cria um grupo REC para um conjunto de linhas EL e BA.
        Regras:
          - todas as linhas ficam associadas ao mesmo EXTSTAMP + GROUPID
          - a soma EL deve igualar a soma BA (diferença ~0)
        """
        import uuid
        from decimal import Decimal
        from sqlalchemy import bindparam
        try:
            body = request.get_json(silent=True) or {}
            extstamp = (body.get('EXTSTAMP') or '').strip()
            el_list = body.get('EL') or []
            ba_list = body.get('BA') or []
            if not extstamp:
                return jsonify({'error': 'EXTSTAMP obrigatório'}), 400
            if not isinstance(el_list, list) or not isinstance(ba_list, list) or not el_list or not ba_list:
                return jsonify({'error': 'Seleciona pelo menos 1 linha EL e 1 movimento BA.'}), 400

            ext = db.session.execute(text("""
                SELECT EXTSTAMP, NOCONTA, DATAINI, DATAFIM
                FROM dbo.EXT
                WHERE EXTSTAMP = :s
            """), {'s': extstamp}).mappings().first()
            if not ext:
                return jsonify({'error': 'Extrato não encontrado.'}), 404

            noconta = int(ext.get('NOCONTA') or 0)
            di = ext.get('DATAINI')
            df = ext.get('DATAFIM')
            di_s = di.strftime('%Y-%m-%d') if isinstance(di, (date, datetime)) else str(di)
            df_s = df.strftime('%Y-%m-%d') if isinstance(df, (date, datetime)) else str(df)

            el_cols = set(
                r[0] for r in db.session.execute(
                    text("SELECT UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'EL'")
                ).fetchall()
            )
            if 'EXTSTAMP' not in el_cols:
                return jsonify({'error': 'A tabela EL precisa do campo EXTSTAMP.'}), 400
            stamp_col = 'ELSTAMP' if 'ELSTAMP' in el_cols else ('ELSATMP' if 'ELSATMP' in el_cols else None)
            if not stamp_col:
                return jsonify({'error': 'A tabela EL precisa de um campo stamp (ELSTAMP ou ELSATMP).'}), 400

            # Carrega valores EL
            el_vals = db.session.execute(text(f"""
                SELECT LTRIM(RTRIM({stamp_col})) AS STAMP, CAST(VALOR AS numeric(12,2)) AS VALOR
                FROM dbo.EL
                WHERE EXTSTAMP = :s AND LTRIM(RTRIM({stamp_col})) IN :ids
            """).bindparams(bindparam('ids', expanding=True)), {'s': extstamp, 'ids': el_list}).mappings().all()
            if len(el_vals) != len(set(el_list)):
                return jsonify({'error': 'Uma ou mais linhas EL não foram encontradas no extrato.'}), 400

            el_sum = sum(Decimal(str(r.get('VALOR') or 0)) for r in el_vals)

            # Carrega valores BA (no período/conta)
            ba_vals = db.session.execute(text("""
                SELECT LTRIM(RTRIM(ISNULL(BA.BASTAMP,''))) AS STAMP, CAST(ISNULL(BA.EENTRADA,0) - ISNULL(BA.ESAIDA,0) AS numeric(12,2)) AS VALOR
                FROM dbo.V_BA AS BA
                WHERE CAST(BA.DATA AS date) BETWEEN :di AND :df
                  AND BA.NOCONTA = :acc
                  AND LTRIM(RTRIM(ISNULL(BA.BASTAMP,''))) IN :ids
            """).bindparams(bindparam('ids', expanding=True)), {'di': di_s, 'df': df_s, 'acc': noconta, 'ids': ba_list}).mappings().all()
            if len(ba_vals) != len(set(ba_list)):
                return jsonify({'error': 'Um ou mais movimentos BA não foram encontrados no período/conta.'}), 400

            ba_sum = sum(Decimal(str(r.get('VALOR') or 0)) for r in ba_vals)
            diff = (el_sum - ba_sum).copy_abs()
            if diff > Decimal('0.01'):
                return jsonify({'error': f'Os valores não batem. Diferença: {float(el_sum - ba_sum):.2f}'}), 400

            # Novo groupid sequencial (lock para evitar duplicados)
            gid = db.session.execute(text("""
                SELECT ISNULL(MAX(GROUPID),0) + 1 AS N
                FROM dbo.REC WITH (UPDLOCK, HOLDLOCK)
            """)).scalar()
            gid = int(gid or 1)

            # Inserir REC (uma linha por item)
            rec_rows = []
            for r in el_vals:
                rec_rows.append({
                    'RECSTAMP': uuid.uuid4().hex[:25].upper(),
                    'EXTSTAMP': extstamp,
                    'GROUPID': gid,
                    'ORIGEM': 'EL',
                    'STAMP': (r.get('STAMP') or '').strip(),
                    'VALOR': float(r.get('VALOR') or 0),
                })
            for r in ba_vals:
                rec_rows.append({
                    'RECSTAMP': uuid.uuid4().hex[:25].upper(),
                    'EXTSTAMP': extstamp,
                    'GROUPID': gid,
                    'ORIGEM': 'BA',
                    'STAMP': (r.get('STAMP') or '').strip(),
                    'VALOR': float(r.get('VALOR') or 0),
                })

            db.session.execute(text("""
                INSERT INTO dbo.REC (RECSTAMP, EXTSTAMP, GROUPID, ORIGEM, STAMP, VALOR)
                VALUES (:RECSTAMP, :EXTSTAMP, :GROUPID, :ORIGEM, :STAMP, :VALOR)
            """), rec_rows)

            # Atualiza EXT.RECONCILIADO se todas as EL estiverem conciliadas
            not_done = db.session.execute(text(f"""
                SELECT COUNT(1) AS N
                FROM dbo.EL AS EL
                LEFT JOIN dbo.REC AS R
                  ON R.EXTSTAMP = EL.EXTSTAMP AND R.ORIGEM = 'EL' AND R.STAMP = EL.{stamp_col}
                WHERE EL.EXTSTAMP = :s
                  AND R.RECSTAMP IS NULL
            """), {'s': extstamp}).scalar()
            if int(not_done or 0) == 0:
                db.session.execute(text("UPDATE dbo.EXT SET RECONCILIADO = 1 WHERE EXTSTAMP = :s"), {'s': extstamp})

            db.session.commit()
            return jsonify({'ok': True, 'GROUPID': gid})
        except Exception as e:
            db.session.rollback()
            return jsonify({'error': str(e)}), 500

    @app.route('/api/reconciliacao/<extstamp>/<int:groupid>', methods=['DELETE'])
    @login_required
    def api_reconciliacao_delete_group(extstamp, groupid):
        """
        Remove uma reconciliação (grupo) inteira:
          - apaga todas as linhas da REC do mesmo EXTSTAMP + GROUPID
          - recalcula EXT.RECONCILIADO (1 apenas se todas as EL estiverem reconciliadas)
        """
        try:
            extstamp = (extstamp or '').strip()
            if not extstamp:
                return jsonify({'error': 'EXTSTAMP obrigatório'}), 400
            if int(groupid or 0) <= 0:
                return jsonify({'error': 'GROUPID inválido'}), 400

            # garantir que existe
            has = db.session.execute(text("""
                SELECT TOP 1 1 AS X
                FROM dbo.REC
                WHERE EXTSTAMP = :s AND GROUPID = :g
            """), {'s': extstamp, 'g': int(groupid)}).fetchone()
            if not has:
                return jsonify({'error': 'Grupo não encontrado.'}), 404

            db.session.execute(text("""
                DELETE FROM dbo.REC
                WHERE EXTSTAMP = :s AND GROUPID = :g
            """), {'s': extstamp, 'g': int(groupid)})

            # Recalcular EXT.RECONCILIADO: 1 apenas se todas as EL tiverem reconciliação
            el_cols = set(
                r[0] for r in db.session.execute(
                    text("SELECT UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'EL'")
                ).fetchall()
            )
            if 'EXTSTAMP' in el_cols:
                stamp_col = 'ELSTAMP' if 'ELSTAMP' in el_cols else ('ELSATMP' if 'ELSATMP' in el_cols else None)
                if stamp_col:
                    not_done = db.session.execute(text(f"""
                        SELECT COUNT(1) AS N
                        FROM dbo.EL AS EL
                        LEFT JOIN dbo.REC AS R
                          ON R.EXTSTAMP = EL.EXTSTAMP AND R.ORIGEM = 'EL' AND R.STAMP = LTRIM(RTRIM(EL.{stamp_col}))
                        WHERE EL.EXTSTAMP = :s
                          AND R.RECSTAMP IS NULL
                    """), {'s': extstamp}).scalar()
                    if int(not_done or 0) == 0:
                        db.session.execute(text("UPDATE dbo.EXT SET RECONCILIADO = 1 WHERE EXTSTAMP = :s"), {'s': extstamp})
                    else:
                        db.session.execute(text("UPDATE dbo.EXT SET RECONCILIADO = 0 WHERE EXTSTAMP = :s"), {'s': extstamp})

            db.session.commit()
            return jsonify({'ok': True})
        except Exception as e:
            db.session.rollback()
            return jsonify({'error': str(e)}), 500

    @app.route('/api/reconciliacao/ow', methods=['POST'])
    @app.route('/api/reconciliacao/olbb', methods=['POST'])
    @login_required
    def api_reconciliacao_create_olbb():
        """
        Gera movimentos de transferência bancária (OLBB) no ERP a partir de
        entradas (VALOR > 0) selecionadas na grelha EL (não reconciliadas).

        Body:
          { "EXTSTAMP": "...", "EL": ["<ELSTAMP>", ...] }
        """
        try:
            body = request.get_json(silent=True) or {}
            extstamp = (body.get('EXTSTAMP') or '').strip()
            stamps = body.get('EL') or []
            if not extstamp:
                return jsonify({'error': 'EXTSTAMP obrigatório'}), 400
            if not isinstance(stamps, list) or not stamps:
                return jsonify({'error': 'Selecione movimentos EL.'}), 400

            ERP_DB = 'GUEST_SPA_TUR'

            # Detetar stamp column na EL
            el_cols = set(
                r[0] for r in db.session.execute(
                    text("SELECT UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'EL'")
                ).fetchall()
            )
            if 'EXTSTAMP' not in el_cols:
                return jsonify({'error': 'A tabela EL precisa do campo EXTSTAMP.'}), 400
            stamp_col = 'ELSTAMP' if 'ELSTAMP' in el_cols else ('ELSATMP' if 'ELSATMP' in el_cols else None)
            if not stamp_col:
                return jsonify({'error': 'A tabela EL precisa de um campo stamp (ELSTAMP ou ELSATMP).'}), 400

            # Verificar tabela/colunas na OLBB (na BD do ERP)
            olbb_tbl = db.session.execute(text(f"""
                SELECT 1 AS X
                FROM [{ERP_DB}].INFORMATION_SCHEMA.TABLES
                WHERE TABLE_SCHEMA = 'dbo' AND TABLE_NAME = 'OLBB'
            """)).fetchone()
            if not olbb_tbl:
                return jsonify({'error': f"Tabela OLBB não existe na BD {ERP_DB}."}), 400

            olbb_cols = set(
                r[0] for r in db.session.execute(
                    text(f"""
                        SELECT UPPER(COLUMN_NAME)
                        FROM [{ERP_DB}].INFORMATION_SCHEMA.COLUMNS
                        WHERE TABLE_SCHEMA = 'dbo' AND TABLE_NAME = 'OLBB'
                    """)
                ).fetchall()
            )
            if not olbb_cols:
                return jsonify({'error': f"Não foi possível ler colunas da OLBB em {ERP_DB}."}), 400

            required = {'OLBBSTAMP', 'DATA', 'DVALOR', 'DESCRICAO', 'EVALOR', 'CONTADO1', 'CONTADO2', 'OLLOCAL1', 'OLLOCAL2', 'DOCUMENTO'}
            missing_req = sorted([c for c in required if c not in olbb_cols])
            if missing_req:
                return jsonify({'error': f"Campos em falta na OLBB ({ERP_DB}): " + ', '.join(missing_req)}), 400

            inserted = 0
            skipped_exists = 0
            skipped_reconciled = 0
            skipped_invalid = 0

            ins_cols = ['OLBBSTAMP', 'DATA', 'DVALOR', 'DESCRICAO', 'EVALOR', 'CONTADO1', 'CONTADO2', 'OLLOCAL1', 'OLLOCAL2', 'DOCUMENTO']
            ins_vals = [':OLBBSTAMP', ':DATA', ':DVALOR', ':DESCRICAO', ':EVALOR', ':CONTADO1', ':CONTADO2', ':OLLOCAL1', ':OLLOCAL2', ':DOCUMENTO']
            optional_defaults = {
                'VALOR': ':VALOR',
                'PLANO': ':PLANO',
                'OUSRINIS': ':OUSRINIS',
                'OUSRDATA': ':OUSRDATA',
                'OUSRHORA': ':OUSRHORA',
                'USRINIS': ':USRINIS',
                'USRDATA': ':USRDATA',
                'USRHORA': ':USRHORA',
            }
            for col_name, bind_name in optional_defaults.items():
                if col_name in olbb_cols:
                    ins_cols.append(col_name)
                    ins_vals.append(bind_name)
            ins_sql = text(f"""
                INSERT INTO [{ERP_DB}].[dbo].[OLBB] ({", ".join(ins_cols)})
                VALUES ({", ".join(ins_vals)})
            """)

            for s in stamps[:5000]:
                el_stamp = (str(s or '').strip())[:25]
                if not el_stamp:
                    skipped_invalid += 1
                    continue

                # Já reconciliado?
                rec = db.session.execute(text("""
                    SELECT TOP 1 1 AS X
                    FROM dbo.REC
                    WHERE EXTSTAMP = :e AND ORIGEM = 'EL' AND LTRIM(RTRIM(STAMP)) = :s
                """), {'e': extstamp, 's': el_stamp}).fetchone()
                if rec:
                    skipped_reconciled += 1
                    continue

                # Buscar EL
                el = db.session.execute(text(f"""
                    SELECT TOP 1
                      CAST(DATA AS date) AS DATA,
                      ISNULL(DESCRICAO,'') AS DESCRICAO,
                      CAST(VALOR AS numeric(19,6)) AS VALOR
                    FROM dbo.EL
                    WHERE EXTSTAMP = :e
                      AND LTRIM(RTRIM({stamp_col})) = :s
                """), {'e': extstamp, 's': el_stamp}).mappings().first()
                if not el:
                    skipped_invalid += 1
                    continue

                valor = float(el.get('VALOR') or 0)
                if valor <= 0.005:
                    skipped_invalid += 1
                    continue

                d = el.get('DATA')
                if isinstance(d, datetime):
                    d = d.date()
                if not isinstance(d, date):
                    skipped_invalid += 1
                    continue
                data_dt = datetime.combine(d, datetime.min.time())
                desc = (str(el.get('DESCRICAO') or '')).strip()[:60]

                # Já existe na OLBB?
                exists = db.session.execute(text("""
                    SELECT TOP 1 1 AS X
                    FROM [GUEST_SPA_TUR].[dbo].[OLBB]
                    WHERE CAST(DATA AS date) = :d
                      AND ISNULL(DESCRICAO,'') = :desc
                      AND CAST(EVALOR AS numeric(19,6)) = :valor
                      AND LTRIM(RTRIM(ISNULL(DOCUMENTO,''))) = 'Trfa'
                """), {'d': d, 'desc': desc, 'valor': valor}).fetchone()
                if exists:
                    skipped_exists += 1
                    continue

                olbb_stamp = uuid.uuid4().hex[:25].upper()
                user_login = (getattr(current_user, 'LOGIN', '') or '').strip()
                now_dt = datetime.now()
                now_hora = now_dt.strftime('%H:%M')

                db.session.execute(ins_sql, {
                    'OLBBSTAMP': olbb_stamp,
                    'DATA': data_dt,
                    'DVALOR': data_dt,
                    'DESCRICAO': desc,
                    'EVALOR': valor,
                    'CONTADO1': 13,
                    'CONTADO2': 1,
                    'OLLOCAL1': 'AIRBNB     AIRBNB',
                    'OLLOCAL2': 'Santander  DO',
                    'DOCUMENTO': 'Trfa',
                    'VALOR': valor,
                    'PLANO': 0,
                    'OUSRINIS': user_login,
                    'OUSRDATA': now_dt,
                    'OUSRHORA': now_hora,
                    'USRINIS': user_login,
                    'USRDATA': now_dt,
                    'USRHORA': now_hora,
                })
                inserted += 1

            db.session.commit()
            return jsonify({
                'ok': True,
                'inserted': inserted,
                'skipped_exists': skipped_exists,
                'skipped_reconciled': skipped_reconciled,
                'skipped_invalid': skipped_invalid
            })
        except Exception as e:
            db.session.rollback()
            return jsonify({'error': str(e)}), 500

    @app.route('/api/extratos/import', methods=['POST'])
    @login_required
    def api_extratos_import():
        """
        Importa um extrato bancário a partir de um CSV (ou Excel).
        CSV (separador ';'):
          - campo 2: DATA
          - campo 3: DTVALOR
          - campo 4: DESCRICAO
          - campo 7: VALOR (com sinal +/-)
        Excel:
          Folha: "estrato"
            - B: DATA
            - C: DTVALOR
            - D: DESCRICAO
            - E: DEBITO (negativo)
            - F: CREDITO (positivo)
        Cria EXT + EL.
        """
        import io
        import uuid
        from decimal import Decimal, InvalidOperation
        import csv

        # openpyxl é opcional (só para xlsx)
        load_workbook = None
        from_excel = None
        try:
            from openpyxl import load_workbook as _lw
            from openpyxl.utils.datetime import from_excel as _fe
            load_workbook = _lw
            from_excel = _fe
        except Exception:
            load_workbook = None
            from_excel = None

        def to_date(v):
            if v is None or v == '':
                return None
            if isinstance(v, datetime):
                return v.date()
            if isinstance(v, date):
                return v
            if isinstance(v, (int, float)) and from_excel:
                try:
                    dt = from_excel(v)
                    return dt.date() if isinstance(dt, datetime) else dt
                except Exception:
                    return None
            if isinstance(v, str):
                s = v.strip()
                if not s:
                    return None
                for fmt in ('%Y-%m-%d', '%d/%m/%Y', '%d-%m-%Y'):
                    try:
                        return datetime.strptime(s, fmt).date()
                    except Exception:
                        pass
            return None

        def to_dec(v):
            if v is None or v == '':
                return Decimal('0')
            if isinstance(v, Decimal):
                return v
            if isinstance(v, (int, float)):
                return Decimal(str(v))
            if isinstance(v, str):
                s = v.strip().replace('.', '').replace(',', '.')
                if s in ('', '-', '+'):
                    return Decimal('0')
                try:
                    return Decimal(s)
                except InvalidOperation:
                    return Decimal('0')
            try:
                return Decimal(str(v))
            except Exception:
                return Decimal('0')

        try:
            noconta = (request.form.get('noconta') or '').strip()
            dataini = (request.form.get('dataini') or '').strip()
            datafim = (request.form.get('datafim') or '').strip()
            saldoini = (request.form.get('saldoini') or '0').strip()
            saldofim = (request.form.get('saldofim') or '0').strip()
            f = request.files.get('file')

            if not noconta:
                return jsonify({'error': 'Conta em falta.'}), 400
            if not dataini or not datafim:
                return jsonify({'error': 'Data início/fim em falta.'}), 400
            if not f or not getattr(f, 'filename', ''):
                return jsonify({'error': 'Ficheiro em falta.'}), 400
            filename = (getattr(f, 'filename', '') or '').lower()

            try:
                noconta_i = int(noconta)
            except Exception:
                return jsonify({'error': 'NOCONTA inválido.'}), 400

            try:
                di = datetime.strptime(dataini, '%Y-%m-%d').date()
                df = datetime.strptime(datafim, '%Y-%m-%d').date()
            except Exception:
                return jsonify({'error': 'Datas inválidas (YYYY-MM-DD).'}), 400

            if df < di:
                return jsonify({'error': 'Data fim não pode ser inferior à data início.'}), 400

            if len(saldoini) > 10 or len(saldofim) > 10:
                return jsonify({'error': 'Saldo início/fim demasiado longo (máx 10 caracteres).'}), 400

            # Verifica colunas da tabela EL
            el_cols = set(
                r[0] for r in db.session.execute(
                    text("SELECT UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'EL'")
                ).fetchall()
            )
            ext_cols = set(
                r[0] for r in db.session.execute(
                    text("SELECT UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'EXT'")
                ).fetchall()
            )
            need_ext = {'EXTSTAMP', 'NOCONTA', 'DATAINI', 'DATAFIM', 'SALDOINI', 'SALDOFIM', 'RECONCILIADO'}
            missing_ext = sorted(list(need_ext - ext_cols))
            if missing_ext:
                return jsonify({'error': f"Campos em falta na EXT: {', '.join(missing_ext)}"}), 400

            # Precisamos de ligar EL ao cabeçalho
            if 'EXTSTAMP' not in el_cols:
                return jsonify({'error': 'A tabela EL precisa do campo EXTSTAMP para ligar ao cabeçalho.'}), 400

            stamp_col = 'ELSTAMP' if 'ELSTAMP' in el_cols else ('ELSATMP' if 'ELSATMP' in el_cols else None)
            if not stamp_col:
                return jsonify({'error': 'A tabela EL precisa de um campo stamp (ELSTAMP ou ELSATMP).'}), 400

            rows_in = []
            skipped = 0
            file_bytes = f.read()

            if filename.endswith('.csv'):
                # decode best-effort (PT banks often cp1252/latin1)
                text_data = None
                for enc in ('utf-8-sig', 'utf-8', 'cp1252', 'latin-1'):
                    try:
                        text_data = file_bytes.decode(enc)
                        break
                    except Exception:
                        continue
                if text_data is None:
                    return jsonify({'error': 'Não foi possível ler o CSV (encoding).'}), 400

                rdr = csv.reader(io.StringIO(text_data), delimiter=';')
                for row in rdr:
                    if not row or len(row) < 7:
                        continue
                    data0 = to_date(row[1])
                    dtval0 = to_date(row[2])
                    desc0 = (row[3] or '').strip()

                    # Alguns CSVs trazem débito/crédito em colunas separadas (débitos já negativos).
                    # Heurística:
                    #   - tenta 6ª e 7ª colunas (1-based) => indexes 5 e 6 (0-based)
                    #   - se der zero, tenta o primeiro número não-zero a seguir à descrição
                    deb = to_dec(row[5]) if len(row) > 5 else Decimal('0')
                    cred = to_dec(row[6]) if len(row) > 6 else Decimal('0')
                    valor = (deb or Decimal('0')) + (cred or Decimal('0'))
                    if abs(valor) < Decimal('0.005'):
                        for cell in row[4:]:
                            v2 = to_dec(cell)
                            if abs(v2) >= Decimal('0.005'):
                                valor = v2
                                break

                    if data0 is None:
                        continue
                    # filtra pelo intervalo escolhido
                    if data0 < di or data0 > df:
                        skipped += 1
                        continue
                    if dtval0 is None:
                        dtval0 = data0
                    if abs(valor) < Decimal('0.005'):
                        skipped += 1
                        continue
                    rows_in.append({
                        'DATA': data0,
                        'DTVALOR': dtval0,
                        'DESCRICAO': (desc0 or '')[:200],
                        'VALOR': valor.quantize(Decimal('0.01')),
                    })
            else:
                if not load_workbook:
                    return jsonify({'error': 'Para importar Excel (.xlsx) é necessário instalar openpyxl.'}), 400

                wb = load_workbook(io.BytesIO(file_bytes), data_only=True)
                ws = None
                for name in wb.sheetnames:
                    if (name or '').strip().lower() == 'estrato':
                        ws = wb[name]
                        break
                if ws is None:
                    return jsonify({'error': 'Folha "estrato" não encontrada no Excel.'}), 400

                for row in ws.iter_rows(values_only=True):
                    # Colunas B..F => indexes 1..5 (0-based)
                    if not row or len(row) < 6:
                        continue
                    data0 = to_date(row[1])
                    dtval0 = to_date(row[2])
                    desc0 = (row[3] or '').strip() if isinstance(row[3], str) else (str(row[3]).strip() if row[3] is not None else '')
                    deb = to_dec(row[4])
                    cred = to_dec(row[5])
                    valor = (cred or Decimal('0')) + (deb or Decimal('0'))

                    if data0 is None:
                        continue
                    if data0 < di or data0 > df:
                        skipped += 1
                        continue
                    if dtval0 is None:
                        dtval0 = data0
                    if abs(valor) < Decimal('0.005'):
                        skipped += 1
                        continue
                    rows_in.append({
                        'DATA': data0,
                        'DTVALOR': dtval0,
                        'DESCRICAO': (desc0 or '')[:200],
                        'VALOR': valor.quantize(Decimal('0.01')),
                    })

            if not rows_in:
                return jsonify({'error': 'Não foram encontradas linhas válidas para importar.'}), 400

            extstamp = uuid.uuid4().hex[:25].upper()

            db.session.execute(text("""
                INSERT INTO dbo.EXT (EXTSTAMP, NOCONTA, DATAINI, DATAFIM, SALDOINI, SALDOFIM, RECONCILIADO)
                VALUES (:s, :n, :di, :df, :si, :sf, 0)
            """), {'s': extstamp, 'n': noconta_i, 'di': di, 'df': df, 'si': saldoini, 'sf': saldofim})

            # Inserção de linhas
            el_rows = []
            for r0 in rows_in:
                el_rows.append({
                    'EXTSTAMP': extstamp,
                    'STAMP': uuid.uuid4().hex[:25].upper(),
                    'DATA': r0['DATA'],
                    'DTVALOR': r0['DTVALOR'],
                    'DESCRICAO': r0['DESCRICAO'],
                    'VALOR': r0['VALOR'],
                })

            ins = text(f"""
                INSERT INTO dbo.EL ({stamp_col}, EXTSTAMP, DATA, DTVALOR, DESCRICAO, VALOR)
                VALUES (:STAMP, :EXTSTAMP, :DATA, :DTVALOR, :DESCRICAO, :VALOR)
            """)
            db.session.execute(ins, el_rows)
            db.session.commit()

            sample = [
                {
                    'DATA': r['DATA'].strftime('%Y-%m-%d') if isinstance(r['DATA'], date) else str(r['DATA']),
                    'DTVALOR': r['DTVALOR'].strftime('%Y-%m-%d') if isinstance(r['DTVALOR'], date) else str(r['DTVALOR']),
                    'DESCRICAO': r['DESCRICAO'],
                    'VALOR': float(r['VALOR']),
                }
                for r in rows_in[:50]
            ]
            return jsonify({'ok': True, 'EXTSTAMP': extstamp, 'inserted': len(rows_in), 'skipped': skipped, 'sample': sample})
        except Exception as e:
            db.session.rollback()
            return jsonify({'error': str(e)}), 500

    @app.route('/api/fr/import', methods=['POST'])
    @login_required
    def api_fr_import():
        """
        Importa linhas para dbo.FR a partir de Excel.

        Excel:
          - 1ª linha: títulos (ignorada)
          - Colunas:
            A DOCUMENTO, B DATA, C CLIENTE, D CCUSTO, I BASE, J TAXAIVA, K IVA, L ANULADO, M ARTIGO

        Regras:
          - só importa ARTIGO in ('Estadia', 'Taxa de Limpeza')
          - upsert por (DOCUMENTO, ARTIGO, CCUSTO)
        """
        import io
        import uuid
        from decimal import Decimal, InvalidOperation

        # openpyxl é necessário para xlsx
        try:
            from openpyxl import load_workbook
            from openpyxl.utils.datetime import from_excel as from_excel_date
        except Exception:
            load_workbook = None
            from_excel_date = None

        def new_stamp():
            return uuid.uuid4().hex.upper()[:25]

        def norm_txt(v, max_len=None):
            s = ('' if v is None else str(v)).strip()
            if max_len:
                s = s[:max_len]
            return s

        def norm_artigo(v):
            s = norm_txt(v, 50)
            s2 = ' '.join(s.split()).strip().casefold()
            return s2

        def to_date(v):
            if v is None or v == '':
                return None
            if isinstance(v, datetime):
                return v.date()
            if isinstance(v, date):
                return v
            if isinstance(v, (int, float)) and from_excel_date:
                try:
                    dt = from_excel_date(v)
                    return dt.date() if isinstance(dt, datetime) else dt
                except Exception:
                    return None
            if isinstance(v, str):
                s = v.strip()
                if not s:
                    return None
                for fmt in ('%Y-%m-%d', '%d/%m/%Y', '%d-%m-%Y'):
                    try:
                        return datetime.strptime(s, fmt).date()
                    except Exception:
                        pass
            return None

        def to_dec(v):
            if v is None or v == '':
                return Decimal('0')
            if isinstance(v, Decimal):
                return v
            if isinstance(v, (int, float)):
                return Decimal(str(v))
            if isinstance(v, str):
                s = v.strip().replace('.', '').replace(',', '.')
                if s in ('', '-', '+'):
                    return Decimal('0')
                try:
                    return Decimal(s)
                except InvalidOperation:
                    return Decimal('0')
            try:
                return Decimal(str(v))
            except Exception:
                return Decimal('0')

        def to_bit(v):
            if v is None or v == '':
                return 0
            if isinstance(v, bool):
                return 1 if v else 0
            if isinstance(v, (int, float)):
                try:
                    return 1 if float(v) != 0 else 0
                except Exception:
                    return 0
            s = str(v).strip().casefold()
            return 1 if s in ('1', 'true', 'sim', 's', 'yes', 'y', 'anulado') else 0

        try:
            f = request.files.get('file')
            if not f or not getattr(f, 'filename', ''):
                return jsonify({'error': 'Ficheiro em falta.'}), 400
            filename = (getattr(f, 'filename', '') or '').lower()
            if not filename.endswith('.xlsx'):
                return jsonify({'error': 'Formato inválido. Use .xlsx'}), 400
            if not load_workbook:
                return jsonify({'error': 'openpyxl não está disponível no servidor.'}), 500

            # validar tabela/colunas mínimas
            cols = set(
                r[0] for r in db.session.execute(
                    text("SELECT UPPER(COLUMN_NAME) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = 'FR'")
                ).fetchall()
            )
            need = {'FRSTAMP', 'DOCUMENTO', 'DATA', 'CLIENTE', 'CCUSTO', 'ARTIGO', 'BASE', 'TAXAIVA', 'IVA', 'ANULADO'}
            missing = sorted(list(need - cols))
            if missing:
                return jsonify({'error': f"Campos em falta na FR: {', '.join(missing)}"}), 400

            raw = f.read()
            wb = load_workbook(io.BytesIO(raw), data_only=True)
            ws = wb.active

            allowed = {'estadia', 'taxa de limpeza'}
            inserted = 0
            updated = 0
            skipped = 0
            sample = []

            # cache de existentes por key (DOCUMENTO, ARTIGO, CCUSTO) -> FRSTAMP
            existing_rows = db.session.execute(text("""
                SELECT FRSTAMP, DOCUMENTO, ARTIGO, CCUSTO
                FROM dbo.FR
            """)).mappings().all()
            existing = {}
            for r in existing_rows:
                k = (
                    norm_txt(r.get('DOCUMENTO'), 100),
                    norm_txt(r.get('ARTIGO'), 25),
                    norm_txt(r.get('CCUSTO'), 50),
                )
                if all(k):
                    existing[k] = norm_txt(r.get('FRSTAMP'), 25)

            ins_sql = text("""
                INSERT INTO dbo.FR
                (FRSTAMP, DOCUMENTO, DATA, CLIENTE, CCUSTO, ARTIGO, BASE, TAXAIVA, IVA, ANULADO)
                VALUES
                (:FRSTAMP, :DOCUMENTO, :DATA, :CLIENTE, :CCUSTO, :ARTIGO, :BASE, :TAXAIVA, :IVA, :ANULADO)
            """)
            upd_sql = text("""
                UPDATE dbo.FR
                SET DATA = :DATA,
                    CLIENTE = :CLIENTE,
                    BASE = :BASE,
                    TAXAIVA = :TAXAIVA,
                    IVA = :IVA,
                    ANULADO = :ANULADO
                WHERE FRSTAMP = :FRSTAMP
            """)

            # iterar a partir da linha 2 (1 = títulos)
            for row_idx in range(2, ws.max_row + 1):
                doc = norm_txt(ws.cell(row=row_idx, column=1).value, 100)   # A
                dt = to_date(ws.cell(row=row_idx, column=2).value)          # B
                cliente = norm_txt(ws.cell(row=row_idx, column=3).value, 100)  # C
                ccusto = norm_txt(ws.cell(row=row_idx, column=4).value, 50) # D
                base = to_dec(ws.cell(row=row_idx, column=9).value)         # I
                taxaiva = to_dec(ws.cell(row=row_idx, column=10).value)     # J
                iva = to_dec(ws.cell(row=row_idx, column=11).value)         # K
                anulado = to_bit(ws.cell(row=row_idx, column=12).value)     # L
                artigo = norm_txt(ws.cell(row=row_idx, column=13).value, 25)  # M

                if not doc or not artigo or not ccusto or not dt:
                    skipped += 1
                    continue
                if norm_artigo(artigo) not in allowed:
                    skipped += 1
                    continue

                k = (doc, artigo, ccusto)
                frstamp = existing.get(k)
                params = {
                    'FRSTAMP': frstamp or new_stamp(),
                    'DOCUMENTO': doc,
                    'DATA': dt,
                    'CLIENTE': cliente,
                    'CCUSTO': ccusto,
                    'ARTIGO': artigo,
                    'BASE': base,
                    'TAXAIVA': taxaiva,
                    'IVA': iva,
                    'ANULADO': anulado,
                }

                if frstamp:
                    db.session.execute(upd_sql, params)
                    updated += 1
                else:
                    db.session.execute(ins_sql, params)
                    inserted += 1
                    existing[k] = params['FRSTAMP']

                if len(sample) < 50:
                    sample.append({
                        'DOCUMENTO': doc,
                        'DATA': dt.strftime('%Y-%m-%d') if dt else '',
                        'CLIENTE': cliente,
                        'CCUSTO': ccusto,
                        'ARTIGO': artigo,
                        'BASE': float(base),
                        'TAXAIVA': float(taxaiva),
                        'IVA': float(iva),
                        'ANULADO': int(anulado),
                        'MODE': 'U' if frstamp else 'I',
                    })

            db.session.commit()
            return jsonify({'ok': True, 'inserted': inserted, 'updated': updated, 'skipped': skipped, 'sample': sample})
        except Exception as e:
            db.session.rollback()
            return jsonify({'error': str(e)}), 500

